
import { Verse } from '../types';

export const PROFETAS_MENORES_SEED: Verse[] = [
  // OBADIAS
  { id: "OBA 1:1", bookId: "OBA", book: "Obadias", chapter: 1, verse: 1, text: "Visão de Obadias. Assim diz o Senhor DEUS a respeito de Edom: Temos ouvido as novas do Senhor, e às nações foi enviado um embaixador, dizendo: Levantai-vos, e levantemo-nos contra ela para a guerra." },
  { id: "OBA 1:2", bookId: "OBA", book: "Obadias", chapter: 1, verse: 2, text: "Eis que te fiz pequeno entre os gentios; tu és muito desprezado." },
  { id: "OBA 1:3", bookId: "OBA", book: "Obadias", chapter: 1, verse: 3, text: "A soberba do teu coração te enganou, como o que habita nas fendas das rochas, na sua alta morada, que diz no seu coração: Quem me derrubará em terra?" },
  { id: "OBA 1:4", bookId: "OBA", book: "Obadias", chapter: 1, verse: 4, text: "Se te elevares como águia, e se puseres o teu ninho entre as estrelas, dali te derrubarei, diz o Senhor." },
  { id: "OBA 1:5", bookId: "OBA", book: "Obadias", chapter: 1, verse: 5, text: "Se viessem a ti ladrões, ou roubadores de noite (como estás destruído!), não furtariam o que lhes bastasse? Se a ti viessem os vindimadores, não deixariam alguns cachos?" },
  { id: "OBA 1:6", bookId: "OBA", book: "Obadias", chapter: 1, verse: 6, text: "Como foram esquadrinhadas as coisas de Esaú! como foram investigados os seus tesouros escondidos!" },
  { id: "OBA 1:7", bookId: "OBA", book: "Obadias", chapter: 1, verse: 7, text: "Todos os teus confederados te levaram para fora dos teus limites; os que estavam de paz contigo te enganaram, e prevaleceram contra ti; os que comem o teu pão puseram armadilhas debaixo de ti; não há nele entendimento." },
  { id: "OBA 1:8", bookId: "OBA", book: "Obadias", chapter: 1, verse: 8, text: "E não acontecerá, naquele dia, diz o Senhor, que farei perecer os sábios de Edom, e o entendimento do monte de Esaú?" },
  { id: "OBA 1:9", bookId: "OBA", book: "Obadias", chapter: 1, verse: 9, text: "E os teus valentes, ó Temã, estarão atemorizados, para que do monte de Esaú seja cada um exterminado pela matança." },
  { id: "OBA 1:10", bookId: "OBA", book: "Obadias", chapter: 1, verse: 10, text: "Por causa da violência feita a teu irmão Jacó, cobrir-te-á a confusão, e serás exterminado para sempre." },
  { id: "OBA 1:11", bookId: "OBA", book: "Obadias", chapter: 1, verse: 11, text: "No dia em que estiveste em frente dele, no dia em que os forasteiros levavam cativo o seu exército, e os estranhos entravam pelas suas portas, e lançavam sortes sobre Jerusalém, tu mesmo eras um deles." },
  { id: "OBA 1:12", bookId: "OBA", book: "Obadias", chapter: 1, verse: 12, text: "Mas tu não devias olhar para o dia de teu irmão, no dia do seu infortúnio; nem alegrar-te sobre os filhos de Judá, no dia da sua ruína; nem alargar a tua boca, no dia da angústia;" },
  { id: "OBA 1:13", bookId: "OBA", book: "Obadias", chapter: 1, verse: 13, text: "Nem entrar pela porta do meu povo, no dia da sua calamidade; sim, tu não devias olhar, satisfeito, para o seu mal, no dia da sua calamidade; nem estender as tuas mãos contra o seu exército, no dia da sua calamidade;" },
  { id: "OBA 1:14", bookId: "OBA", book: "Obadias", chapter: 1, verse: 14, text: "Nem parar nas encruzilhadas, para exterminares os que escapassem; nem entregar os que lhe restassem, no dia da angústia." },
  { id: "OBA 1:15", bookId: "OBA", book: "Obadias", chapter: 1, verse: 15, text: "Porque o dia do Senhor está perto, sobre todos os gentios; como tu fizeste, assim se fará contigo; a tua recompensa voltará sobre a tua cabeça." },
  { id: "OBA 1:16", bookId: "OBA", book: "Obadias", chapter: 1, verse: 16, text: "Porque, como vós bebestes no meu santo monte, assim beberão de contínuo todos os gentios; beberão, e sorverão, e serão como se nunca tivessem sido." },
  { id: "OBA 1:17", bookId: "OBA", book: "Obadias", chapter: 1, verse: 17, text: "Mas no monte de Sião haverá livramento, e ele será santo; e os da casa de Jacó possuirão as suas herdades." },
  { id: "OBA 1:18", bookId: "OBA", book: "Obadias", chapter: 1, verse: 18, text: "E a casa de Jacó será fogo, e a casa de José chama, e a casa de Esaú palha; e se acenderão contra eles, e os consumirão; e ninguém mais restará da casa de Esaú, porque o Senhor o falou." },
  { id: "OBA 1:19", bookId: "OBA", book: "Obadias", chapter: 1, verse: 19, text: "E os do sul possuirão o monte de Esaú, e os das planícies, os filisteus; possuirão também os campos de Efraim, e os campos de Samaria; e Benjamim possuirá a Gileade." },
  { id: "OBA 1:20", bookId: "OBA", book: "Obadias", chapter: 1, verse: 20, text: "E os cativos deste exército dos filhos de Israel possuirão os cananeus, até Zarefate; e os cativos de Jerusalém, que estão em Sefarade, possuirão as cidades do sul." },
  { id: "OBA 1:21", bookId: "OBA", book: "Obadias", chapter: 1, verse: 21, text: "E subirão salvadores ao monte de Sião, para julgarem o monte de Esaú; e o reino será do Senhor." },

  // AGEU
  { id: "HAG 1:1", bookId: "HAG", book: "Ageu", chapter: 1, verse: 1, text: "No segundo ano do rei Dario, no sexto mês, no primeiro dia do mês, veio a palavra do Senhor, por intermédio do profeta Ageu, a Zorobabel, filho de Sealtiel, governador de Judá, e a Josué, filho de Jozadaque, o sumo sacerdote, dizendo:" },
  { id: "HAG 1:2", bookId: "HAG", book: "Ageu", chapter: 1, verse: 2, text: "Assim fala o Senhor dos Exércitos, dizendo: Este povo diz: Não veio ainda o tempo, o tempo em que a casa do Senhor deve ser edificada." },
  { id: "HAG 1:3", bookId: "HAG", book: "Ageu", chapter: 1, verse: 3, text: "Veio, pois, a palavra do Senhor, por intermédio do profeta Ageu, dizendo:" },
  { id: "HAG 1:4", bookId: "HAG", book: "Ageu", chapter: 1, verse: 4, text: "Porventura é tempo de habitardes vós em casas estucadas, enquanto esta casa está deserta?" },
  { id: "HAG 1:5", bookId: "HAG", book: "Ageu", chapter: 1, verse: 5, text: "Ora, pois, assim diz o Senhor dos Exércitos: Considerai os vossos caminhos." },
  { id: "HAG 1:6", bookId: "HAG", book: "Ageu", chapter: 1, verse: 6, text: "Semeais muito, e recolheis pouco; comeis, porém não vos fartais; bebeis, porém não vos saciais; vesti-vos, porém ninguém se aquece; e o que recebe salário, recebe-o num saquitel furado." },
  { id: "HAG 1:7", bookId: "HAG", book: "Ageu", chapter: 1, verse: 7, text: "Assim diz o Senhor dos Exércitos: Considerai os vossos caminhos." },
  { id: "HAG 1:8", bookId: "HAG", book: "Ageu", chapter: 1, verse: 8, text: "Subi ao monte, e trazei madeira, e edificai a casa; e dela me agradarei, e serei glorificado, diz o Senhor." },
  { id: "HAG 1:9", bookId: "HAG", book: "Ageu", chapter: 1, verse: 9, text: "Esperastes o muito, mas eis que veio a ser pouco; e esse pouco, quando o trouxestes para casa, eu dissipei com um sopro. Por que causa? disse o Senhor dos Exércitos. Por causa da minha casa, que está deserta, enquanto cada um de vós corre à sua própria casa." },
  { id: "HAG 1:10", bookId: "HAG", book: "Ageu", chapter: 1, verse: 10, text: "Por isso retiveram os céus sobre vós o orvalho, e a terra reteve os seus frutos." },
  { id: "HAG 1:11", bookId: "HAG", book: "Ageu", chapter: 1, verse: 11, text: "E chamei a seca sobre a terra, e sobre os montes, e sobre o trigo, e sobre o mosto, e sobre o azeite, e sobre o que a terra produz; como também sobre os homens, e sobre o gado, e sobre todo o trabalho das mãos." },
  { id: "HAG 1:12", bookId: "HAG", book: "Ageu", chapter: 1, verse: 12, text: "Então ouviu Zorobabel, filho de Sealtiel, e Josué, filho de Jozadaque, sumo sacerdote, e todo o resto do povo, a voz do Senhor seu Deus, e as palavras do profeta Ageu, assim como o Senhor seu Deus o tinha enviado; e temeu o povo diante do Senhor." },
  { id: "HAG 1:13", bookId: "HAG", book: "Ageu", chapter: 1, verse: 13, text: "Então Ageu, o mensageiro do Senhor, falou ao povo conforme a mensagem do Senhor, dizendo: Eu sou convosco, diz o Senhor." },
  { id: "HAG 1:14", bookId: "HAG", book: "Ageu", chapter: 1, verse: 14, text: "E o Senhor levantou o espírito de Zorobabel, filho de Sealtiel, governador de Judá, e o espírito de Josué, filho de Jozadaque, sumo sacerdote, e o espírito de todo o resto do povo, e eles vieram, e fizeram a obra na casa do Senhor dos Exércitos, seu Deus," },
  { id: "HAG 1:15", bookId: "HAG", book: "Ageu", chapter: 1, verse: 15, text: "Ao vigésimo quarto dia do sexto mês, no segundo ano do rei Dario." },
  { id: "HAG 2:1", bookId: "HAG", book: "Ageu", chapter: 2, verse: 1, text: "No sétimo mês, ao vigésimo primeiro do mês, veio a palavra do Senhor por intermédio do profeta Ageu, dizendo:" },
  { id: "HAG 2:2", bookId: "HAG", book: "Ageu", chapter: 2, verse: 2, text: "Fala agora a Zorobabel, filho de Sealtiel, governador de Judá, e a Josué, filho de Jozadaque, sumo sacerdote, e ao resto do povo, dizendo:" },
  { id: "HAG 2:3", bookId: "HAG", book: "Ageu", chapter: 2, verse: 3, text: "Quem há entre vós que tendo ficado, viu esta casa na sua primeira glória? E como a vedes agora? Não é esta como nada em vossos olhos, comparada com aquela?" },
  { id: "HAG 2:4", bookId: "HAG", book: "Ageu", chapter: 2, verse: 4, text: "Ora, pois, esforça-te, Zorobabel, diz o Senhor, e esforça-te, Josué, filho de Jozadaque, sumo sacerdote, e esforçai-vos, todo o povo da terra, diz o Senhor, e trabalhai; porque eu sou convosco, diz o Senhor dos Exércitos," },
  { id: "HAG 2:5", bookId: "HAG", book: "Ageu", chapter: 2, verse: 5, text: "Segundo a palavra da aliança que fiz convosco, quando saístes do Egito, o meu Espírito habita no meio de vós; não temais." },
  { id: "HAG 2:6", bookId: "HAG", book: "Ageu", chapter: 2, verse: 6, text: "Porque assim diz o Senhor dos Exércitos: Ainda uma vez, daqui a pouco, farei tremer os céus e a terra, o mar e a terra seca;" },
  { id: "HAG 2:7", bookId: "HAG", book: "Ageu", chapter: 2, verse: 7, text: "E farei tremer todas as nações, e virão as coisas preciosas de todas as nações, e encherei esta casa de glória, diz o Senhor dos Exércitos." },
  { id: "HAG 2:8", bookId: "HAG", book: "Ageu", chapter: 2, verse: 8, text: "Minha é a prata, e meu é o ouro, disse o Senhor dos Exércitos." },
  { id: "HAG 2:9", bookId: "HAG", book: "Ageu", chapter: 2, verse: 9, text: "A glória desta última casa será maior do que a da primeira, diz o Senhor dos Exércitos, e neste lugar darei a paz, diz o Senhor dos Exércitos." },
  { id: "HAG 2:10", bookId: "HAG", book: "Ageu", chapter: 2, verse: 10, text: "Ao vigésimo quarto dia do mês nono, no segundo ano de Dario, veio a palavra do Senhor por intermédio do profeta Ageu, dizendo:" },
  { id: "HAG 2:11", bookId: "HAG", book: "Ageu", chapter: 2, verse: 11, text: "Assim diz o Senhor dos Exércitos: Pergunta agora aos sacerdotes, acerca da lei, dizendo:" },
  { id: "HAG 2:12", bookId: "HAG", book: "Ageu", chapter: 2, verse: 12, text: "Se alguém leva carne santa na orla das suas vestes, e com ela tocar no pão, ou no guisado, ou no vinho, ou no azeite, ou em qualquer outro mantimento, porventura ficará isto santificado? E os sacerdotes responderam, e disseram: Não." },
  { id: "HAG 2:13", bookId: "HAG", book: "Ageu", chapter: 2, verse: 13, text: "E disse Ageu: Se alguém que for imundo por causa de um corpo morto, tocar em alguma destas coisas, ficará ela imunda? E os sacerdotes responderam, e disseram: Ficará imunda." },
  { id: "HAG 2:14", bookId: "HAG", book: "Ageu", chapter: 2, verse: 14, text: "Então respondeu Ageu, e disse: Assim é este povo, e assim é esta nação diante de mim, diz o Senhor; e assim é toda a obra das suas mãos; e tudo o que ali oferecem é imundo." },
  { id: "HAG 2:15", bookId: "HAG", book: "Ageu", chapter: 2, verse: 15, text: "Agora, pois, aplicai o vosso coração a isso, desde este dia em diante, antes que se pusesse pedra sobre pedra no templo do Senhor." },
  { id: "HAG 2:16", bookId: "HAG", book: "Ageu", chapter: 2, verse: 16, text: "Antes que sucedessem estas coisas, vinha alguém a um montão de vinte medidas, e havia somente dez; quando vinha ao lagar para tirar cinquenta, havia somente vinte." },
  { id: "HAG 2:17", bookId: "HAG", book: "Ageu", chapter: 2, verse: 17, text: "Feri-vos com queimadura, e com ferrugem, e com saraiva, em toda a obra das vossas mãos, e não houve entre vós quem voltasse para mim, diz o Senhor." },
  { id: "HAG 2:18", bookId: "HAG", book: "Ageu", chapter: 2, verse: 18, text: "Considerai, pois, em vosso coração, desde este dia em diante, desde o vigésimo quarto dia do mês nono, desde o dia em que se fundou o templo do Senhor, considerai estas coisas." },
  { id: "HAG 2:19", bookId: "HAG", book: "Ageu", chapter: 2, verse: 19, text: "Há ainda semente no celeiro? Nem a videira, nem a figueira, nem a romeira, nem a oliveira, têm dado os seus frutos; mas desde este dia vos abençoarei." },
  { id: "HAG 2:20", bookId: "HAG", book: "Ageu", chapter: 2, verse: 20, text: "E veio a palavra do Senhor segunda vez a Ageu, aos vinte e quatro do mês, dizendo:" },
  { id: "HAG 2:21", bookId: "HAG", book: "Ageu", chapter: 2, verse: 21, text: "Fala a Zorobabel, governador de Judá, dizendo: Farei tremer os céus e a terra;" },
  { id: "HAG 2:22", bookId: "HAG", book: "Ageu", chapter: 2, verse: 22, text: "E transtornarei o trono dos reinos, e destruirei a força dos reinos dos gentios; e transtornarei os carros e os que neles andam; e os cavalos e os seus cavaleiros cairão, cada um pela espada do seu irmão." },
  { id: "HAG 2:23", bookId: "HAG", book: "Ageu", chapter: 2, verse: 23, text: "Naquele dia, diz o Senhor dos Exércitos, te tomarei, ó Zorobabel, servo meu, filho de Sealtiel, diz o Senhor, e far-te-ei como um anel de selar; porque te escolhi, diz o Senhor dos Exércitos." },

  // NAUM
  { id: "NAH 1:1", bookId: "NAH", book: "Naum", chapter: 1, verse: 1, text: "Peso de Nínive. Livro da visão de Naum, o elcosita." },
  { id: "NAH 1:2", bookId: "NAH", book: "Naum", chapter: 1, verse: 2, text: "O Senhor é um Deus zeloso e vingador; o Senhor é vingador e cheio de furor; o Senhor toma vingança contra os seus adversários, e guarda a ira contra os seus inimigos." },
  { id: "NAH 1:3", bookId: "NAH", book: "Naum", chapter: 1, verse: 3, text: "O Senhor é tardio em irar-se, mas grande em poder, e ao culpado não tem por inocente; o Senhor tem o seu caminho na tormenta e na tempestade, e as nuvens são o pó dos seus pés." },
  { id: "NAH 1:4", bookId: "NAH", book: "Naum", chapter: 1, verse: 4, text: "Ele repreende o mar, e o faz secar, e esgota todos os rios; desfalecem Basã e Carmelo, e a flor do Líbano murcha." },
  { id: "NAH 1:5", bookId: "NAH", book: "Naum", chapter: 1, verse: 5, text: "Os montes tremem perante ele, e os outeiros se derretem; e a terra se levanta na sua presença; e o mundo, e todos os que nele habitam." },
  { id: "NAH 1:6", bookId: "NAH", book: "Naum", chapter: 1, verse: 6, text: "Quem parará diante do seu furor, e quem subsistirá diante do ardor da sua ira? A sua cólera se derramou como fogo, e as rochas foram por ele derrubadas." },
  { id: "NAH 1:7", bookId: "NAH", book: "Naum", chapter: 1, verse: 7, text: "O Senhor é bom, ele serve de fortaleza no dia da angústia, e conhece os que confiam nele." },
  { id: "NAH 1:8", bookId: "NAH", book: "Naum", chapter: 1, verse: 8, text: "E com inundação transbordante fará uma consumação do seu lugar; e as trevas perseguirão os seus inimigos." },
  { id: "NAH 1:9", bookId: "NAH", book: "Naum", chapter: 1, verse: 9, text: "Que imaginais vós contra o Senhor? Ele mesmo fará uma consumação; a angústia não se levantará duas vezes." },
  { id: "NAH 1:10", bookId: "NAH", book: "Naum", chapter: 1, verse: 10, text: "Porque, ainda que eles se entrelacem como os espinhos, e se embriaguem como os bêbados, serão inteiramente consumidos como palha seca." },
  { id: "NAH 1:11", bookId: "NAH", book: "Naum", chapter: 1, verse: 11, text: "De ti saiu um que maquinou o mal contra o Senhor, um conselheiro de Belial." },
  { id: "NAH 1:12", bookId: "NAH", book: "Naum", chapter: 1, verse: 12, text: "Assim diz o Senhor: Por mais seguros que estejam, e por mais numerosos que sejam, ainda assim serão cortados, e ele passará; eu te afligi, mas não te afligirei mais." },
  { id: "NAH 1:13", bookId: "NAH", book: "Naum", chapter: 1, verse: 13, text: "Mas agora quebrarei o seu jugo de sobre ti, e romperei as tuas ataduras." },
  { id: "NAH 1:14", bookId: "NAH", book: "Naum", chapter: 1, verse: 14, text: "Contra ti, porém, o Senhor deu ordem, que não haja mais linhagem do teu nome; da casa dos teus deuses destruirei as imagens de escultura e de fundição; ali farei o teu sepulcro, porque és vil." },
  { id: "NAH 1:15", bookId: "NAH", book: "Naum", chapter: 1, verse: 15, text: "Eis sobre os montes os pés do que traz as boas novas, do que anuncia a paz! Celebra as tuas festas, ó Judá, cumpre os teus votos, porque o ímpio não tornará mais a passar por ti; ele é inteiramente exterminado." },
  { id: "NAH 2:1", bookId: "NAH", book: "Naum", chapter: 2, verse: 1, text: "O destruidor subiu contra ti. Guarda a fortaleza, vigia o caminho, fortifica os lombos, reúne todas as tuas forças." },
  { id: "NAH 2:2", bookId: "NAH", book: "Naum", chapter: 2, verse: 2, text: "Porque o Senhor restaurará a excelência de Jacó como a excelência de Israel; porque os saqueadores os despojaram, e destruíram os seus sarmentos." },
  { id: "NAH 2:3", bookId: "NAH", book: "Naum", chapter: 2, verse: 3, text: "Os escudos dos seus fortes serão vermelhos, os homens valorosos estarão vestidos de escarlate, os carros como tochas de fogo no dia da sua preparação, e os ciprestes serão terrivelmente abalados." },
  { id: "NAH 2:4", bookId: "NAH", book: "Naum", chapter: 2, verse: 4, text: "Os carros correrão furiosamente nas ruas, colidirão um contra o outro nos largos; o seu aspecto será como o de tochas, correrão como relâmpagos." },
  { id: "NAH 2:5", bookId: "NAH", book: "Naum", chapter: 2, verse: 5, text: "Ele se lembrará dos seus valentes; eles tropeçarão na sua marcha; apressar-se-ão para chegar ao seu muro, e o pálio será preparado." },
  { id: "NAH 2:6", bookId: "NAH", book: "Naum", chapter: 2, verse: 6, text: "As portas dos rios se abrirão, e o palácio se derreterá." },
  { id: "NAH 2:7", bookId: "NAH", book: "Naum", chapter: 2, verse: 7, text: "E é decretado: ela será levada cativa, conduzida para cima; e as suas servas a acompanharão, gemendo como pombas, batendo em seus peitos." },
  { id: "NAH 2:8", bookId: "NAH", book: "Naum", chapter: 2, verse: 8, text: "Nínive desde que existiu tem sido como um tanque de águas, porém elas agora fogem. Parai, parai, clamarão; mas ninguém olhará para trás." },
  { id: "NAH 2:9", bookId: "NAH", book: "Naum", chapter: 2, verse: 9, text: "Saqueai a prata, saqueai o ouro, porque não têm fim as provisões, riquezas de toda a sorte de bens desejáveis." },
  { id: "NAH 2:10", bookId: "NAH", book: "Naum", chapter: 2, verse: 10, text: "Vazia, e esgotada, e devastada está; e derrete-se o coração, e tremem os joelhos, e em todos os lombos há dor, e os rostos de todos eles empalidecem." },
  { id: "NAH 2:11", bookId: "NAH", book: "Naum", chapter: 2, verse: 11, text: "Onde está agora o covil dos leões, e as pastagens dos leõezinhos, onde passeava o leão, a leoa, e o filhote do leão, sem que ninguém os espantasse?" },
  { id: "NAH 2:12", bookId: "NAH", book: "Naum", chapter: 2, verse: 12, text: "O leão arrebatava o que bastava para os seus filhotes, e estrangulava para as suas leoas, e enchia de presas as suas cavernas, e os seus covis de rapina." },
  { id: "NAH 2:13", bookId: "NAH", book: "Naum", chapter: 2, verse: 13, text: "Eis que eu estou contra ti, diz o Senhor dos Exércitos, e queimarei na fumaça os teus carros, e a espada devorará os teus leõezinhos, e arrancarei da terra a tua presa, e não se ouvirá mais a voz dos teus embaixadores." },
  { id: "NAH 3:1", bookId: "NAH", book: "Naum", chapter: 3, verse: 1, text: "Ai da cidade sanguinária! Ela está toda cheia de mentiras e de roubo; não se aparta dela a rapina." },
  { id: "NAH 3:2", bookId: "NAH", book: "Naum", chapter: 3, verse: 2, text: "Estrondo de açoite há, e o barulho do ruído das rodas; e os cavalos atropelam, e carros saltam." },
  { id: "NAH 3:3", bookId: "NAH", book: "Naum", chapter: 3, verse: 3, text: "O cavaleiro levanta a espada flamejante, como a lança relampejante, e ali haverá uma multidão de mortos, e abundância de cadáveres, e não terão fim os defuntos; tropeçarão nos seus corpos;" },
  { id: "NAH 3:4", bookId: "NAH", book: "Naum", chapter: 3, verse: 4, text: "Por causa da multidão dos pecados da meretriz muito graciosa, da mestra das feitiçarias, que vendeu as nações com as suas fornicações, e as famílias com as suas feitiçarias." },
  { id: "NAH 3:5", bookId: "NAH", book: "Naum", chapter: 3, verse: 5, text: "Eis que eu estou contra ti, diz o Senhor dos Exércitos; e levantarei as tuas saias sobre o teu rosto, e às nações mostrarei a tua nudez, e aos reinos a tua vergonha." },
  { id: "NAH 3:6", bookId: "NAH", book: "Naum", chapter: 3, verse: 6, text: "E lançarei sobre ti coisas abomináveis, e envergonhar-te-ei, e pôr-te-ei como espetáculo." },
  { id: "NAH 3:7", bookId: "NAH", book: "Naum", chapter: 3, verse: 7, text: "E há de ser que, todos os que te virem, fugirão de ti, e dirão: Nínive está destruída, quem terá compaixão dela? Donde te buscarei consoladores?" },
  { id: "NAH 3:8", bookId: "NAH", book: "Naum", chapter: 3, verse: 8, text: "És tu melhor do que Nô-Amom, que estava assentada entre os canais do Nilo, cercada de águas, cujo baluarte era o mar, e o mar a sua muralha?" },
  { id: "NAH 3:9", bookId: "NAH", book: "Naum", chapter: 3, verse: 9, text: "Etiópia e Egito eram a sua força, e não tinha fim; Pute e Líbia foram o teu socorro." },
  { id: "NAH 3:10", bookId: "NAH", book: "Naum", chapter: 3, verse: 10, text: "Todavia foi levada cativa, foi para o cativeiro; também os seus filhos foram despedaçados nas esquinas de todas as ruas; e sobre os seus nobres lançaram sortes, e todos os seus grandes foram presos com grilhões." },
  { id: "NAH 3:11", bookId: "NAH", book: "Naum", chapter: 3, verse: 11, text: "Tu também serás embriagada, e te esconderás; também buscarás força por causa do inimigo." },
  { id: "NAH 3:12", bookId: "NAH", book: "Naum", chapter: 3, verse: 12, text: "Todas as tuas fortalezas serão como figueiras com figos temporãos; se as sacodem, caem na boca do que os há de comer." },
  { id: "NAH 3:13", bookId: "NAH", book: "Naum", chapter: 3, verse: 13, text: "Eis que o teu povo no meio de ti são como mulheres; as portas da tua terra estarão de todo abertas aos teus inimigos; o fogo consumirá os teus ferrolhos." },
  { id: "NAH 3:14", bookId: "NAH", book: "Naum", chapter: 3, verse: 14, text: "Tira águas para o cerco, fortifica as tuas fortalezas; entra no lodo, e pisa o barro, pega a forma para os tijolos." },
  { id: "NAH 3:15", bookId: "NAH", book: "Naum", chapter: 3, verse: 15, text: "O fogo ali te consumirá, a espada te exterminará, consumir-te-á como a locusta. Multiplica-te como a locusta, multiplica-te como os gafanhotos." },
  { id: "NAH 3:16", bookId: "NAH", book: "Naum", chapter: 3, verse: 16, text: "Multiplicaste os teus negociantes mais do que as estrelas do céu; a locusta se espalhará e voará." },
  { id: "NAH 3:17", bookId: "NAH", book: "Naum", chapter: 3, verse: 17, text: "Os teus príncipes são como os gafanhotos, e os teus capitães como o enxame de gafanhotos, que se acampam nas sebes nos dias de frio; em subindo o sol voam, de sorte que não se sabe mais o lugar onde estão." },
  { id: "NAH 3:18", bookId: "NAH", book: "Naum", chapter: 3, verse: 18, text: "Os teus pastores dormirão, ó rei da Assíria, os teus ilustres repousarão, o teu povo se espalhará pelos montes, sem que haja quem o ajunte." },
  { id: "NAH 3:19", bookId: "NAH", book: "Naum", chapter: 3, verse: 19, text: "Não há cura para a tua ferida, a tua chaga é dolorosa. Todos os que ouvirem a tua fama baterão as palmas sobre ti; porque, sobre quem não passou continuamente a tua malícia?" },
  // HABACUQUE
  { id: "HAB 1:1", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 1, text: "O peso que viu o profeta Habacuque." },
  { id: "HAB 1:2", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 2, text: "Até quando, Senhor, clamarei eu, e tu não me escutarás? Gritarei: Violência! e não salvarás?" },
  { id: "HAB 1:3", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 3, text: "Por que me mostras a iniquidade, e me fazes ver a opressão? Pois que a destruição e a violência estão diante de mim, havendo também quem suscite a contenda e o litígio." },
  { id: "HAB 1:4", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 4, text: "Por esta causa a lei se afrouxa, e a justiça nunca se manifesta; porque o ímpio cerca o justo, e a justiça se manifesta torcida." },
  { id: "HAB 1:5", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 5, text: "Vede entre os gentios e olhai, e maravilhai-vos, e admirai-vos; porque realizarei em vossos dias uma obra que vós não crereis, quando for contada." },
  { id: "HAB 1:6", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 6, text: "Porque eis que suscito os caldeus, nação amarga e impetuosa, que marcha sobre a largura da terra, para apoderar-se de moradas que não são suas." },
  { id: "HAB 1:7", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 7, text: "Horrível e terrível é; dela mesma sairá o seu juízo e a sua dignidade." },
  { id: "HAB 1:8", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 8, text: "E os seus cavalos são mais ligeiros do que os leopardos, e mais espertos do que os lobos à tarde; os seus cavaleiros espalham-se por toda parte; os seus cavaleiros virão de longe; voarão como águias que se apressam a devorar." },
  { id: "HAB 1:9", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 9, text: "Eles todos virão para fazer violência; os seus rostos buscarão o vento oriental, e reunirão os cativos como areia." },
  { id: "HAB 1:10", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 10, text: "E escarnecerão dos reis, e dos príncipes farão zombaria; eles se rirão de todas as fortalezas, porque amontoarão terra, e as tomarão." },
  { id: "HAB 1:11", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 11, text: "Então mudarão de espírito, e passarão adiante, e se farão culpados, atribuindo o seu poder ao seu deus." },
  { id: "HAB 1:12", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 12, text: "Não és tu desde a eternidade, ó Senhor meu Deus, meu Santo? Nós não morreremos. Ó Senhor, para juízo o puseste, e tu, ó Rocha, o fundaste para castigar." },
  { id: "HAB 1:13", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 13, text: "Tu és tão puro de olhos, que não podes ver o mal, e a opressão não podes contemplar. Por que olhas para os que procedem aleivosamente, e te calas quando o ímpio devora aquele que é mais justo do que ele?" },
  { id: "HAB 1:14", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 14, text: "E farias os homens como os peixes do mar, como os répteis, que não têm quem os governe?" },
  { id: "HAB 1:15", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 15, text: "Ele a todos levantará com o anzol, apanhá-los-á com a sua rede, e os ajuntará na sua rede varredoura; por isso ele se alegra e se regozija." },
  { id: "HAB 1:16", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 16, text: "Por isso sacrifica à sua rede, e queima incenso à sua varredoura; porque com elas se engordou a sua porção, e se engrossou a sua comida." },
  { id: "HAB 1:17", bookId: "HAB", book: "Habacuque", chapter: 1, verse: 17, text: "Porventura por isso esvaziará a sua rede e não terá piedade de matar as nações continuamente?" },
  { id: "HAB 2:1", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 1, text: "Sobre a minha guarda estarei, e sobre a fortaleza me apresentarei e vigiarei, para ver o que falará a mim, e o que eu responderei quando for argüido." },
  { id: "HAB 2:2", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 2, text: "Então o Senhor me respondeu, e disse: Escreve a visão e torna-a bem legível sobre tábuas, para que a possa ler quem passa correndo." },
  { id: "HAB 2:3", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 3, text: "Porque a visão é ainda para o tempo determinado, mas se apressa para o fim, e não enganará; se tardar, espera-o, porque certamente virá, não tardará." },
  { id: "HAB 2:4", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 4, text: "Eis que a sua alma está orgulhosa, não é reta nele; mas o justo pela sua fé viverá." },
  { id: "HAB 2:5", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 5, text: "Tanto mais que, por ser dado ao vinho, é desleal; homem soberbo que não permanecerá; que alarga como o inferno a sua alma, e é como a morte que não se farta, e ajunta a si todas as nações, e congrega a si todos os povos." },
  { id: "HAB 2:6", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 6, text: "Não levantarão, pois, todos estes contra ele uma parábola e um provérbio sarcástico contra ele? E dirão: Ai daquele que multiplica o que não é seu! (até quando?) e daquele que carrega sobre si penhores!" },
  { id: "HAB 2:7", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 7, text: "Não se levantarão de repente os teus credores, e não despertarão os que te farão tremer, e não lhes servirás tu de despojo?" },
  { id: "HAB 2:8", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 8, text: "Porquanto despojaste a muitas nações, todos os mais povos te despojarão a ti, por causa do sangue dos homens, e da violência feita à terra, à cidade, e a todos os que nela habitam." },
  { id: "HAB 2:9", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 9, text: "Ai daquele que, para a sua casa, ajunta cobiça maligna, para pôr o seu ninho no alto, a fim de se livrar do poder do mal!" },
  { id: "HAB 2:10", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 10, text: "Vergonha maquinaste para a tua casa; destruindo tu a muitos povos, pecaste contra a tua alma." },
  { id: "HAB 2:11", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 11, text: "Porque a pedra clamará da parede, e a trave lhe responderá do madeiramento." },
  { id: "HAB 2:12", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 12, text: "Ai daquele que edifica a cidade com sangue, e que funda a cidade com iniquidade!" },
  { id: "HAB 2:13", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 13, text: "Porventura não vem do Senhor dos Exércitos que os povos trabalhem para o fogo e os homens se cansem em vão?" },
  { id: "HAB 2:14", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 14, text: "Porque a terra se encherá do conhecimento da glória do Senhor, como as águas cobrem o mar." },
  { id: "HAB 2:15", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 15, text: "Ai daquele que dá de beber ao seu companheiro! Tu, que lhe chegas o teu odre, e o embebedas, para ver a sua nudez!" },
  { id: "HAB 2:16", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 16, text: "Serás farto de ignomínia em lugar de honra; bebe tu também, e descobre a tua incircuncisão; o cálice da mão direita do Senhor voltará a ti, e ignomínia cairá sobre a tua glória." },
  { id: "HAB 2:17", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 17, text: "Porque a violência cometida contra o Líbano te cobrirá, e a destruição dos animais ferozes te assombrará, por causa do sangue dos homens, e da violência feita à terra, à cidade, e a todos os que nela habitam." },
  { id: "HAB 2:18", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 18, text: "Que aproveita a imagem de escultura, depois que a esculpiu o seu artífice? Ela é imagem de fundição que ensina mentira, para que quem a formou confie na sua obra, fazendo ídolos mudos?" },
  { id: "HAB 2:19", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 19, text: "Ai daquele que diz ao pau: Acorda! e à pedra muda: Desperta! Pode isso ensinar? Eis que está coberta de ouro e de prata, mas dentro dela não há espírito algum." },
  { id: "HAB 2:20", bookId: "HAB", book: "Habacuque", chapter: 2, verse: 20, text: "Mas o Senhor está no seu santo templo; cale-se diante dele toda a terra." },
  { id: "HAB 3:1", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 1, text: "Oração do profeta Habacuque sobre Sigionote." },
  { id: "HAB 3:2", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 2, text: "Ouvi, Senhor, a tua palavra, e temi; aviva, ó Senhor, a tua obra no meio dos anos, no meio dos anos faze-a conhecida; na tua ira lembra-te da misericórdia." },
  { id: "HAB 3:3", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 3, text: "Deus veio de Temã, e o Santo do monte Parã. (Selá.) A sua glória cobriu os céus, e a terra encheu-se do seu louvor." },
  { id: "HAB 3:4", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 4, text: "E o seu resplendor era como a luz, raios brilhantes saíam da sua mão, e ali estava o esconderijo da sua força." },
  { id: "HAB 3:5", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 5, text: "Adiante dele ia a peste, e brasas ardentes saíam dos seus passos." },
  { id: "HAB 3:6", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 6, text: "Parou, e mediu a terra; olhou, e separou as nações; e os montes perpétuos foram esmiuçados; os outeiros eternos se abateram, porque os caminhos eternos lhe pertencem." },
  { id: "HAB 3:7", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 7, text: "Vi as tendas de Cusã em aflição; tremiam as cortinas da terra de Midiã." },
  { id: "HAB 3:8", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 8, text: "Acaso é contra os rios, Senhor, que estás irado? É contra os ribeiros a tua ira, ou contra o mar o teu furor, visto que andas montado sobre os teus cavalos, e nos teus carros de salvação?" },
  { id: "HAB 3:9", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 9, text: "Descoberto se fez o teu arco; os juramentos feitos às tribos foram uma palavra segura. (Selá.) Tu fendeste a terra com rios." },
  { id: "HAB 3:10", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 10, text: "Os montes te viram, e tremeram; a inundação das águas passou; o abismo levantou a sua voz, e levantou ao alto as suas mãos." },
  { id: "HAB 3:11", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 11, text: "O sol e a lua pararam nas suas moradas; andaram à luz das tuas flechas, ao resplendor do relâmpago da tua lança." },
  { id: "HAB 3:12", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 12, text: "Com indignação marchaste pela terra, com ira trilhaste as nações." },
  { id: "HAB 3:13", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 13, text: "Tu saíste para salvação do teu povo, para salvação do teu ungido; tu feriste a cabeça da casa do ímpio, descobrindo o fundamento até ao pescoço. (Selá.)" },
  { id: "HAB 3:14", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 14, text: "Tu traspassaste com as suas próprias lanças a cabeça das suas vilas; eles se espalharam como tempestade para me espalharem; alegravam-se, como se estivessem para devorar o pobre em segredo." },
  { id: "HAB 3:15", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 15, text: "Tu com os teus cavalos marchaste pelo mar, pela massa de grandes águas." },
  { id: "HAB 3:16", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 16, text: "Ouvindo-o eu, o meu ventre se comoveu, à sua voz tremeram os meus lábios; entrou a podridão nos meus ossos, e estremeci dentro de mim; no dia da angústia descansarei, quando subir contra o povo que invadirá com suas tropas." },
  { id: "HAB 3:17", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 17, text: "Porque ainda que a figueira não floresça, nem haja fruto na vide; ainda que decepcione o produto da oliveira, e os campos não produzam mantimento; ainda que as ovelhas da malhada sejam arrebatadas, e nos currais não haja gado;" },
  { id: "HAB 3:18", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 18, text: "Todavia eu me alegrarei no Senhor; exultarei no Deus da minha salvação." },
  { id: "HAB 3:19", bookId: "HAB", book: "Habacuque", chapter: 3, verse: 19, text: "O Senhor Deus é a minha força, e fará os meus pés como os das cervas, e me fará andar sobre as minhas alturas. (Para o mestre de canto sobre os meus instrumentos de corda)." },

  // SOFONIAS
  { id: "ZEP 1:1", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 1, text: "A palavra do Senhor, que veio a Sofonias, filho de Cusi, filho de Gedalias, filho de Amarias, filho de Ezequias, nos dias de Josias, filho de Amom, rei de Judá." },
  { id: "ZEP 1:2", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 2, text: "Hei de consumir por completo tudo de sobre a face da terra, diz o Senhor." },
  { id: "ZEP 1:3", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 3, text: "Consumirei os homens e os animais, consumirei as aves do céu, e os peixes do mar, e os tropeços juntamente com os ímpios; e exterminarei os homens de sobre a face da terra, diz o Senhor." },
  { id: "ZEP 1:4", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 4, text: "E estenderei a minha mão contra Judá, e contra todos os habitantes de Jerusalém, e exterminarei deste lugar o restante de Baal, e o nome dos ministros dos ídolos, juntamente com os sacerdotes;" },
  { id: "ZEP 1:5", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 5, text: "E os que sobre os telhados adoram o exército do céu; e os que se inclinam jurando ao Senhor, e juram por Milcom;" },
  { id: "ZEP 1:6", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 6, text: "E os que deixam de andar em seguimento do Senhor, e os que não buscam ao Senhor, nem perguntam por ele." },
  { id: "ZEP 1:7", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 7, text: "Cala-te diante do Senhor Deus, porque o dia do Senhor está perto; porque o Senhor preparou o sacrifício, e santificou os seus convidados." },
  { id: "ZEP 1:8", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 8, text: "E acontecerá que, no dia do sacrifício do Senhor, castigarei os príncipes, e os filhos do rei, e todos os que se vestem de trajes estrangeiros." },
  { id: "ZEP 1:9", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 9, text: "Castigarei também naquele dia todos aqueles que saltam sobre o limiar, que enchem de violência e engano a casa dos seus senhores." },
  { id: "ZEP 1:10", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 10, text: "E naquele dia, diz o Senhor, far-se-á ouvir uma voz de clamor desde a porta dos peixes, e um uivo desde a segunda porta, e grande estrondo desde os outeiros." },
  { id: "ZEP 1:11", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 11, text: "Uivai vós, moradores de Mactes, porque todo o povo negociante está arruinado, todos os que pesavam a prata foram destruídos." },
  { id: "ZEP 1:12", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 12, text: "E há de ser que, naquele tempo, esquadrinharei a Jerusalém com lanternas, e castigarei os homens que estão assentados sobre as suas fezes, que dizem no seu coração: O Senhor não faz o bem nem faz o mal." },
  { id: "ZEP 1:13", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 13, text: "Por isso serão saqueados os seus bens, e assoladas as suas casas; e edificarão casas, mas não habitarão nelas, e plantarão vinhas, mas não lhes beberão o vinho." },
  { id: "ZEP 1:14", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 14, text: "O grande dia do Senhor está perto, sim, está perto, e se apressa muito; amarga é a voz do dia do Senhor; clamará ali o poderoso." },
  { id: "ZEP 1:15", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 15, text: "Aquele dia será um dia de indignação, dia de tribulação e de angústia, dia de alvoroço e de assolação, dia de trevas e de escuridão, dia de nuvens e de densas trevas," },
  { id: "ZEP 1:16", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 16, text: "Dia de trombeta e de alarido contra as cidades fortificadas e contra as torres altas." },
  { id: "ZEP 1:17", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 17, text: "E angustiarei os homens, que andarão como cegos, porque pecaram contra o Senhor; e o seu sangue se derramará como pó, e a sua carne será como esterco." },
  { id: "ZEP 1:18", bookId: "ZEP", book: "Sofonias", chapter: 1, verse: 18, text: "Nem a sua prata nem o seu ouro os poderá livrar no dia da indignação do Senhor, mas pelo fogo do seu zelo toda esta terra será consumida, porque certamente fará de todos os moradores da terra uma destruição total e apressada." },
  { id: "ZEP 2:1", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 1, text: "Congregai-vos, sim, congregai-vos, ó nação não desejável;" },
  { id: "ZEP 2:2", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 2, text: "Antes que o decreto produza o seu efeito, e o dia passe como a pragana; antes que venha sobre vós o furor da ira do Senhor, antes que venha sobre vós o dia da ira do Senhor." },
  { id: "ZEP 2:3", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 3, text: "Buscai ao Senhor, vós todos os mansos da terra, que tendes posto por obra o seu juízo; buscai a justiça, buscai a mansidão; pode ser que sejais escondidos no dia da ira do Senhor." },
  { id: "ZEP 2:4", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 4, text: "Porque Gaza será desamparada, e Ascalom assolada; Asdode ao meio-dia será expulsa, e Ecrom desarraigada." },
  { id: "ZEP 2:5", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 5, text: "Ai dos habitantes da costa do mar, a nação dos quereteus! A palavra do Senhor será contra vós, ó Canaã, terra dos filisteus; e eu vos destruirei, até que não haja morador." },
  { id: "ZEP 2:6", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 6, text: "E a costa do mar será de pastagens e cabanas para os pastores, e currais para os rebanhos." },
  { id: "ZEP 2:7", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 7, text: "E será a costa para o restante da casa de Judá; ali apascentarão os seus rebanhos; de tarde se deitarão nas casas de Ascalom; porque o Senhor seu Deus os visitará, e fará voltar o seu cativeiro." },
  { id: "ZEP 2:8", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 8, text: "Eu ouvi o escárnio de Moabe, e as injúrias dos filhos de Amom, com que escarneceram do meu povo, e se engrandeceram contra o seu termo." },
  { id: "ZEP 2:9", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 9, text: "Portanto, vivo eu, diz o Senhor dos Exércitos, o Deus de Israel, que Moabe será como Sodoma, e os filhos de Amom como Gomorra, campo de urtigas e poços de sal, e desolação perpétua; o restante do meu povo os saqueará, e o restante da minha nação os possuirá." },
  { id: "ZEP 2:10", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 10, text: "Isso terão em recompensa da sua soberba, porque escarneceram, e se engrandeceram contra o povo do Senhor dos Exércitos." },
  { id: "ZEP 2:11", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 11, text: "O Senhor será terrível para eles, porque emagrecerá todos os deuses da terra; e todos virão adorá-lo, cada um desde o seu lugar, de todas as ilhas dos gentios." },
  { id: "ZEP 2:12", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 12, text: "Também vós, ó etíopes, sereis mortos com a minha espada." },
  { id: "ZEP 2:13", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 13, text: "Estenderá também a sua mão contra o norte, e destruirá a Assíria; e fará de Nínive uma desolação, terra seca como o deserto." },
  { id: "ZEP 2:14", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 14, text: "E no meio dela repousarão os rebanhos, todos os animais dos povos; e alojar-se-ão nos seus capitéis assim o pelicano como o ouriço; a voz das aves ressoará nas janelas, a desolação estará no limiar, quando tiver posto a descoberto a obra de cedro." },
  { id: "ZEP 2:15", bookId: "ZEP", book: "Sofonias", chapter: 2, verse: 15, text: "Esta é a cidade alegre, que habitava despreocupadamente, que dizia no seu coração: Eu sou, e não há outra além de mim; como se tornou em desolação, em pousada de animais! Todo o que passar por ela assobiará, e meneará a sua mão." },
  { id: "ZEP 3:1", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 1, text: "Ai da rebelde e contaminada, da cidade opressora!" },
  { id: "ZEP 3:2", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 2, text: "Não obedeceu à voz, não aceitou o castigo; não confiou no Senhor; nem se aproximou do seu Deus." },
  { id: "ZEP 3:3", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 3, text: "Os seus príncipes no meio dela são leões rugidores; os seus juízes são lobos da tarde, que não deixam os ossos para a manhã." },
  { id: "ZEP 3:4", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 4, text: "Os seus profetas são levianos, homens aleivosos; os seus sacerdotes profanam o santuário, e fazem violência à lei." },
  { id: "ZEP 3:5", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 5, text: "O Senhor é justo no meio dela; ele não comete iniquidade; cada manhã traz o seu juízo à luz; nunca falta; mas o iníquo não conhece a vergonha." },
  { id: "ZEP 3:6", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 6, text: "Exterminei as nações, as suas torres estão assoladas; fiz desertas as suas praças, a ponto de não ficar quem passe por elas; as suas cidades foram destruídas, até não ficar ninguém, até não haver quem as habite." },
  { id: "ZEP 3:7", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 7, text: "Eu dizia: Certamente me temerás, e aceitarás a correção, e assim a sua morada não seria destruída, por tudo quanto havia ordenado contra ela; mas eles se levantaram de madrugada, corromperam todas as suas obras." },
  { id: "ZEP 3:8", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 8, text: "Portanto esperai-me, diz o Senhor, no dia em que eu me levantar para o despojo; porque o meu juízo é ajuntar as nações e congregar os reinos, para sobre eles derramar a minha indignação, e todo o ardor da minha ira; porque toda esta terra será consumida pelo fogo do meu zelo." },
  { id: "ZEP 3:9", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 9, text: "Porque então darei lábios puros aos povos, para que todos invoquem o nome do Senhor, para que o sirvam com um mesmo consenso." },
  { id: "ZEP 3:10", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 10, text: "Dalém dos rios da Etiópia, meus suplicantes, a filha dos meus dispersos, me trarão sacrifício." },
  { id: "ZEP 3:11", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 11, text: "Naquele dia não te envergonharás de nenhuma das tuas obras, com as quais te rebelaste contra mim; porque então tirarei do meio de ti os que exultam na tua soberba, e tu nunca mais te ensoberbecerás no meu santo monte." },
  { id: "ZEP 3:12", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 12, text: "Mas deixarei no meio de ti um povo modesto e humilde, que confia no nome do Senhor." },
  { id: "ZEP 3:13", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 13, text: "O remanescente de Israel não cometerá iniquidade, nem proferirá mentira, e na sua boca não se achará língua enganosa; mas serão apascentados, e deitar-se-ão, e não haverá quem os espante." },
  { id: "ZEP 3:14", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 14, text: "Canta alegremente, ó filha de Sião; rejubila, ó Israel; regozija-te, e exulta de todo o coração, ó filha de Jerusalém." },
  { id: "ZEP 3:15", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 15, text: "O Senhor afastou os teus juízos, exterminou o teu inimigo; o Senhor, o rei de Israel, está no meio de ti; tu não verás mais mal algum." },
  { id: "ZEP 3:16", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 16, text: "Naquele dia se dirá a Jerusalém: Não temas, ó Sião, não se enfraqueçam as tuas mãos." },
  { id: "ZEP 3:17", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 17, text: "O Senhor teu Deus, o poderoso, está no meio de ti, ele salvará; ele se deleitará em ti com alegria; calar-se-á por seu amor, regozijar-se-á em ti com júbilo." },
  { id: "ZEP 3:18", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 18, text: "Os que se entristeceram por causa da reunião solene, eu os congregarei; esses que são de ti e sobre os quais o opróbrio pesa." },
  { id: "ZEP 3:19", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 19, text: "Eis que naquele tempo procederei contra todos os que te afligem, e salvarei a que coxeia, e recolherei a que foi expulsa; e deles farei um louvor e um nome em toda a terra em que foram envergonhados." },
  { id: "ZEP 3:20", bookId: "ZEP", book: "Sofonias", chapter: 3, verse: 20, text: "Naquele tempo vos farei voltar, naquele tempo vos recolherei; certamente farei de vós um nome e um louvor entre todos os povos da terra, quando fizer voltar os vossos cativos diante dos vossos olhos, diz o Senhor." }
,
  // JOEL
  { id: "JOE 1:1", bookId: "JOE", book: "Joel", chapter: 1, verse: 1, text: "Palavra do SENHOR, que foi dirigida a Joel, filho de Petuel." },
  { id: "JOE 1:2", bookId: "JOE", book: "Joel", chapter: 1, verse: 2, text: "Ouvi isto, vós anciãos, e escutai, todos os moradores da terra: Porventura isto aconteceu em vossos dias, ou nos dias de vossos pais?" },
  { id: "JOE 1:3", bookId: "JOE", book: "Joel", chapter: 1, verse: 3, text: "Fazei sobre isto uma narração a vossos filhos, e vossos filhos a seus filhos, e os filhos destes à outra geração." },
  { id: "JOE 1:4", bookId: "JOE", book: "Joel", chapter: 1, verse: 4, text: "O que ficou da lagarta, o gafanhoto o comeu, e o que ficou do gafanhoto, a locusta o comeu, e o que ficou da locusta, o pulgão o comeu." },
  { id: "JOE 1:5", bookId: "JOE", book: "Joel", chapter: 1, verse: 5, text: "Despertai-vos, bêbados, e chorai; gemei, todos os que bebeis vinho, por causa do mosto, porque tirado é da vossa boca." },
  { id: "JOE 1:6", bookId: "JOE", book: "Joel", chapter: 1, verse: 6, text: "Porque subiu contra a minha terra uma nação poderosa e sem número; os seus dentes são dentes de leão, e têm queixadas de um leão velho." },
  { id: "JOE 1:7", bookId: "JOE", book: "Joel", chapter: 1, verse: 7, text: "Fez da minha vide uma assolação, e tirou a casca da minha figueira; despiu-a toda, e a lançou por terra; os seus sarmentos se embranqueceram." },
  { id: "JOE 1:8", bookId: "JOE", book: "Joel", chapter: 1, verse: 8, text: "Lamenta como a virgem que está cingida de saco, pelo marido da sua mocidade." },
  { id: "JOE 1:9", bookId: "JOE", book: "Joel", chapter: 1, verse: 9, text: "Foi cortada a oferta de alimentos e a libação da casa do Senhor; os sacerdotes, ministros do Senhor, estão entristecidos." },
  { id: "JOE 1:10", bookId: "JOE", book: "Joel", chapter: 1, verse: 10, text: "O campo está assolado, e a terra triste; porque o trigo está destruído, o mosto se secou, o azeite acabou." },
  { id: "JOE 1:11", bookId: "JOE", book: "Joel", chapter: 1, verse: 11, text: "Envergonhai-vos, lavradores, gemei, vinhateiros, sobre o trigo e a cevada; porque a colheita do campo pereceu." },
  { id: "JOE 1:12", bookId: "JOE", book: "Joel", chapter: 1, verse: 12, text: "A vide se secou, a figueira se murchou, a romeira também, e a palmeira e a macieira; todas as árvores do campo se secaram, e já não há alegria entre os filhos dos homens." },
  { id: "JOE 1:13", bookId: "JOE", book: "Joel", chapter: 1, verse: 13, text: "Cingi-vos e lamentai-vos, sacerdotes; gemei, ministros do altar; entrai e passai a noite vestidos de saco, ministros do meu Deus; porque a oferta de alimentos, e a libação, foram cortadas da casa de vosso Deus." },
  { id: "JOE 1:14", bookId: "JOE", book: "Joel", chapter: 1, verse: 14, text: "Santificai um jejum, convocai uma assembléia solene, congregai os anciãos, e todos os moradores desta terra, na casa do Senhor vosso Deus, e clamai ao Senhor." },
  { id: "JOE 1:15", bookId: "JOE", book: "Joel", chapter: 1, verse: 15, text: "Ai do dia! Porque o dia do Senhor está perto, e virá como uma assolação do Todo-Poderoso." },
  { id: "JOE 1:16", bookId: "JOE", book: "Joel", chapter: 1, verse: 16, text: "Porventura o mantimento não está cortado de diante de nossos olhos, a alegria e o regozijo da casa de nosso Deus?" },
  { id: "JOE 1:17", bookId: "JOE", book: "Joel", chapter: 1, verse: 17, text: "As sementes apodreceram debaixo dos seus torrões, os celeiros foram assolados, os armazéns derrubados, porque se secou o trigo." },
  { id: "JOE 1:18", bookId: "JOE", book: "Joel", chapter: 1, verse: 18, text: "Como geme o animal! As manadas de gados estão confusas, porque não têm pasto; também os rebanhos de ovelhas estão perecendo." },
  { id: "JOE 1:19", bookId: "JOE", book: "Joel", chapter: 1, verse: 19, text: "A ti, ó Senhor, clamo, porque o fogo consumiu os pastos do deserto, e a chama abrasou todas as árvores do campo." },
  { id: "JOE 1:20", bookId: "JOE", book: "Joel", chapter: 1, verse: 20, text: "Também todos os animais do campo bramam a ti; porque as correntes de água se secaram, e o fogo consumiu os pastos do deserto." },
  { id: "JOE 2:1", bookId: "JOE", book: "Joel", chapter: 2, verse: 1, text: "Tocai a trombeta em Sião, e clamai em alta voz no meu santo monte; tremam todos os moradores da terra, porque o dia do SENHOR vem, já está perto;" },
  { id: "JOE 2:2", bookId: "JOE", book: "Joel", chapter: 2, verse: 2, text: "Dia de trevas e de escuridão; dia de nuvens e densas trevas, como a alva espalhada sobre os montes; povo grande e poderoso, qual nunca houve desde o tempo antigo, nem depois dele haverá pelos anos adiante, de geração em geração." },
  { id: "JOE 2:3", bookId: "JOE", book: "Joel", chapter: 2, verse: 3, text: "Diante dele um fogo consome, e atrás dele uma chama abrasa; a terra diante dele é como o jardim do Éden, mas atrás dele um desolado deserto; sim, nada lhe escapará." },
  { id: "JOE 2:4", bookId: "JOE", book: "Joel", chapter: 2, verse: 4, text: "A sua aparência é como a de cavalos; e como cavaleiros assim correm." },
  { id: "JOE 2:5", bookId: "JOE", book: "Joel", chapter: 2, verse: 5, text: "Como o estrondo de carros, irão saltando sobre os cumes dos montes, como o ruído da chama de fogo que consome a pragana, como um povo poderoso, posto em ordem para o combate." },
  { id: "JOE 2:6", bookId: "JOE", book: "Joel", chapter: 2, verse: 6, text: "Diante dele temerão os povos; todos os rostos se tornarão enegrecidos." },
  { id: "JOE 2:7", bookId: "JOE", book: "Joel", chapter: 2, verse: 7, text: "Como valentes correrão, como homens de guerra subirão os muros; e marchará cada um no seu caminho e não se desviará da sua fileira." },
  { id: "JOE 2:8", bookId: "JOE", book: "Joel", chapter: 2, verse: 8, text: "Ninguém apertará a seu irmão; marchará cada um pelo seu caminho; sobre a mesma espada se arremessarão, e não serão feridos." },
  { id: "JOE 2:9", bookId: "JOE", book: "Joel", chapter: 2, verse: 9, text: "Irão pela cidade, correrão pelos muros, subirão às casas, entrarão pelas janelas como o ladrão." },
  { id: "JOE 2:10", bookId: "JOE", book: "Joel", chapter: 2, verse: 10, text: "Diante dele tremerá a terra, abalar-se-ão os céus; o sol e a lua se enegrecerão, e as estrelas retirarão o seu resplendor." },
  { id: "JOE 2:11", bookId: "JOE", book: "Joel", chapter: 2, verse: 11, text: "E o Senhor levantará a sua voz diante do seu exército; porque muitíssimo grande é o seu arraial; porque poderoso é, executando a sua palavra; porque o dia do Senhor é grande e mui terrível, e quem o poderá suportar?" },
  { id: "JOE 2:12", bookId: "JOE", book: "Joel", chapter: 2, verse: 12, text: "Ainda assim, agora mesmo diz o Senhor: Convertei-vos a mim de todo o vosso coração; e isso com jejuns, e com choro, e com pranto." },
  { id: "JOE 2:13", bookId: "JOE", book: "Joel", chapter: 2, verse: 13, text: "E rasgai o vosso coração, e não as vossas vestes, e convertei-vos ao Senhor vosso Deus; porque ele é misericordioso, e compassivo, e tardio em irar-se, e grande em benignidade, e se arrepende do mal." },
  { id: "JOE 2:14", bookId: "JOE", book: "Joel", chapter: 2, verse: 14, text: "Quem sabe se não se voltará e se arrependerá, e deixará após si uma bênção, em oferta de alimentos e libação para o Senhor vosso Deus?" },
  { id: "JOE 2:15", bookId: "JOE", book: "Joel", chapter: 2, verse: 15, text: "Tocai a trombeta em Sião, santificai um jejum, convocai uma assembléia solene." },
  { id: "JOE 2:16", bookId: "JOE", book: "Joel", chapter: 2, verse: 16, text: "Congregai o povo, santificai a congregação, ajuntai os anciãos, congregai as crianças, e os que mamam; saia o noivo da sua recâmara, e a noiva do seu aposento." },
  { id: "JOE 2:17", bookId: "JOE", book: "Joel", chapter: 2, verse: 17, text: "Chorem os sacerdotes, ministros do Senhor, entre o alpendre e o altar, e digam: Poupa a teu povo, ó Senhor, e não entregues a tua herança ao opróbrio, para que os gentios o dominem; por que diriam entre os povos: Onde está o seu Deus?" },
  { id: "JOE 2:18", bookId: "JOE", book: "Joel", chapter: 2, verse: 18, text: "Então o Senhor se mostrou zeloso da sua terra, e compadeceu-se do seu povo." },
  { id: "JOE 2:19", bookId: "JOE", book: "Joel", chapter: 2, verse: 19, text: "E o Senhor, respondendo, disse ao seu povo: Eis que vos envio o trigo, e o mosto, e o azeite, e deles sereis fartos, e vos não entregarei mais ao opróbrio entre os gentios." },
  { id: "JOE 2:20", bookId: "JOE", book: "Joel", chapter: 2, verse: 20, text: "Mas removerei para longe de vós o exército do norte, e lançá-lo-ei em uma terra seca e deserta; a sua frente para o mar oriental, e a sua retaguarda para o mar ocidental; e subirá o seu mau cheiro, e subirá a sua podridão; porque fez grandes coisas." },
  { id: "JOE 2:21", bookId: "JOE", book: "Joel", chapter: 2, verse: 21, text: "Não temas, ó terra: regozija-te e alegra-te, porque o Senhor fez grandes coisas." },
  { id: "JOE 2:22", bookId: "JOE", book: "Joel", chapter: 2, verse: 22, text: "Não temais, animais do campo, porque os pastos do deserto reverdecerão, porque o arvoredo dará o seu fruto, a vide e a figueira darão a sua força." },
  { id: "JOE 2:23", bookId: "JOE", book: "Joel", chapter: 2, verse: 23, text: "E vós, filhos de Sião, regozijai-vos e alegrai-vos no Senhor vosso Deus, porque ele vos dará em justa medida a chuva temporã; fará descer a chuva no primeiro mês, a temporã e a serôdia." },
  { id: "JOE 2:24", bookId: "JOE", book: "Joel", chapter: 2, verse: 24, text: "E as eiras se encherão de trigo, e os lagares trasbordarão de mosto e de azeite." },
  { id: "JOE 2:25", bookId: "JOE", book: "Joel", chapter: 2, verse: 25, text: "E restituir-vos-ei os anos que comeu o gafanhoto, a locusta, e o pulgão e a lagarta, o meu grande exército que enviei contra vós." },
  { id: "JOE 2:26", bookId: "JOE", book: "Joel", chapter: 2, verse: 26, text: "E comereis abundantemente e vos fartareis, e louvareis o nome do Senhor vosso Deus, que procedeu para convosco maravilhosamente; e o meu povo nunca mais será envergonhado." },
  { id: "JOE 2:27", bookId: "JOE", book: "Joel", chapter: 2, verse: 27, text: "E vós sabereis que eu estou no meio de Israel, e que eu sou o Senhor vosso Deus, e que não há outro; e o meu povo nunca mais será envergonhado." },
  { id: "JOE 2:28", bookId: "JOE", book: "Joel", chapter: 2, verse: 28, text: "E há de ser que, depois derramarei o meu Espírito sobre toda a carne, e vossos filhos e vossas filhas profetizarão, os vossos velhos terão sonhos, os vossos jovens terão visões." },
  { id: "JOE 2:29", bookId: "JOE", book: "Joel", chapter: 2, verse: 29, text: "E também sobre os servos e sobre as servas naqueles dias derramarei o meu Espírito." },
  { id: "JOE 2:30", bookId: "JOE", book: "Joel", chapter: 2, verse: 30, text: "E mostrarei prodígios no céu, e na terra, sangue e fogo, e colunas de fumaça." },
  { id: "JOE 2:31", bookId: "JOE", book: "Joel", chapter: 2, verse: 31, text: "O sol se converterá em trevas, e a lua em sangue, antes que venha o grande e terrível dia do Senhor." },
  { id: "JOE 2:32", bookId: "JOE", book: "Joel", chapter: 2, verse: 32, text: "E há de ser que todo aquele que invocar o nome do Senhor será salvo; porque no monte Sião e em Jerusalém haverá livramento, assim como disse o Senhor, e entre os sobreviventes, aqueles que o Senhor chamar." },
  { id: "JOE 3:1", bookId: "JOE", book: "Joel", chapter: 3, verse: 1, text: "Porque, eis que naqueles dias, e naquele tempo, em que removerei o cativeiro de Judá e de Jerusalém," },
  { id: "JOE 3:2", bookId: "JOE", book: "Joel", chapter: 3, verse: 2, text: "Congregarei todas as nações, e as farei descer ao vale de Jeosafá; e ali com elas entrarei em juízo, por causa do meu povo, e da minha herança, Israel, a quem elas espalharam entre as nações e repartiram a minha terra." },
  { id: "JOE 3:3", bookId: "JOE", book: "Joel", chapter: 3, verse: 3, text: "E lançaram sortes sobre o meu povo, e deram um menino por uma meretriz, e venderam uma menina por vinho, para beberem." },
  { id: "JOE 3:4", bookId: "JOE", book: "Joel", chapter: 3, verse: 4, text: "E também que tendes vós comigo, Tiro e Sidom, e todas as regiões da Filístia? É tal o pago que vós me dais? Pois se me pagais assim, bem depressa vos farei tornar a vossa paga sobre a vossa cabeça." },
  { id: "JOE 3:5", bookId: "JOE", book: "Joel", chapter: 3, verse: 5, text: "Visto como levastes a minha prata e o meu ouro, e as minhas coisas desejáveis e formosas pusestes nos vossos templos." },
  { id: "JOE 3:6", bookId: "JOE", book: "Joel", chapter: 3, verse: 6, text: "E vendestes os filhos de Judá e os filhos de Jerusalém aos filhos dos gregos, para os apartar para longe dos seus termos." },
  { id: "JOE 3:7", bookId: "JOE", book: "Joel", chapter: 3, verse: 7, text: "Eis que eu os suscitarei do lugar para onde os vendestes, e farei tornar a vossa paga sobre a vossa própria cabeça." },
  { id: "JOE 3:8", bookId: "JOE", book: "Joel", chapter: 3, verse: 8, text: "E venderei vossos filhos e vossas filhas na mão dos filhos de Judá, que os venderão aos sabeus, a um povo distante, porque o Senhor o disse." },
  { id: "JOE 3:9", bookId: "JOE", book: "Joel", chapter: 3, verse: 9, text: "Proclamai isto entre os gentios; preparai a guerra, suscitai os fortes; cheguem-se, subam todos os homens de guerra." },
  { id: "JOE 3:10", bookId: "JOE", book: "Joel", chapter: 3, verse: 10, text: "Forjai espadas das vossas enxadas, e lanças das vossas foices; diga o fraco: Eu sou forte." },
  { id: "JOE 3:11", bookId: "JOE", book: "Joel", chapter: 3, verse: 11, text: "Ajuntai-vos, e vinde, todos os gentios em redor, e congregai-vos. Ó Senhor, faze descer ali os teus fortes;" },
  { id: "JOE 3:12", bookId: "JOE", book: "Joel", chapter: 3, verse: 12, text: "Suscitem-se os gentios, e subam ao vale de Jeosafá; pois ali me assentarei para julgar todos os gentios em redor." },
  { id: "JOE 3:13", bookId: "JOE", book: "Joel", chapter: 3, verse: 13, text: "Lançai a foice, porque já está madura a seara; vinde, descei, porque o lagar está cheio, e os vasos dos lagares transbordam, porque a sua malícia é grande." },
  { id: "JOE 3:14", bookId: "JOE", book: "Joel", chapter: 3, verse: 14, text: "Multidões, multidões no vale da decisão; porque o dia do Senhor está perto, no vale da decisão." },
  { id: "JOE 3:15", bookId: "JOE", book: "Joel", chapter: 3, verse: 15, text: "O sol e a lua se enegrecerão, e as estrelas retirarão o seu resplendor." },
  { id: "JOE 3:16", bookId: "JOE", book: "Joel", chapter: 3, verse: 16, text: "E o Senhor bramará de Sião, e de Jerusalém fará ouvir a sua voz; e os céus e a terra tremerão, mas o Senhor será o refúgio do seu povo, e a fortaleza dos filhos de Israel." },
  { id: "JOE 3:17", bookId: "JOE", book: "Joel", chapter: 3, verse: 17, text: "E vós sabereis que eu sou o Senhor vosso Deus, que habito em Sião, o meu santo monte; e Jerusalém será santa; estranhos não passarão mais por ela." },
  { id: "JOE 3:18", bookId: "JOE", book: "Joel", chapter: 3, verse: 18, text: "E há de ser que, naquele dia, os montes destilarão mosto, e os outeiros manarão leite, e todos os rios de Judá estarão cheios de águas; e sairá uma fonte, da casa do Senhor, e regará o vale de Sitim." },
  { id: "JOE 3:19", bookId: "JOE", book: "Joel", chapter: 3, verse: 19, text: "O Egito se fará uma desolação, e Edom se fará um deserto assolado, por causa da violência que fizeram aos filhos de Judá, em cuja terra derramaram sangue inocente." },
  { id: "JOE 3:20", bookId: "JOE", book: "Joel", chapter: 3, verse: 20, text: "Mas Judá será habitada para sempre, e Jerusalém de geração em geração." },
  { id: "JOE 3:21", bookId: "JOE", book: "Joel", chapter: 3, verse: 21, text: "E purificarei o sangue dos que eu não tinha purificado; porque o Senhor habitará em Sião." },
  // AMÓS
  { id: "AMO 1:1", bookId: "AMO", book: "Amós", chapter: 1, verse: 1, text: "As palavras de Amós, que estava entre os pastores de Tecoa, as quais viu a respeito de Israel, nos dias de Uzias, rei de Judá, e nos dias de Jeroboão, filho de Joás, rei de Israel, dois anos antes do terremoto." },
  { id: "AMO 1:2", bookId: "AMO", book: "Amós", chapter: 1, verse: 2, text: "Ele disse: O Senhor bramará de Sião, e de Jerusalém fará ouvir a sua voz; os prados dos pastores prantearão, e secar-se-á o cume do Carmelo." },
  { id: "AMO 1:3", bookId: "AMO", book: "Amós", chapter: 1, verse: 3, text: "Assim diz o Senhor: Por três transgressões de Damasco, e por quatro, não retirarei o castigo, porque trilharam a Gileade com trilhos de ferro." },
  { id: "AMO 1:4", bookId: "AMO", book: "Amós", chapter: 1, verse: 4, text: "Por isso porei fogo à casa de Hazael, e ele consumirá os palácios de Ben-Hadade." },
  { id: "AMO 1:5", bookId: "AMO", book: "Amós", chapter: 1, verse: 5, text: "E quebrarei o ferrolho de Damasco, e exterminarei o morador do vale de Áven, e ao que tem o cetro de Bete-Éden; e o povo da Síria será levado em cativeiro a Quir, diz o Senhor." },
  { id: "AMO 1:6", bookId: "AMO", book: "Amós", chapter: 1, verse: 6, text: "Assim diz o Senhor: Por três transgressões de Gaza, e por quatro, não retirarei o castigo, porque levaram em cativeiro todos os cativos para os entregarem a Edom." },
  { id: "AMO 1:7", bookId: "AMO", book: "Amós", chapter: 1, verse: 7, text: "Por isso porei fogo ao muro de Gaza, e ele consumirá os seus palácios." },
  { id: "AMO 1:8", bookId: "AMO", book: "Amós", chapter: 1, verse: 8, text: "E exterminarei o morador de Asdode, e o que tem o cetro de Ascalom, e tornarei a minha mão contra Ecrom; e o restante dos filisteus perecerá, diz o Senhor DEUS." },
  { id: "AMO 1:9", bookId: "AMO", book: "Amós", chapter: 1, verse: 9, text: "Assim diz o Senhor: Por três transgressões de Tiro, e por quatro, não retirarei o castigo, porque entregaram todos os cativos a Edom, e não se lembraram da aliança dos irmãos." },
  { id: "AMO 1:10", bookId: "AMO", book: "Amós", chapter: 1, verse: 10, text: "Por isso porei fogo ao muro de Tiro, e ele consumirá os seus palácios." },
  { id: "AMO 1:11", bookId: "AMO", book: "Amós", chapter: 1, verse: 11, text: "Assim diz o Senhor: Por três transgressões de Edom, e por quatro, não retirarei o castigo, porque perseguiu a seu irmão à espada, e aniquilou as suas misericórdias; e a sua ira despedaçou eternamente, e conservou a sua indignação para sempre." },
  { id: "AMO 1:12", bookId: "AMO", book: "Amós", chapter: 1, verse: 12, text: "Por isso porei fogo a Temã, e ele consumirá os palácios de Bozra." },
  { id: "AMO 1:13", bookId: "AMO", book: "Amós", chapter: 1, verse: 13, text: "Assim diz o Senhor: Por três transgressões dos filhos de Amom, e por quatro, não retirarei o castigo, porque fenderam o ventre às grávidas de Gileade, para dilatarem os seus termos." },
  { id: "AMO 1:14", bookId: "AMO", book: "Amós", chapter: 1, verse: 14, text: "Por isso porei fogo ao muro de Rabá, e ele consumirá os seus palácios, com alarido no dia da batalha, com tempestade no dia da tormenta." },
  { id: "AMO 1:15", bookId: "AMO", book: "Amós", chapter: 1, verse: 15, text: "E o seu rei irá para o cativeiro, ele e os seus príncipes juntamente, diz o Senhor." },
  { id: "AMO 2:1", bookId: "AMO", book: "Amós", chapter: 2, verse: 1, text: "Assim diz o SENHOR: Por três transgressões de Moabe, e por quatro, não retirarei o castigo, porque queimou os ossos do rei de Edom, até os tornar a cal." },
  { id: "AMO 2:2", bookId: "AMO", book: "Amós", chapter: 2, verse: 2, text: "Por isso porei fogo a Moabe, e consumirá os palácios de Queriote; e Moabe morrerá com grande estrondo, com alarido, com som de trombeta." },
  { id: "AMO 2:3", bookId: "AMO", book: "Amós", chapter: 2, verse: 3, text: "E exterminarei o juiz do meio dele, e a todos os seus príncipes com ele matarei, diz o Senhor." },
  { id: "AMO 2:4", bookId: "AMO", book: "Amós", chapter: 2, verse: 4, text: "Assim diz o Senhor: Por três transgressões de Judá, e por quatro, não retirarei o castigo, porque rejeitaram a lei do Senhor, e não guardaram os seus estatutos, antes se deixaram enganar por suas próprias mentiras, após as quais andaram seus pais." },
  { id: "AMO 2:5", bookId: "AMO", book: "Amós", chapter: 2, verse: 5, text: "Por isso porei fogo a Judá, e ele consumirá os palácios de Jerusalém." },
  { id: "AMO 2:6", bookId: "AMO", book: "Amós", chapter: 2, verse: 6, text: "Assim diz o Senhor: Por três transgressões de Israel, e por quatro, não retirarei o castigo, porque vendem o justo por dinheiro, e o necessitado por um par de sapatos," },
  { id: "AMO 2:7", bookId: "AMO", book: "Amós", chapter: 2, verse: 7, text: "Suspirando pelo pó da terra, sobre a cabeça dos pobres, pervertem o caminho dos mansos; e um homem e seu pai entram à mesma moça, para profanarem o meu santo nome." },
  { id: "AMO 2:8", bookId: "AMO", book: "Amós", chapter: 2, verse: 8, text: "E se deitam junto a qualquer altar sobre roupas empenhadas, e na casa dos seus deuses bebem o vinho dos que tinham multado." },
  { id: "AMO 2:9", bookId: "AMO", book: "Amós", chapter: 2, verse: 9, text: "Todavia eu destruí diante dele o amorreu, cuja altura era como a altura dos cedros, e que era forte como os carvalhos; mas destruí o seu fruto por cima, e as suas raízes por baixo." },
  { id: "AMO 2:10", bookId: "AMO", book: "Amós", chapter: 2, verse: 10, text: "Também vos fiz subir da terra do Egito, e quarenta anos vos guiei no deserto, para que possuísseis a terra do amorreu." },
  { id: "AMO 2:11", bookId: "AMO", book: "Amós", chapter: 2, verse: 11, text: "E dentre vossos filhos suscitei profetas, e dentre os vossos jovens nazireus. Não é isto assim, filhos de Israel? diz o Senhor." },
  { id: "AMO 2:12", bookId: "AMO", book: "Amós", chapter: 2, verse: 12, text: "Mas vós aos nazireus destes vinho a beber, e aos profetas ordenastes, dizendo: Não profetizareis." },
  { id: "AMO 2:13", bookId: "AMO", book: "Amós", chapter: 2, verse: 13, text: "Eis que eu vos apertarei no vosso lugar como se aperta um carro cheio de feixes." },
  { id: "AMO 2:14", bookId: "AMO", book: "Amós", chapter: 2, verse: 14, text: "Assim perecerá a fuga ao ágil; nem o forte corroborará a sua força, nem o poderoso livrará a sua vida." },
  { id: "AMO 2:15", bookId: "AMO", book: "Amós", chapter: 2, verse: 15, text: "E não ficará em pé o que maneja o arco, nem o ligeiro de pés se livrará, nem tampouco se livrará o que vai montado a cavalo." },
  { id: "AMO 2:16", bookId: "AMO", book: "Amós", chapter: 2, verse: 16, text: "E o mais corajoso entre os fortes fugirá nu naquele dia, diz o Senhor." },
  { id: "AMO 3:1", bookId: "AMO", book: "Amós", chapter: 3, verse: 1, text: "Ouvi esta palavra que o SENHOR fala contra vós, filhos de Israel, contra toda a família que fiz subir da terra do Egito, dizendo:" },
  { id: "AMO 3:2", bookId: "AMO", book: "Amós", chapter: 3, verse: 2, text: "De todas as famílias da terra só a vós vos tenho conhecido; portanto eu vos punirei por todas as vossas iniqüidades." },
  { id: "AMO 3:3", bookId: "AMO", book: "Amós", chapter: 3, verse: 3, text: "Porventura andarão dois juntos, se não estiverem de acordo?" },
  { id: "AMO 3:4", bookId: "AMO", book: "Amós", chapter: 3, verse: 4, text: "Rugirá o leão no bosque, sem que tenha presa? Levantará o leãozinho no seu covil a sua voz, se nada tiver apanhado?" },
  { id: "AMO 3:5", bookId: "AMO", book: "Amós", chapter: 3, verse: 5, text: "Cairá a ave no laço em terra, se não houver armadilha para ela? Levantar-se-á da terra o laço, sem que tenha apanhado alguma coisa?" },
  { id: "AMO 3:6", bookId: "AMO", book: "Amós", chapter: 3, verse: 6, text: "Tocar-se-á a trombeta na cidade, e o povo não estremecerá? Sucederá algum mal na cidade, sem que o Senhor o tenha feito?" },
  { id: "AMO 3:7", bookId: "AMO", book: "Amós", chapter: 3, verse: 7, text: "Certamente o Senhor DEUS não fará coisa alguma, sem ter revelado o seu segredo aos seus servos, os profetas." },
  { id: "AMO 3:8", bookId: "AMO", book: "Amós", chapter: 3, verse: 8, text: "Rugiu o leão, quem não temerá? Falou o Senhor DEUS, quem não profetizará?" },
  { id: "AMO 3:9", bookId: "AMO", book: "Amós", chapter: 3, verse: 9, text: "Fazei ouvir isso nos palácios de Asdode, e nos palácios da terra do Egito, e dizei: Ajuntai-vos sobre os montes de Samaria, e vede que grandes alvoroços há no meio dela, e como são oprimidos dentro dela." },
  { id: "AMO 3:10", bookId: "AMO", book: "Amós", chapter: 3, verse: 10, text: "Porque não sabem fazer o que é reto, diz o Senhor, aqueles que entesouram nos seus palácios a violência e a destruição." },
  { id: "AMO 3:11", bookId: "AMO", book: "Amós", chapter: 3, verse: 11, text: "Portanto, o Senhor DEUS diz assim: O inimigo virá, e cercará a terra, derrubará a tua fortaleza, e os teus palácios serão saqueados." },
  { id: "AMO 3:12", bookId: "AMO", book: "Amós", chapter: 3, verse: 12, text: "Assim diz o Senhor: Como o pastor livra da boca do leão as duas pernas, ou um pedaço da orelha, assim serão livrados os filhos de Israel que habitam em Samaria, no canto da cama, e no damasco do leito." },
  { id: "AMO 3:13", bookId: "AMO", book: "Amós", chapter: 3, verse: 13, text: "Ouvi, e protestai contra a casa de Jacó, diz o Senhor DEUS, o Deus dos Exércitos;" },
  { id: "AMO 3:14", bookId: "AMO", book: "Amós", chapter: 3, verse: 14, text: "Pois no dia em que eu punir as transgressões de Israel, também castigarei os altares de Betel; e as pontas do altar serão cortadas, e cairão por terra." },
  { id: "AMO 3:15", bookId: "AMO", book: "Amós", chapter: 3, verse: 15, text: "E ferirei a casa de inverno juntamente com a casa de verão; e as casas de marfim perecerão, e as grandes casas terão fim, diz o Senhor." },
  { id: "AMO 4:1", bookId: "AMO", book: "Amós", chapter: 4, verse: 1, text: "Ouvi esta palavra vós, vacas de Basã, que estais no monte de Samaria, que oprimis aos pobres, que esmagais os necessitados, que dizeis a vossos senhores: Dai cá, e bebamos." },
  { id: "AMO 4:2", bookId: "AMO", book: "Amós", chapter: 4, verse: 2, text: "Jurou o Senhor DEUS, pela sua santidade, que dias estão para vir sobre vós, em que vos levarão com ganchos e a vossos descendentes com anzóis de pesca." },
  { id: "AMO 4:3", bookId: "AMO", book: "Amós", chapter: 4, verse: 3, text: "E saireis pelas brechas, uma após outra, e sereis lançadas para Harmom, disse o Senhor." },
  { id: "AMO 4:4", bookId: "AMO", book: "Amós", chapter: 4, verse: 4, text: "Vinde a Betel, e transgredi; a Gilgal, e multiplicai as transgressões; e cada manhã trazei os vossos sacrifícios, e os vossos dízimos de três em três dias." },
  { id: "AMO 4:5", bookId: "AMO", book: "Amós", chapter: 4, verse: 5, text: "E oferecei o sacrifício de louvores do que é levedado, e apregoai as ofertas voluntárias, publicai-as; porque disso gostais, ó filhos de Israel, disse o Senhor DEUS." },
  { id: "AMO 4:6", bookId: "AMO", book: "Amós", chapter: 4, verse: 6, text: "Por isso também vos dei limpeza de dentes em todas as vossas cidades, e falta de pão em todos os vossos lugares; contudo não vos convertestes a mim, disse o Senhor." },
  { id: "AMO 4:7", bookId: "AMO", book: "Amós", chapter: 4, verse: 7, text: "Além disso, retive de vós a chuva quando ainda faltavam três meses para a ceifa; e fiz que chovesse sobre uma cidade, e não chovesse sobre a outra cidade; sobre um campo choveu, mas o outro, sobre o qual não choveu, secou-se." },
  { id: "AMO 4:8", bookId: "AMO", book: "Amós", chapter: 4, verse: 8, text: "E andaram errantes duas ou três cidades, indo a outra cidade para beberem água, mas não se saciaram; contudo não vos convertestes a mim, disse o Senhor." },
  { id: "AMO 4:9", bookId: "AMO", book: "Amós", chapter: 4, verse: 9, text: "Feri-vos com queimadura, e com ferrugem; a multidão das vossas hortas, e das vossas vinhas, e das vossas figueiras, e das vossas oliveiras, comeu a locusta; contudo não vos convertestes a mim, disse o Senhor." },
  { id: "AMO 4:10", bookId: "AMO", book: "Amós", chapter: 4, verse: 10, text: "Enviei a peste contra vós, à maneira do Egito; os vossos jovens matei à espada, e os vossos cavalos deixei levar presos, e o mau cheiro dos vossos arraiais fiz subir às vossas narinas; contudo não vos convertestes a mim, disse o Senhor." },
  { id: "AMO 4:11", bookId: "AMO", book: "Amós", chapter: 4, verse: 11, text: "Subverti a alguns dentre vós, como Deus subverteu a Sodoma e Gomorra, e vós fostes como um tição arrebatado do incêndio; contudo não vos convertestes a mim, disse o Senhor." },
  { id: "AMO 4:12", bookId: "AMO", book: "Amós", chapter: 4, verse: 12, text: "Portanto, assim te farei, ó Israel! E porque isso te farei, prepara-te, ó Israel, para te encontrares com o teu Deus." },
  { id: "AMO 4:13", bookId: "AMO", book: "Amós", chapter: 4, verse: 13, text: "Porque eis aqui o que forma os montes, e cria o vento, e declara ao homem qual seja o seu pensamento, o que faz da manhã trevas, e pisa os altos da terra; o Senhor, o Deus dos Exércitos, é o seu nome." },
  { id: "AMO 5:1", bookId: "AMO", book: "Amós", chapter: 5, verse: 1, text: "Ouvi esta palavra, que levanto como uma lamentação sobre vós, ó casa de Israel." },
  { id: "AMO 5:2", bookId: "AMO", book: "Amós", chapter: 5, verse: 2, text: "A virgem de Israel caiu, e não mais tornará a levantar-se; desamparada está na sua terra, não há quem a levante." },
  { id: "AMO 5:3", bookId: "AMO", book: "Amós", chapter: 5, verse: 3, text: "Porque assim diz o Senhor DEUS: A cidade da qual saem mil conservará cem, e aquela da qual saem cem conservará dez, para a casa de Israel." },
  { id: "AMO 5:4", bookId: "AMO", book: "Amós", chapter: 5, verse: 4, text: "Porque assim diz o Senhor à casa de Israel: Buscai-me, e vivei." },
  { id: "AMO 5:5", bookId: "AMO", book: "Amós", chapter: 5, verse: 5, text: "Mas não busqueis a Betel, nem venhais a Gilgal, nem passeis a Berseba, porque Gilgal certamente será levada ao cativeiro, e Betel será desfeita em nada." },
  { id: "AMO 5:6", bookId: "AMO", book: "Amós", chapter: 5, verse: 6, text: "Buscai ao Senhor, e vivei, para que ele não irrompa na casa de José como um fogo, e a consuma, e não haja em Betel quem o apague." },
  { id: "AMO 5:7", bookId: "AMO", book: "Amós", chapter: 5, verse: 7, text: "Vós que converteis o juízo em alosna, e deitais por terra a justiça," },
  { id: "AMO 5:8", bookId: "AMO", book: "Amós", chapter: 5, verse: 8, text: "Procurai o que faz o sete-estrêlo e o órion e torna a sombra da noite em manhã, e faz escurecer o dia como a noite, que chama as águas do mar, e as derrama sobre a terra; o Senhor é o seu nome." },
  { id: "AMO 5:9", bookId: "AMO", book: "Amós", chapter: 5, verse: 9, text: "O que promove súbita destruição contra o forte; de modo que venha a destruição contra a fortaleza." },
  { id: "AMO 5:10", bookId: "AMO", book: "Amós", chapter: 5, verse: 10, text: "Odeiam na porta ao que os repreende, e abominam ao que fala sinceramente." },
  { id: "AMO 5:11", bookId: "AMO", book: "Amós", chapter: 5, verse: 11, text: "Portanto, visto que pisais o pobre e dele exigis um tributo de trigo, edificastes casas de pedras lavradas, mas nelas não habitareis; vinhas desejáveis plantastes, mas não bebereis do seu vinho." },
  { id: "AMO 5:12", bookId: "AMO", book: "Amós", chapter: 5, verse: 12, text: "Porque sei que são muitas as vossas transgressões e graves os vossos pecados; afligis o justo, tomais resgate, e rejeitais os necessitados na porta." },
  { id: "AMO 5:13", bookId: "AMO", book: "Amós", chapter: 5, verse: 13, text: "Portanto, o que for prudente guardará silêncio naquele tempo, porque o tempo será mau." },
  { id: "AMO 5:14", bookId: "AMO", book: "Amós", chapter: 5, verse: 14, text: "Buscai o bem, e não o mal, para que vivais; e assim o Senhor, o Deus dos Exércitos, estará convosco, como dizeis." },
  { id: "AMO 5:15", bookId: "AMO", book: "Amós", chapter: 5, verse: 15, text: "Odiai o mal, e amai o bem, e estabelecei na porta o juízo. Talvez o Senhor Deus dos Exércitos tenha piedade do remanescente de José." },
  { id: "AMO 5:16", bookId: "AMO", book: "Amós", chapter: 5, verse: 16, text: "Portanto, assim diz o Senhor, o Deus dos Exércitos, o Senhor: Em todas as ruas haverá pranto, e em todas as estradas dirão: Ai! Ai! E ao lavrador chamarão para choro, e para pranto os que souberem prantear." },
  { id: "AMO 5:17", bookId: "AMO", book: "Amós", chapter: 5, verse: 17, text: "E em todas as vinhas haverá pranto; porque passarei pelo meio de ti, diz o Senhor." },
  { id: "AMO 5:18", bookId: "AMO", book: "Amós", chapter: 5, verse: 18, text: "Ai daqueles que desejam o dia do Senhor! Para que quereis vós este dia do Senhor? Será de trevas e não de luz." },
  { id: "AMO 5:19", bookId: "AMO", book: "Amós", chapter: 5, verse: 19, text: "É como se um homem fugisse de diante do leão, e se encontrasse com ele o urso; ou como se entrando numa casa, a sua mão encostasse à parede, e fosse mordido por uma cobra." },
  { id: "AMO 5:20", bookId: "AMO", book: "Amós", chapter: 5, verse: 20, text: "Não será, pois, o dia do Senhor trevas e não luz, e escuridão, sem que haja resplendor?" },
  { id: "AMO 5:21", bookId: "AMO", book: "Amós", chapter: 5, verse: 21, text: "Odeio, desprezo as vossas festas, e as vossas assembléias solenes não me exalarão bom cheiro." },
  { id: "AMO 5:22", bookId: "AMO", book: "Amós", chapter: 5, verse: 22, text: "E ainda que me ofereçais holocaustos, ofertas de alimentos, não me agradarei delas; nem atentarei para as ofertas pacíficas de vossos animais gordos." },
  { id: "AMO 5:23", bookId: "AMO", book: "Amós", chapter: 5, verse: 23, text: "Afasta de mim o estrépito dos teus cânticos; porque não ouvirei as melodias das tuas violas." },
  { id: "AMO 5:24", bookId: "AMO", book: "Amós", chapter: 5, verse: 24, text: "Corra, porém, o juízo como as águas, e a justiça como o ribeiro impetuoso." },
  { id: "AMO 5:25", bookId: "AMO", book: "Amós", chapter: 5, verse: 25, text: "Oferecestes-me vós sacrifícios e oblações no deserto por quarenta anos, ó casa de Israel?" },
  { id: "AMO 5:26", bookId: "AMO", book: "Amós", chapter: 5, verse: 26, text: "Antes levastes a tenda de vosso Moloque, e a estátua das vossas imagens, a estrela do vosso deus, que fizestes para vós mesmos." },
  { id: "AMO 5:27", bookId: "AMO", book: "Amós", chapter: 5, verse: 27, text: "Portanto vos levarei cativos, para além de Damasco, diz o Senhor, cujo nome é o Deus dos Exércitos." },
  { id: "AMO 6:1", bookId: "AMO", book: "Amós", chapter: 6, verse: 1, text: "Ai dos que vivem sossegados em Sião, e dos que estão confiados no monte de Samaria, que têm nome entre as primeiras das nações, e aos quais vem a casa de Israel!" },
  { id: "AMO 6:2", bookId: "AMO", book: "Amós", chapter: 6, verse: 2, text: "Passai a Calne, e vede; e dali ide à grande Hamate; e depois descei a Gate dos filisteus; serão melhores que estes reinos? Ou maior o seu termo do que o vosso termo?" },
  { id: "AMO 6:3", bookId: "AMO", book: "Amós", chapter: 6, verse: 3, text: "Ó vós que afastais o dia mau, e fazeis chegar o assento da violência." },
  { id: "AMO 6:4", bookId: "AMO", book: "Amós", chapter: 6, verse: 4, text: "Ai dos que dormem em camas de marfim, e se estendem sobre os seus leitos, e comem os cordeiros do rebanho, e os bezerros do meio do curral;" },
  { id: "AMO 6:5", bookId: "AMO", book: "Amós", chapter: 6, verse: 5, text: "Que cantam ao som da viola, e inventam para si instrumentos musicais, assim como Davi;" },
  { id: "AMO 6:6", bookId: "AMO", book: "Amós", chapter: 6, verse: 6, text: "Que bebem vinho em taças, e se ungem com o mais excelente óleo: mas não se afligem pela ruína de José;" },
  { id: "AMO 6:7", bookId: "AMO", book: "Amós", chapter: 6, verse: 7, text: "Portanto agora irão em cativeiro entre os primeiros dos que forem levados cativos, e cessarão os festins dos banqueteadores." },
  { id: "AMO 6:8", bookId: "AMO", book: "Amós", chapter: 6, verse: 8, text: "Jurou o Senhor DEUS por si mesmo, diz o SENHOR, o Deus dos Exércitos: Abomino a soberba de Jacó, e odeio os seus palácios; por isso entregarei a cidade e tudo o que nela há." },
  { id: "AMO 6:9", bookId: "AMO", book: "Amós", chapter: 6, verse: 9, text: "E acontecerá que, se numa casa ficarem dez homens, morrerão." },
  { id: "AMO 6:10", bookId: "AMO", book: "Amós", chapter: 6, verse: 10, text: "Quando o tio de alguém, aquele que o queima, o tomar para levar-lhe os ossos para fora da casa, e disser ao que estiver no mais interior da casa: Está ainda alguém contigo? E este responder: Ninguém; então lhe dirá ele: Cala-te, porque não devemos fazer menção do nome do Senhor." },
  { id: "AMO 6:11", bookId: "AMO", book: "Amós", chapter: 6, verse: 11, text: "Porque, eis que o Senhor ordena, e ferirá a casa grande de brechas, e a casa pequena de fendas." },
  { id: "AMO 6:12", bookId: "AMO", book: "Amós", chapter: 6, verse: 12, text: "Porventura correrão cavalos sobre rocha? Lavrar-se-á nela com bois? Mas vós haveis tornado o juízo em fel, e o fruto da justiça em alosna;" },
  { id: "AMO 6:13", bookId: "AMO", book: "Amós", chapter: 6, verse: 13, text: "Vós que vos alegrais do nada, vós que dizeis: Não é assim que por nossa própria força nos temos tornado poderosos?" },
  { id: "AMO 6:14", bookId: "AMO", book: "Amós", chapter: 6, verse: 14, text: "Porque, eis que eu levantarei sobre vós, ó casa de Israel, uma nação, diz o Senhor, o Deus dos Exércitos, e oprimir-vos-á, desde a entrada de Hamate até ao ribeiro do deserto." },
  { id: "AMO 7:1", bookId: "AMO", book: "Amós", chapter: 7, verse: 1, text: "O SENHOR DEUS assim me fez ver, e eis que ele formava gafanhotos no princípio do rebento da erva serôdia, e eis que era a erva serôdia depois de findas as ceifas do rei." },
  { id: "AMO 7:2", bookId: "AMO", book: "Amós", chapter: 7, verse: 2, text: "E aconteceu que, tendo eles comido completamente a erva da terra, eu disse: Senhor DEUS, perdoa, rogo-te; quem levantará a Jacó? pois ele é pequeno." },
  { id: "AMO 7:3", bookId: "AMO", book: "Amós", chapter: 7, verse: 3, text: "Então o Senhor se arrependeu disso. Não acontecerá, disse o Senhor." },
  { id: "AMO 7:4", bookId: "AMO", book: "Amós", chapter: 7, verse: 4, text: "Assim me mostrou o Senhor DEUS: Eis que o Senhor DEUS clamava, para contender com fogo; este consumiu o grande abismo, e também uma parte da terra." },
  { id: "AMO 7:5", bookId: "AMO", book: "Amós", chapter: 7, verse: 5, text: "Então eu disse: Senhor Deus, cessa, eu te peço; quem levantará a Jacó? pois é pequeno." },
  { id: "AMO 7:6", bookId: "AMO", book: "Amós", chapter: 7, verse: 6, text: "E o SENHOR se arrependeu disso. Nem isso acontecerá, disse o Senhor DEUS." },
  { id: "AMO 7:7", bookId: "AMO", book: "Amós", chapter: 7, verse: 7, text: "Mostrou-me também assim: e eis que o Senhor estava sobre um muro, levantado a prumo; e tinha um prumo na sua mão." },
  { id: "AMO 7:8", bookId: "AMO", book: "Amós", chapter: 7, verse: 8, text: "E o Senhor me disse: Que vês tu, Amós? E eu disse: Um prumo. Então disse o Senhor: Eis que eu porei o prumo no meio do meu povo Israel; nunca mais passarei por ele." },
  { id: "AMO 7:9", bookId: "AMO", book: "Amós", chapter: 7, verse: 9, text: "Mas os altos de Isaque serão assolados, e destruídos os santuários de Israel; e levantar-me-ei com a espada contra a casa de Jeroboão." },
  { id: "AMO 7:10", bookId: "AMO", book: "Amós", chapter: 7, verse: 10, text: "Então Amazias, o sacerdote de Betel, mandou dizer a Jeroboão, rei de Israel: Amós tem conspirado contra ti, no meio da casa de Israel; a terra não poderá sofrer todas as suas palavras." },
  { id: "AMO 7:11", bookId: "AMO", book: "Amós", chapter: 7, verse: 11, text: "Porque assim diz Amós: Jeroboão morrerá à espada, e Israel certamente será levado para fora da sua terra em cativeiro." },
  { id: "AMO 7:12", bookId: "AMO", book: "Amós", chapter: 7, verse: 12, text: "Depois Amazias disse a Amós: Vai-te, ó vidente, e foge para a terra de Judá, e ali come o pão, e ali profetiza;" },
  { id: "AMO 7:13", bookId: "AMO", book: "Amós", chapter: 7, verse: 13, text: "Mas em Betel daqui por diante não profetizes mais, porque é o santuário do rei e casa real." },
  { id: "AMO 7:14", bookId: "AMO", book: "Amós", chapter: 7, verse: 14, text: "E respondeu Amós, dizendo a Amazias: Eu não sou profeta, nem filho de profeta, mas boiadeiro, e cultivador de sicômoros." },
  { id: "AMO 7:15", bookId: "AMO", book: "Amós", chapter: 7, verse: 15, text: "Mas o Senhor me tirou de seguir o rebanho, e o Senhor me disse: Vai, e profetiza ao meu povo Israel." },
  { id: "AMO 7:16", bookId: "AMO", book: "Amós", chapter: 7, verse: 16, text: "Agora, pois, ouve a palavra do Senhor: Tu dizes: Não profetizes contra Israel, nem fales contra a casa de Isaque." },
  { id: "AMO 7:17", bookId: "AMO", book: "Amós", chapter: 7, verse: 17, text: "Portanto assim diz o Senhor: Tua mulher se prostituirá na cidade, e teus filhos e tuas filhas cairão à espada, e a tua terra será repartida a cordel, e tu morrerás na terra imunda, e Israel certamente será levado cativo para fora da sua terra." },
  { id: "AMO 8:1", bookId: "AMO", book: "Amós", chapter: 8, verse: 1, text: "O SENHOR DEUS assim me fez ver: E eis aqui um cesto de frutos do verão." },
  { id: "AMO 8:2", bookId: "AMO", book: "Amós", chapter: 8, verse: 2, text: "E disse: Que vês, Amós? E eu disse: Um cesto de frutos do verão. Então o Senhor me disse: Chegou o fim sobre o meu povo Israel; nunca mais passarei por ele." },
  { id: "AMO 8:3", bookId: "AMO", book: "Amós", chapter: 8, verse: 3, text: "Mas os cânticos do templo naquele dia serão gemidos, diz o Senhor DEUS; multiplicar-se-ão os cadáveres; em todos os lugares serão lançados fora em silêncio." },
  { id: "AMO 8:4", bookId: "AMO", book: "Amós", chapter: 8, verse: 4, text: "Ouvi isto, vós que anelais o abatimento do necessitado; e destruís os miseráveis da terra," },
  { id: "AMO 8:5", bookId: "AMO", book: "Amós", chapter: 8, verse: 5, text: "Dizendo: Quando passará a lua nova, para vendermos o grão, e o sábado, para abrirmos os celeiros de trigo, diminuindo o efa, e aumentando o siclo, e procedendo dolosamente com balanças enganosas," },
  { id: "AMO 8:6", bookId: "AMO", book: "Amós", chapter: 8, verse: 6, text: "Para comprarmos os pobres por dinheiro, e os necessitados por um par de sapatos, e para vendermos o refugo do trigo?" },
  { id: "AMO 8:7", bookId: "AMO", book: "Amós", chapter: 8, verse: 7, text: "Jurou o Senhor pela glória de Jacó: Eu não me esquecerei de todas as suas obras para sempre." },
  { id: "AMO 8:8", bookId: "AMO", book: "Amós", chapter: 8, verse: 8, text: "Por causa disto não estremecerá a terra, e não chorará todo aquele que nela habita? Certamente levantar-se-á toda ela como o grande rio, e será agitada, e baixará como o rio do Egito." },
  { id: "AMO 8:9", bookId: "AMO", book: "Amós", chapter: 8, verse: 9, text: "E sucederá que, naquele dia, diz o Senhor Deus, farei que o sol se ponha ao meio-dia, e a terra se entenebreça no dia claro." },
  { id: "AMO 8:10", bookId: "AMO", book: "Amós", chapter: 8, verse: 10, text: "E tornarei as vossas festas em luto, e todos os vossos cânticos em lamentações; e porei pano de saco sobre todos os lombos, e calva sobre toda cabeça; e farei que isso seja como luto por um filho único, e o seu fim como dia de amarguras." },
  { id: "AMO 8:11", bookId: "AMO", book: "Amós", chapter: 8, verse: 11, text: "Eis que vêm dias, diz o Senhor DEUS, em que enviarei fome sobre a terra; não fome de pão, nem sede de água, mas de ouvir as palavras do SENHOR." },
  { id: "AMO 8:12", bookId: "AMO", book: "Amós", chapter: 8, verse: 12, text: "E irão errantes de um mar até outro mar, e do norte até ao oriente; correrão por toda a parte, buscando a palavra do Senhor, mas não a acharão." },
  { id: "AMO 8:13", bookId: "AMO", book: "Amós", chapter: 8, verse: 13, text: "Naquele dia as virgens formosas e os jovens desmaiarão de sede." },
  { id: "AMO 8:14", bookId: "AMO", book: "Amós", chapter: 8, verse: 14, text: "Os que juram pela culpa de Samaria, dizendo: Vive o teu deus, ó Dã; e vive o caminho de Berseba; esses mesmos cairão, e não se levantarão jamais." },
  { id: "AMO 9:1", bookId: "AMO", book: "Amós", chapter: 9, verse: 1, text: "Vi o Senhor, que estava em pé sobre o altar; e me disse: Fere o capitel, e estremeçam os umbrais, e faze tudo em pedaços sobre a cabeça de todos eles; e eu matarei à espada até ao último deles; nenhum deles conseguirá fugir, nenhum deles escapará." },
  { id: "AMO 9:2", bookId: "AMO", book: "Amós", chapter: 9, verse: 2, text: "Ainda que cavem até ao inferno, a minha mão os tirará dali; e, se subirem ao céu, dali os farei descer." },
  { id: "AMO 9:3", bookId: "AMO", book: "Amós", chapter: 9, verse: 3, text: "E, se se esconderem no cume do Carmelo, buscá-los-ei, e dali os tirarei; e, se dos meus olhos se ocultarem no fundo do mar, ali darei ordem à serpente, e ela os picará." },
  { id: "AMO 9:4", bookId: "AMO", book: "Amós", chapter: 9, verse: 4, text: "E, se forem em cativeiro diante de seus inimigos, ali darei ordem à espada que os mate; e eu porei os meus olhos sobre eles para o mal, e não para o bem." },
  { id: "AMO 9:5", bookId: "AMO", book: "Amós", chapter: 9, verse: 5, text: "Porque o Senhor DEUS dos Exércitos é o que toca a terra, e ela se derrete, e todos os que habitam nela chorarão; e ela subirá toda como um rio, e abaixará como o rio do Egito." },
  { id: "AMO 9:6", bookId: "AMO", book: "Amós", chapter: 9, verse: 6, text: "Ele é o que edifica as suas câmaras superiores no céu, e fundou na terra a sua abóbada, e o que chama as águas do mar, e as derrama sobre a terra; o Senhor é o seu nome." },
  { id: "AMO 9:7", bookId: "AMO", book: "Amós", chapter: 9, verse: 7, text: "Não me sois, vós, ó filhos de Israel, como os filhos dos etíopes? diz o Senhor: Não fiz eu subir a Israel da terra do Egito, e aos filisteus de Caftor, e aos sírios de Quir?" },
  { id: "AMO 9:8", bookId: "AMO", book: "Amós", chapter: 9, verse: 8, text: "Eis que os olhos do Senhor DEUS estão contra este reino pecador, e eu o destruirei de sobre a face da terra; mas não destruirei de todo a casa de Jacó, diz o SENHOR." },
  { id: "AMO 9:9", bookId: "AMO", book: "Amós", chapter: 9, verse: 9, text: "Porque eis que darei ordem, e sacudirei a casa de Israel entre todas as nações, assim como se sacode grão no crivo, sem que caia na terra um só grão." },
  { id: "AMO 9:10", bookId: "AMO", book: "Amós", chapter: 9, verse: 10, text: "Todos os pecadores do meu povo morrerão à espada, os que dizem: Não nos alcançará nem nos encontrará o mal." },
  { id: "AMO 9:11", bookId: "AMO", book: "Amós", chapter: 9, verse: 11, text: "Naquele dia tornarei a levantar o tabernáculo caído de Davi, e repararei as suas brechas, e tornarei a levantar as suas ruínas, e o edificarei como nos dias da antigüidade;" },
  { id: "AMO 9:12", bookId: "AMO", book: "Amós", chapter: 9, verse: 12, text: "Para que possuam o restante de Edom, e todos os gentios que são chamados pelo meu nome, diz o Senhor, que faz essas coisas." },
  { id: "AMO 9:13", bookId: "AMO", book: "Amós", chapter: 9, verse: 13, text: "Eis que vêm dias, diz o Senhor, em que o que lavra alcançará ao que sega, e o que pisa as uvas ao que lança a semente; e os montes destilarão mosto, e todos os outeiros se derreterão." },
  { id: "AMO 9:14", bookId: "AMO", book: "Amós", chapter: 9, verse: 14, text: "E trarei do cativeiro meu povo Israel, e eles reedificarão as cidades assoladas, e nelas habitarão, e plantarão vinhas, e beberão o seu vinho, e farão pomares, e lhes comerão o fruto." },
  { id: "AMO 9:15", bookId: "AMO", book: "Amós", chapter: 9, verse: 15, text: "E plantá-los-ei na sua terra, e não serão mais arrancados da sua terra que lhes dei, diz o Senhor teu Deus." },
  // JONAS
  { id: "JON 1:1", bookId: "JON", book: "Jonas", chapter: 1, verse: 1, text: "E veio a palavra do SENHOR a Jonas, filho de Amitai, dizendo:" },
  { id: "JON 1:2", bookId: "JON", book: "Jonas", chapter: 1, verse: 2, text: "Levanta-te, vai à grande cidade de Nínive, e clama contra ela, porque a sua malícia subiu até à minha presença." },
  { id: "JON 1:3", bookId: "JON", book: "Jonas", chapter: 1, verse: 3, text: "Porém, Jonas se levantou para fugir da presença do Senhor para Társis. E descendo a Jope, achou um navio que ia para Társis; pagou, pois, a sua passagem, e desceu para dentro dele, para ir com eles para Társis, para longe da presença do Senhor." },
  { id: "JON 1:4", bookId: "JON", book: "Jonas", chapter: 1, verse: 4, text: "Mas o Senhor mandou ao mar um grande vento, e fez-se no mar uma forte tempestade, e o navio estava a ponto de quebrar-se." },
  { id: "JON 1:5", bookId: "JON", book: "Jonas", chapter: 1, verse: 5, text: "Então temeram os marinheiros, e clamavam cada um ao seu deus, e lançaram ao mar as cargas, que estavam no navio, para o aliviarem do seu peso; Jonas, porém, desceu ao porão do navio, e, tendo-se deitado, dormia um profundo sono." },
  { id: "JON 1:6", bookId: "JON", book: "Jonas", chapter: 1, verse: 6, text: "E o mestre do navio chegou- se a ele, e disse-lhe: Que tens, dorminhoco? Levanta-te, clama ao teu Deus; talvez assim ele se lembre de nós para que não pereçamos." },
  { id: "JON 1:7", bookId: "JON", book: "Jonas", chapter: 1, verse: 7, text: "E diziam cada um ao seu companheiro: Vinde, e lancemos sortes, para que saibamos por que causa nos sobreveio este mal. E lançaram sortes, e a sorte caiu sobre Jonas." },
  { id: "JON 1:8", bookId: "JON", book: "Jonas", chapter: 1, verse: 8, text: "Então lhe disseram: Declara-nos tu agora, por causa de quem nos sobreveio este mal. Que ocupação é a tua? Donde vens? Qual é a tua terra? E de que povo és tu?" },
  { id: "JON 1:9", bookId: "JON", book: "Jonas", chapter: 1, verse: 9, text: "E ele lhes disse: Eu sou hebreu, e temo ao Senhor, o Deus do céu, que fez o mar e a terra seca." },
  { id: "JON 1:10", bookId: "JON", book: "Jonas", chapter: 1, verse: 10, text: "Então estes homens se enche-ram de grande temor, e disseram-lhe: Por que fizeste tu isto? Pois sabiam os homens que fugia da presença do Senhor, porque ele lho tinha declarado." },
  { id: "JON 1:11", bookId: "JON", book: "Jonas", chapter: 1, verse: 11, text: "E disseram-lhe: Que te faremos nós, para que o mar se nos acalme? Porque o mar ia se tornando cada vez mais tempestuoso." },
  { id: "JON 1:12", bookId: "JON", book: "Jonas", chapter: 1, verse: 12, text: "E ele lhes disse: Levantai-me, e lançai-me ao mar, e o mar se vos aquietará; porque eu sei que por minha causa vos sobreveio esta grande tempestade." },
  { id: "JON 1:13", bookId: "JON", book: "Jonas", chapter: 1, verse: 13, text: "Entretanto, os homens remavam, para fazer voltar o navio à terra, mas não podiam, porquanto o mar se ia embravecendo cada vez mais contra eles." },
  { id: "JON 1:14", bookId: "JON", book: "Jonas", chapter: 1, verse: 14, text: "Então clamaram ao Senhor, e disseram: Ah, Senhor! Nós te rogamos, que não pereçamos por causa da alma deste homem, e que não ponhas sobre nós o sangue inocente; porque tu, Senhor, fizeste como te aprouve." },
  { id: "JON 1:15", bookId: "JON", book: "Jonas", chapter: 1, verse: 15, text: "E levantaram a Jonas, e o lançaram ao mar, e cessou o mar da sua fúria." },
  { id: "JON 1:16", bookId: "JON", book: "Jonas", chapter: 1, verse: 16, text: "Temeram, pois, estes homens ao Senhor com grande temor; e ofereceram sacrifício ao Senhor, e fizeram votos." },
  { id: "JON 1:17", bookId: "JON", book: "Jonas", chapter: 1, verse: 17, text: "Preparou, pois, o Senhor um grande peixe, para que tragasse a Jonas; e esteve Jonas três dias e três noites nas entranhas do peixe." },
  { id: "JON 2:1", bookId: "JON", book: "Jonas", chapter: 2, verse: 1, text: "E orou Jonas ao SENHOR, seu Deus, das entranhas do peixe." },
  { id: "JON 2:2", bookId: "JON", book: "Jonas", chapter: 2, verse: 2, text: "E disse: Na minha angústia clamei ao Senhor, e ele me respondeu; do ventre do inferno gritei, e tu ouviste a minha voz." },
  { id: "JON 2:3", bookId: "JON", book: "Jonas", chapter: 2, verse: 3, text: "Porque tu me lançaste no profundo, no coração dos mares, e a corrente das águas me cercou; todas as tuas ondas e as tuas vagas têm passado por cima de mim." },
  { id: "JON 2:4", bookId: "JON", book: "Jonas", chapter: 2, verse: 4, text: "E eu disse: Lançado estou de diante dos teus olhos; todavia tornarei a ver o teu santo templo." },
  { id: "JON 2:5", bookId: "JON", book: "Jonas", chapter: 2, verse: 5, text: "As águas me cercaram até à alma, o abismo me rodeou, e as algas se enrolaram na minha cabeça." },
  { id: "JON 2:6", bookId: "JON", book: "Jonas", chapter: 2, verse: 6, text: "Eu desci até aos fundamentos dos montes; a terra me encerrou para sempre com os seus ferrolhos; mas tu fizeste subir a minha vida da perdição, ó Senhor meu Deus." },
  { id: "JON 2:7", bookId: "JON", book: "Jonas", chapter: 2, verse: 7, text: "Quando desfalecia em mim a minha alma, lembrei-me do Senhor; e entrou a ti a minha oração, no teu santo templo." },
  { id: "JON 2:8", bookId: "JON", book: "Jonas", chapter: 2, verse: 8, text: "Os que observam as falsas vaidades deixam a sua misericórdia." },
  { id: "JON 2:9", bookId: "JON", book: "Jonas", chapter: 2, verse: 9, text: "Mas eu te oferecerei sacrifício com a voz do agradecimento; o que votei pagarei. Do Senhor vem a salvação." },
  { id: "JON 2:10", bookId: "JON", book: "Jonas", chapter: 2, verse: 10, text: "Falou, pois, o Senhor ao peixe, e este vomitou a Jonas na terra seca." },
  { id: "JON 3:1", bookId: "JON", book: "Jonas", chapter: 3, verse: 1, text: "E veio a palavra do SENHOR segunda vez a Jonas, dizendo:" },
  { id: "JON 3:2", bookId: "JON", book: "Jonas", chapter: 3, verse: 2, text: "Levanta-te, e vai à grande cidade de Nínive, e prega contra ela a mensagem que eu te digo." },
  { id: "JON 3:3", bookId: "JON", book: "Jonas", chapter: 3, verse: 3, text: "E levantou-se Jonas, e foi a Nínive, segundo a palavra do Senhor. Ora, Nínive era uma cidade muito grande, de três dias de caminho." },
  { id: "JON 3:4", bookId: "JON", book: "Jonas", chapter: 3, verse: 4, text: "E começou Jonas a entrar pela cidade caminho de um dia, e pregava, dizendo: Ainda quarenta dias, e Nínive será subvertida." },
  { id: "JON 3:5", bookId: "JON", book: "Jonas", chapter: 3, verse: 5, text: "E os homens de Nínive creram em Deus; e proclamaram um jejum, e vestiram-se de saco, desde o maior até ao menor." },
  { id: "JON 3:6", bookId: "JON", book: "Jonas", chapter: 3, verse: 6, text: "Esta palavra chegou também ao rei de Nínive; e ele levantou-se do seu trono, e tirou de si as suas vestes, e cobriu-se de saco, e sentou-se sobre a cinza." },
  { id: "JON 3:7", bookId: "JON", book: "Jonas", chapter: 3, verse: 7, text: "E fez uma proclamação que se divulgou em Nínive, pelo decreto do rei e dos seus grandes, dizendo: Nem homens, nem animais, nem bois, nem ovelhas provem coisa alguma, nem se lhes dê alimentos, nem bebam água;" },
  { id: "JON 3:8", bookId: "JON", book: "Jonas", chapter: 3, verse: 8, text: "Mas os homens e os animais sejam cobertos de sacos, e clamem fortemente a Deus, e convertam-se, cada um do seu mau caminho, e da violência que há nas suas mãos." },
  { id: "JON 3:9", bookId: "JON", book: "Jonas", chapter: 3, verse: 9, text: "Quem sabe se se voltará Deus, e se arrependerá, e se apartará do furor da sua ira, de sorte que não pereçamos?" },
  { id: "JON 3:10", bookId: "JON", book: "Jonas", chapter: 3, verse: 10, text: "E Deus viu as obras deles, como se converteram do seu mau caminho; e Deus se arrependeu do mal que tinha anunciado lhes faria, e não o fez." },
  { id: "JON 4:1", bookId: "JON", book: "Jonas", chapter: 4, verse: 1, text: "Mas isso desagradou extremamente a Jonas, e ele ficou irado." },
  { id: "JON 4:2", bookId: "JON", book: "Jonas", chapter: 4, verse: 2, text: "E orou ao Senhor, e disse: Ah! Senhor! Não foi esta minha palavra, estando ainda na minha terra? Por isso é que me preveni, fugindo para Társis, pois sabia que és Deus compassivo e misericordioso, longânimo e grande em benignidade, e que te arrependes do mal." },
  { id: "JON 4:3", bookId: "JON", book: "Jonas", chapter: 4, verse: 3, text: "Peço-te, pois, ó Senhor, tira-me a vida, porque melhor me é morrer do que viver." },
  { id: "JON 4:4", bookId: "JON", book: "Jonas", chapter: 4, verse: 4, text: "E disse o Senhor: Fazes bem que assim te ires?" },
  { id: "JON 4:5", bookId: "JON", book: "Jonas", chapter: 4, verse: 5, text: "Então Jonas saiu da cidade, e sentou-se ao oriente dela; e ali fez uma cabana, e sentou-se debaixo dela, à sombra, até ver o que aconteceria à cidade." },
  { id: "JON 4:6", bookId: "JON", book: "Jonas", chapter: 4, verse: 6, text: "E fez o Senhor Deus nascer uma aboboreira, e ela subiu por cima de Jonas, para que fizesse sombra sobre a sua cabeça, a fim de o livrar do seu enfado; e Jonas se alegrou em extremo por causa da aboboreira." },
  { id: "JON 4:7", bookId: "JON", book: "Jonas", chapter: 4, verse: 7, text: "Mas Deus enviou um verme, no dia seguinte ao subir da alva, o qual feriu a aboboreira, e esta se secou." },
  { id: "JON 4:8", bookId: "JON", book: "Jonas", chapter: 4, verse: 8, text: "E aconteceu que, aparecendo o sol, Deus mandou um vento calmoso oriental, e o sol feriu a cabeça de Jonas; e ele desmaiou, e desejou com toda a sua alma morrer, dizendo: Melhor me é morrer do que viver." },
  { id: "JON 4:9", bookId: "JON", book: "Jonas", chapter: 4, verse: 9, text: "Então disse Deus a Jonas: Fazes bem que assim te ires por causa da aboboreira? E ele disse: Faço bem que me revolte até à morte." },
  { id: "JON 4:10", bookId: "JON", book: "Jonas", chapter: 4, verse: 10, text: "E disse o Senhor: Tiveste tu compaixão da aboboreira, na qual não trabalhaste, nem a fizeste crescer, que numa noite nasceu, e numa noite pereceu;" },
  { id: "JON 4:11", bookId: "JON", book: "Jonas", chapter: 4, verse: 11, text: "E não hei de eu ter compaixão da grande cidade de Nínive, em que estão mais de cento e vinte mil homens que não sabem discernir entre a sua mão direita e a sua mão esquerda, e também muitos animais?" },
  // OSÉIAS
  { id: "HOS 1:1", bookId: "HOS", book: "Oséias", chapter: 1, verse: 1, text: "Palavra do SENHOR, que foi dirigida a Oséias, filho de Beeri, nos dias de Uzias, Jotão, Acaz, Ezequias, reis de Judá, e nos dias de Jeroboão, filho de Joás, rei de Israel." },
  { id: "HOS 1:2", bookId: "HOS", book: "Oséias", chapter: 1, verse: 2, text: "O princípio da palavra do Senhor por meio de Oséias. Disse, pois, o Senhor a Oséias: Vai, toma uma mulher de prostituições, e filhos de prostituição; porque a terra certamente se prostitui, desviando-se do Senhor." },
  { id: "HOS 1:3", bookId: "HOS", book: "Oséias", chapter: 1, verse: 3, text: "Foi, pois, e tomou a Gômer, filha de Diblaim, e ela concebeu, e lhe deu um filho." },
  { id: "HOS 1:4", bookId: "HOS", book: "Oséias", chapter: 1, verse: 4, text: "E disse-lhe o Senhor: Põe-lhe o nome de Jizreel; porque daqui a pouco visitarei o sangue de Jizreel sobre a casa de Jeú, e farei cessar o reino da casa de Israel." },
  { id: "HOS 1:5", bookId: "HOS", book: "Oséias", chapter: 1, verse: 5, text: "E naquele dia quebrarei o arco de Israel no vale de Jizreel." },
  { id: "HOS 1:6", bookId: "HOS", book: "Oséias", chapter: 1, verse: 6, text: "E tornou ela a conceber, e deu à luz uma filha. E Deus disse: Põe-lhe o nome de Lo-Ruama; porque eu não tornarei mais a compadecer-me da casa de Israel, mas tudo lhe tirarei." },
  { id: "HOS 1:7", bookId: "HOS", book: "Oséias", chapter: 1, verse: 7, text: "Mas da casa de Judá me compadecerei, e os salvarei pelo Senhor seu Deus, pois não os salvarei pelo arco, nem pela espada, nem pela guerra, nem pelos cavalos, nem pelos cavaleiros." },
  { id: "HOS 1:8", bookId: "HOS", book: "Oséias", chapter: 1, verse: 8, text: "E, depois de haver desmamado a Lo-Ruama, concebeu e deu à luz um filho." },
  { id: "HOS 1:9", bookId: "HOS", book: "Oséias", chapter: 1, verse: 9, text: "E Deus disse: Põe-lhe o nome de Lo-Ami; porque vós não sois meu povo, nem eu serei vosso Deus." },
  { id: "HOS 1:10", bookId: "HOS", book: "Oséias", chapter: 1, verse: 10, text: "Todavia o número dos filhos de Israel será como a areia do mar, que não pode medir-se nem contar-se; e acontecerá que no lugar onde se lhes dizia: Vós não sois meu povo, se lhes dirá: Vós sois filhos do Deus vivo." },
  { id: "HOS 1:11", bookId: "HOS", book: "Oséias", chapter: 1, verse: 11, text: "E os filhos de Judá e os filhos de Israel juntos se congregarão, e constituirão sobre si uma só cabeça, e subirão da terra; porque grande será o dia de Jizreel." },
  { id: "HOS 2:1", bookId: "HOS", book: "Oséias", chapter: 2, verse: 1, text: "Dizei a vossos irmãos: Ami; e a vossas irmãs: Ruama." },
  { id: "HOS 2:2", bookId: "HOS", book: "Oséias", chapter: 2, verse: 2, text: "Contendei com vossa mãe, contendei, porque ela não é minha mulher, e eu não sou seu marido; e desvie ela as suas prostituições da sua vista e os seus adultérios de entre os seus seios." },
  { id: "HOS 2:3", bookId: "HOS", book: "Oséias", chapter: 2, verse: 3, text: "Para que eu não a despoje, ficando ela nua, e a ponha como no dia em que nasceu, e a faça como um deserto, e a torne como uma terra seca, e a mate à sede;" },
  { id: "HOS 2:4", bookId: "HOS", book: "Oséias", chapter: 2, verse: 4, text: "E não me compadeça de seus filhos, porque são filhos de prostituições." },
  { id: "HOS 2:5", bookId: "HOS", book: "Oséias", chapter: 2, verse: 5, text: "Porque sua mãe se prostituiu; aquela que os concebeu houve-se torpemente, porque diz: Irei atrás de meus amantes, que me dão o meu pão e a minha água, a minha lã e o meu linho, o meu óleo e as minhas bebidas." },
  { id: "HOS 2:6", bookId: "HOS", book: "Oséias", chapter: 2, verse: 6, text: "Portanto, eis que cercarei o teu caminho com espinhos; e levantarei um muro de sebe, para que ela não ache as suas veredas." },
  { id: "HOS 2:7", bookId: "HOS", book: "Oséias", chapter: 2, verse: 7, text: "Ela irá atrás de seus amantes, mas não os alcançará; e buscá-los-á, mas não os achará; então dirá: Ir-me-ei, e tornar-me-ei a meu primeiro marido, porque melhor me ia então do que agora." },
  { id: "HOS 2:8", bookId: "HOS", book: "Oséias", chapter: 2, verse: 8, text: "Ela, pois, não reconhece que eu lhe dei o grão, e o mosto, e o azeite, e que lhe multipliquei a prata e o ouro, que eles usaram para Baal." },
  { id: "HOS 2:9", bookId: "HOS", book: "Oséias", chapter: 2, verse: 9, text: "Portanto tornarei a tirar o meu grão a seu tempo e o meu mosto no seu tempo determinado; e arrebatarei a minha lã e o meu linho, com que cobriam a sua nudez." },
  { id: "HOS 2:10", bookId: "HOS", book: "Oséias", chapter: 2, verse: 10, text: "E agora descobrirei a sua vileza diante dos olhos dos seus amantes, e ninguém a livrará da minha mão." },
  { id: "HOS 2:11", bookId: "HOS", book: "Oséias", chapter: 2, verse: 11, text: "E farei cessar todo o seu gozo, as suas festas, as suas luas novas, e os seus sábados, e todas as suas festividades." },
  { id: "HOS 2:12", bookId: "HOS", book: "Oséias", chapter: 2, verse: 12, text: "E devastarei a sua vide e a sua figueira, de que ela diz: É esta a minha paga que me deram os meus amantes; eu, pois, farei delas um bosque, e as feras do campo as devorarão." },
  { id: "HOS 2:13", bookId: "HOS", book: "Oséias", chapter: 2, verse: 13, text: "Castigá-la-ei pelos dias dos Baalins, nos quais lhes queimou incenso, e se adornou dos seus pendentes e das suas jóias, e andou atrás de seus amantes, mas de mim se esqueceu, diz o SENHOR." },
  { id: "HOS 2:14", bookId: "HOS", book: "Oséias", chapter: 2, verse: 14, text: "Portanto, eis que eu a atrairei, e a levarei para o deserto, e lhe falarei ao coração." },
  { id: "HOS 2:15", bookId: "HOS", book: "Oséias", chapter: 2, verse: 15, text: "E lhe darei as suas vinhas dali, e o vale de Acor, por porta de esperança; e ali cantará, como nos dias de sua mocidade, e como no dia em que subiu da terra do Egito." },
  { id: "HOS 2:16", bookId: "HOS", book: "Oséias", chapter: 2, verse: 16, text: "E naquele dia, diz o SENHOR, tu me chamarás: Meu marido; e não mais me chamarás: Meu senhor." },
  { id: "HOS 2:17", bookId: "HOS", book: "Oséias", chapter: 2, verse: 17, text: "E da sua boca tirarei os nomes dos Baalins, e não mais se lembrará desses nomes." },
  { id: "HOS 2:18", bookId: "HOS", book: "Oséias", chapter: 2, verse: 18, text: "E naquele dia farei por eles aliança com as feras do campo, e com as aves do céu, e com os répteis da terra; e da terra quebrarei o arco, e a espada, e a guerra, e os farei deitar em segurança." },
  { id: "HOS 2:19", bookId: "HOS", book: "Oséias", chapter: 2, verse: 19, text: "E desposar-te-ei comigo para sempre; desposar-te-ei comigo em justiça, e em juízo, e em benignidade, e em misericórdias." },
  { id: "HOS 2:20", bookId: "HOS", book: "Oséias", chapter: 2, verse: 20, text: "E desposar-te-ei comigo em fidelidade, e conhecerás ao Senhor." },
  { id: "HOS 2:21", bookId: "HOS", book: "Oséias", chapter: 2, verse: 21, text: "E acontecerá naquele dia que eu atenderei, diz o Senhor; eu atenderei aos céus, e estes atenderão à terra." },
  { id: "HOS 2:22", bookId: "HOS", book: "Oséias", chapter: 2, verse: 22, text: "E a terra atenderá ao trigo, e ao mosto, e ao azeite, e estes atenderão a Jizreel." },
  { id: "HOS 2:23", bookId: "HOS", book: "Oséias", chapter: 2, verse: 23, text: "E semeá-la-ei para mim na terra, e compadecer-me-ei dela que não obteve misericórdia; e eu direi àquele que não era meu povo: Tu és meu povo; e ele dirá: Tu és meu Deus!" },
  { id: "HOS 3:1", bookId: "HOS", book: "Oséias", chapter: 3, verse: 1, text: "E o SENHOR me disse: Vai outra vez, ama uma mulher, amada de seu amigo, contudo adúltera, como o SENHOR ama os filhos de Israel, embora eles olhem para outros deuses, e amem os bolos de uvas." },
  { id: "HOS 3:2", bookId: "HOS", book: "Oséias", chapter: 3, verse: 2, text: "E comprei-a para mim por quinze peças de prata, e um ômer, e meio ômer de cevada;" },
  { id: "HOS 3:3", bookId: "HOS", book: "Oséias", chapter: 3, verse: 3, text: "E ele lhe disse: Tu ficarás comigo muitos dias; não te prostituirás, nem serás de outro homem; assim também eu esperarei por ti." },
  { id: "HOS 3:4", bookId: "HOS", book: "Oséias", chapter: 3, verse: 4, text: "Porque os filhos de Israel ficarão por muitos dias sem rei, e sem príncipe, e sem sacrifício, e sem estátua, e sem éfode ou terafim." },
  { id: "HOS 3:5", bookId: "HOS", book: "Oséias", chapter: 3, verse: 5, text: "Depois tornarão os filhos de Israel, e buscarão ao Senhor seu Deus, e a Davi, seu rei; e temerão ao Senhor, e à sua bondade, no fim dos dias." },
  { id: "HOS 4:1", bookId: "HOS", book: "Oséias", chapter: 4, verse: 1, text: "Ouvi a palavra do SENHOR, vós filhos de Israel, porque o SENHOR tem uma contenda com os habitantes da terra; porque na terra não há verdade, nem benignidade, nem conhecimento de Deus." },
  { id: "HOS 4:2", bookId: "HOS", book: "Oséias", chapter: 4, verse: 2, text: "Só permanecem o perjurar, o mentir, o matar, o furtar e o adulterar; fazem violência, um ato sanguinário segue imediatamente a outro." },
  { id: "HOS 4:3", bookId: "HOS", book: "Oséias", chapter: 4, verse: 3, text: "Por isso a terra se lamentará, e qualquer que morar nela desfalecerá, com os animais do campo e com as aves do céu; e até os peixes do mar serão tirados." },
  { id: "HOS 4:4", bookId: "HOS", book: "Oséias", chapter: 4, verse: 4, text: "Todavia ninguém contenda, ninguém repreenda, porque o teu povo é como os que contendem com o sacerdote." },
  { id: "HOS 4:5", bookId: "HOS", book: "Oséias", chapter: 4, verse: 5, text: "Por isso tropeçarás de dia, e o profeta contigo tropeçará de noite; e destruirei a tua mãe." },
  { id: "HOS 4:6", bookId: "HOS", book: "Oséias", chapter: 4, verse: 6, text: "O meu povo foi destruído, porque lhe faltou o conhecimento; porque tu rejeitaste o conhecimento, também eu te rejeitarei, para que não sejas sacerdote diante de mim; e, visto que te esqueceste da lei do teu Deus, também eu me esquecerei de teus filhos." },
  { id: "HOS 4:7", bookId: "HOS", book: "Oséias", chapter: 4, verse: 7, text: "Como eles se multiplicaram, assim pecaram contra mim; eu mudarei a sua honra em vergonha." },
  { id: "HOS 4:8", bookId: "HOS", book: "Oséias", chapter: 4, verse: 8, text: "Comem da oferta pelo pecado do meu povo, e pela transgressão dele têm desejo ardente." },
  { id: "HOS 4:9", bookId: "HOS", book: "Oséias", chapter: 4, verse: 9, text: "Por isso, como é o povo, assim será o sacerdote; e castigá-lo-ei segundo os seus caminhos, e dar-lhe-ei a recompensa das suas obras." },
  { id: "HOS 4:10", bookId: "HOS", book: "Oséias", chapter: 4, verse: 10, text: "Comerão, mas não se fartarão; entregar-se-ão à luxúria, mas não se multiplicarão; porque deixaram de atentar ao Senhor." },
  { id: "HOS 4:11", bookId: "HOS", book: "Oséias", chapter: 4, verse: 11, text: "A luxúria, e o vinho, e o mosto tiram o coração." },
  { id: "HOS 4:12", bookId: "HOS", book: "Oséias", chapter: 4, verse: 12, text: "O meu povo consulta a sua madeira, e a sua vara lhe responde, porque o espírito da luxúria os engana, e prostituem-se, apartando-se da sujeição do seu Deus." },
  { id: "HOS 4:13", bookId: "HOS", book: "Oséias", chapter: 4, verse: 13, text: "Sacrificam sobre os cumes dos montes, e queimam incenso sobre os outeiros, debaixo do carvalho, e do álamo, e do olmeiro, porque é boa a sua sombra; por isso vossas filhas se prostituem, e as vossas noras adulteram." },
  { id: "HOS 4:14", bookId: "HOS", book: "Oséias", chapter: 4, verse: 14, text: "Eu não castigarei vossas filhas, quando se prostituem, nem vossas noras, quando adulteram; porque eles mesmos com as prostitutas se desviam, e com as meretrizes sacrificam; pois o povo que não tem entendimento será transtornado." },
  { id: "HOS 4:15", bookId: "HOS", book: "Oséias", chapter: 4, verse: 15, text: "Ainda que tu, ó Israel, queiras prostituir-te, contudo não se faça culpado Judá; não venhais a Gilgal, e não subais a Bete-Áven, e não jureis, dizendo: Vive o Senhor." },
  { id: "HOS 4:16", bookId: "HOS", book: "Oséias", chapter: 4, verse: 16, text: "Porque como uma novilha obstinada se rebelou Israel; agora o Senhor os apascentará como a um cordeiro num lugar espaçoso." },
  { id: "HOS 4:17", bookId: "HOS", book: "Oséias", chapter: 4, verse: 17, text: "Efraim está entregue aos ídolos; deixa-o." },
  { id: "HOS 4:18", bookId: "HOS", book: "Oséias", chapter: 4, verse: 18, text: "A sua bebida se foi; lançaram-se à luxúria continuamente; certamente os seus governadores amam a vergonha." },
  { id: "HOS 4:19", bookId: "HOS", book: "Oséias", chapter: 4, verse: 19, text: "Um vento os envolveu nas suas asas, e envergonhar-se-ão por causa dos seus sacrifícios." },
  { id: "HOS 5:1", bookId: "HOS", book: "Oséias", chapter: 5, verse: 1, text: "Ouvi isto, ó sacerdotes, e escutai, ó casa de Israel, e dai ouvidos, ó casa do rei, porque contra vós se dirige este juízo, visto que fostes um laço para Mizpá, e rede estendida sobre o Tabor." },
  { id: "HOS 5:2", bookId: "HOS", book: "Oséias", chapter: 5, verse: 2, text: "Os revoltos se aprofundaram na matança; mas eu castigarei a todos eles." },
  { id: "HOS 5:3", bookId: "HOS", book: "Oséias", chapter: 5, verse: 3, text: "Eu conheço a Efraim, e Israel não se esconde de mim; porque agora te tens prostituído, ó Efraim, e Israel se contaminou." },
  { id: "HOS 5:4", bookId: "HOS", book: "Oséias", chapter: 5, verse: 4, text: "Não querem ordenar as suas ações a fim de voltarem para o seu Deus, porque o espírito das prostituições está no meio deles, e não conhecem ao Senhor." },
  { id: "HOS 5:5", bookId: "HOS", book: "Oséias", chapter: 5, verse: 5, text: "A soberba de Israel testificará no seu rosto; e Israel e Efraim cairão pela sua injustiça, e Judá cairá juntamente com eles." },
  { id: "HOS 5:6", bookId: "HOS", book: "Oséias", chapter: 5, verse: 6, text: "Então irão com os seus rebanhos, e com o seu gado, para buscarem ao Senhor, mas não o acharão; ele se retirou deles." },
  { id: "HOS 5:7", bookId: "HOS", book: "Oséias", chapter: 5, verse: 7, text: "Aleivosamente se houveram contra o Senhor, porque geraram filhos estranhos; agora em um só mês os consumirá com as suas porções." },
  { id: "HOS 5:8", bookId: "HOS", book: "Oséias", chapter: 5, verse: 8, text: "Tocai a buzina em Gibeá, a trombeta em Ramá; gritai altamente em Bete-Áven; depois de ti, ó Benjamim." },
  { id: "HOS 5:9", bookId: "HOS", book: "Oséias", chapter: 5, verse: 9, text: "Efraim será para assolação no dia do castigo; entre as tribos de Israel manifestei o que está certo." },
  { id: "HOS 5:10", bookId: "HOS", book: "Oséias", chapter: 5, verse: 10, text: "Os príncipes de Judá são como os que mudam os limites; derramarei, pois, o meu furor sobre eles como água." },
  { id: "HOS 5:11", bookId: "HOS", book: "Oséias", chapter: 5, verse: 11, text: "Efraim está oprimido e quebrantado no juízo, porque quis andar após o mandamento dos homens." },
  { id: "HOS 5:12", bookId: "HOS", book: "Oséias", chapter: 5, verse: 12, text: "Portanto a Efraim serei como a traça, e para a casa de Judá como a podridão." },
  { id: "HOS 5:13", bookId: "HOS", book: "Oséias", chapter: 5, verse: 13, text: "Quando Efraim viu a sua enfermidade, e Judá a sua chaga, subiu Efraim à Assíria e enviou ao rei Jarebe; mas ele não poderá sarar-vos, nem curar a vossa chaga." },
  { id: "HOS 5:14", bookId: "HOS", book: "Oséias", chapter: 5, verse: 14, text: "Porque para Efraim serei como um leão, e como um leãozinho à casa de Judá: eu, eu o despedaçarei, e irme-ei embora; arrebatarei, e não haverá quem livre." },
  { id: "HOS 5:15", bookId: "HOS", book: "Oséias", chapter: 5, verse: 15, text: "Irei e voltarei ao meu lugar, até que se reconheçam culpados e busquem a minha face; estando eles angustiados, de madrugada me buscarão." },
  { id: "HOS 6:1", bookId: "HOS", book: "Oséias", chapter: 6, verse: 1, text: "Vinde, e tornemos ao SENHOR, porque ele despedaçou, e nos sarará; feriu, e nos atará a ferida." },
  { id: "HOS 6:2", bookId: "HOS", book: "Oséias", chapter: 6, verse: 2, text: "Depois de dois dias nos dará a vida; ao terceiro dia nos ressuscitará, e viveremos diante dele." },
  { id: "HOS 6:3", bookId: "HOS", book: "Oséias", chapter: 6, verse: 3, text: "Então conheçamos, e prossigamos em conhecer ao Senhor; a sua saída, como a alva, é certa; e ele a nós virá como a chuva, como chuva serôdia que rega a terra." },
  { id: "HOS 6:4", bookId: "HOS", book: "Oséias", chapter: 6, verse: 4, text: "Que te farei, ó Efraim? Que te farei, ó Judá? Porque a vossa benignidade é como a nuvem da manhã e como o orvalho da madrugada, que cedo passa." },
  { id: "HOS 6:5", bookId: "HOS", book: "Oséias", chapter: 6, verse: 5, text: "Por isso os abati pelos profetas; pelas palavras da minha boca os matei; e os teus juízos sairão como a luz," },
  { id: "HOS 6:6", bookId: "HOS", book: "Oséias", chapter: 6, verse: 6, text: "Porque eu quero a misericórdia, e não o sacrifício; e o conhecimento de Deus, mais do que os holocaustos." },
  { id: "HOS 6:7", bookId: "HOS", book: "Oséias", chapter: 6, verse: 7, text: "Mas eles transgrediram a aliança, como Adão; eles se portaram aleivosamente contra mim." },
  { id: "HOS 6:8", bookId: "HOS", book: "Oséias", chapter: 6, verse: 8, text: "Gileade é a cidade dos que praticam iniqüidade, manchada de sangue." },
  { id: "HOS 6:9", bookId: "HOS", book: "Oséias", chapter: 6, verse: 9, text: "Como as hordas de salteadores que esperam alguns, assim é a companhia dos sacerdotes que matam no caminho num mesmo consenso; sim, eles cometem abominações." },
  { id: "HOS 6:10", bookId: "HOS", book: "Oséias", chapter: 6, verse: 10, text: "Vejo uma coisa horrenda na casa de Israel, ali está a prostituição de Efraim; Israel está contaminado." },
  { id: "HOS 6:11", bookId: "HOS", book: "Oséias", chapter: 6, verse: 11, text: "Também para ti, ó Judá, está assinada uma sega, quando eu trouxer o cativeiro do meu povo." },
  { id: "HOS 7:1", bookId: "HOS", book: "Oséias", chapter: 7, verse: 1, text: "Sarando eu a Israel, se descobriu a iniqüidade de Efraim, como também as maldades de Samaria, porque praticaram a falsidade; e o ladrão entra, e a horda dos salteadores despoja por fora." },
  { id: "HOS 7:2", bookId: "HOS", book: "Oséias", chapter: 7, verse: 2, text: "E não dizem no seu coração que eu me lembro de toda a sua maldade; agora, pois, os cercam as suas obras; diante da minha face estão." },
  { id: "HOS 7:3", bookId: "HOS", book: "Oséias", chapter: 7, verse: 3, text: "Com a sua malícia alegram ao rei, e com as suas mentiras aos príncipes." },
  { id: "HOS 7:4", bookId: "HOS", book: "Oséias", chapter: 7, verse: 4, text: "Todos eles são adúlteros; são semelhantes ao forno aceso pelo padeiro, que cessa de mexer nas brasas, depois que amassou a massa, até que seja levedada." },
  { id: "HOS 7:5", bookId: "HOS", book: "Oséias", chapter: 7, verse: 5, text: "E no dia do nosso rei os príncipes se tornaram doentes com frascos de vinho; ele estendeu a sua mão com os escarnecedores." },
  { id: "HOS 7:6", bookId: "HOS", book: "Oséias", chapter: 7, verse: 6, text: "Porque, prepararam o coração como um forno, na sua emboscada; toda a noite dorme o seu padeiro, pela manhã arde como fogo de chama." },
  { id: "HOS 7:7", bookId: "HOS", book: "Oséias", chapter: 7, verse: 7, text: "Todos eles estão quentes como um forno, e consomem os seus juízes; todos os seus reis caem, ninguém entre eles há que me invoque." },
  { id: "HOS 7:8", bookId: "HOS", book: "Oséias", chapter: 7, verse: 8, text: "Efraim se mistura com os povos; Efraim é um bolo que não foi virado." },
  { id: "HOS 7:9", bookId: "HOS", book: "Oséias", chapter: 7, verse: 9, text: "Estrangeiros lhe comeram a força, e ele não o sabe; também as cãs se espalharam sobre ele, e não o sabe." },
  { id: "HOS 7:10", bookId: "HOS", book: "Oséias", chapter: 7, verse: 10, text: "E a soberba de Israel testificará diante dele; todavia não voltarão para o Senhor seu Deus, nem o buscarão em tudo isto." },
  { id: "HOS 7:11", bookId: "HOS", book: "Oséias", chapter: 7, verse: 11, text: "Porque Efraim é como uma pomba ingênua, sem entendimento; invocam o Egito, vão para a Assíria." },
  { id: "HOS 7:12", bookId: "HOS", book: "Oséias", chapter: 7, verse: 12, text: "Quando forem, sobre eles estenderei a minha rede, e como aves do céu os farei descer; castigá-los-ei, conforme o que eles têm ouvido na sua congregação." },
  { id: "HOS 7:13", bookId: "HOS", book: "Oséias", chapter: 7, verse: 13, text: "Ai deles, porque fugiram de mim; destruição sobre eles, porque se rebelaram contra mim; eu os remi, mas disseram mentiras contra mim." },
  { id: "HOS 7:14", bookId: "HOS", book: "Oséias", chapter: 7, verse: 14, text: "E não clamaram a mim com seu coração, mas davam uivos nas suas camas; para o trigo e para o vinho se ajuntam, mas contra mim se rebelam." },
  { id: "HOS 7:15", bookId: "HOS", book: "Oséias", chapter: 7, verse: 15, text: "Eu os corrigi, e lhes esforcei os braços, mas pensam mal contra mim." },
  { id: "HOS 7:16", bookId: "HOS", book: "Oséias", chapter: 7, verse: 16, text: "Eles voltaram, mas não para o Altíssimo. Fizeram-se como um arco enganador; caem à espada os seus príncipes, por causa do furor da sua língua; este será o seu escárnio na terra do Egito." },
  { id: "HOS 8:1", bookId: "HOS", book: "Oséias", chapter: 8, verse: 1, text: "Põe a trombeta à tua boca. Ele virá como a águia contra a casa do SENHOR, porque transgrediram a minha aliança, e se rebelaram contra a minha lei." },
  { id: "HOS 8:2", bookId: "HOS", book: "Oséias", chapter: 8, verse: 2, text: "E a mim clamarão: Deus meu! Nós, Israel, te conhecemos." },
  { id: "HOS 8:3", bookId: "HOS", book: "Oséias", chapter: 8, verse: 3, text: "Israel rejeitou o bem; o inimigo persegui-lo-á." },
  { id: "HOS 8:4", bookId: "HOS", book: "Oséias", chapter: 8, verse: 4, text: "Eles fizeram reis, mas não por mim; constituíram príncipes, mas eu não o soube; da sua prata e do seu ouro fizeram ídolos para si, para serem destruídos." },
  { id: "HOS 8:5", bookId: "HOS", book: "Oséias", chapter: 8, verse: 5, text: "O teu bezerro, ó Samaria, te rejeitou; a minha ira se acendeu contra eles; até quando serão eles incapazes da inocência?" },
  { id: "HOS 8:6", bookId: "HOS", book: "Oséias", chapter: 8, verse: 6, text: "Porque isso vem de Israel, um artífice o fez, e não é Deus; mas em pedaços será desfeito o bezerro de Samaria." },
  { id: "HOS 8:7", bookId: "HOS", book: "Oséias", chapter: 8, verse: 7, text: "Porque semearam vento, e segarão tormenta, não haverá seara, a erva não dará farinha; se a der, tragá-la-ão os estrangeiros." },
  { id: "HOS 8:8", bookId: "HOS", book: "Oséias", chapter: 8, verse: 8, text: "Israel foi devorado; agora está entre os gentios como um vaso em que ninguém tem prazer." },
  { id: "HOS 8:9", bookId: "HOS", book: "Oséias", chapter: 8, verse: 9, text: "Porque subiram à Assíria, como um jumento montês, por si só; Efraim mercou amores." },
  { id: "HOS 8:10", bookId: "HOS", book: "Oséias", chapter: 8, verse: 10, text: "Todavia, ainda que eles merquem entre as nações, eu os congregarei; e serão um pouco afligidos por causa da carga do rei dos príncipes." },
  { id: "HOS 8:11", bookId: "HOS", book: "Oséias", chapter: 8, verse: 11, text: "Porquanto Efraim multiplicou os altares para pecar; teve altares para pecar." },
  { id: "HOS 8:12", bookId: "HOS", book: "Oséias", chapter: 8, verse: 12, text: "Escrevi-lhe as grandezas da minha lei, porém essas são estimadas como coisa estranha." },
  { id: "HOS 8:13", bookId: "HOS", book: "Oséias", chapter: 8, verse: 13, text: "Quanto aos sacrifícios das minhas ofertas, sacrificam carne, e a comem, mas o Senhor não as aceita; agora se lembrará da sua iniqüidade, e punirá os seus pecados; eles voltarão para o Egito." },
  { id: "HOS 8:14", bookId: "HOS", book: "Oséias", chapter: 8, verse: 14, text: "Porque Israel se esqueceu do seu Criador, e edificou templos, e Judá multiplicou cidades fortificadas. Mas eu enviarei um fogo contra as suas cidades, que consumirá os seus palácios." },
  { id: "HOS 9:1", bookId: "HOS", book: "Oséias", chapter: 9, verse: 1, text: "Não te alegres, ó Israel, não exultes, como os povos; porque ao prostituir-te abandonaste o teu Deus; amaste a paga de meretriz sobre todas as eiras de trigo." },
  { id: "HOS 9:2", bookId: "HOS", book: "Oséias", chapter: 9, verse: 2, text: "A eira e o lagar não os manterão; e o mosto lhes faltará." },
  { id: "HOS 9:3", bookId: "HOS", book: "Oséias", chapter: 9, verse: 3, text: "Na terra do Senhor não permanecerão; mas Efraim tornará ao Egito, e na Assíria comerão comida imunda." },
  { id: "HOS 9:4", bookId: "HOS", book: "Oséias", chapter: 9, verse: 4, text: "Não derramarão libações de vinho ao Senhor, nem lhe agradarão as suas ofertas. Os seus sacrifícios lhes serão como pão de pranteadores; todos os que dele comerem serão imundos, porque o seu pão será somente para si mesmos; não entrará na casa do Senhor." },
  { id: "HOS 9:5", bookId: "HOS", book: "Oséias", chapter: 9, verse: 5, text: "Que fareis vós no dia da solenidade, e no dia da festa do Senhor?" },
  { id: "HOS 9:6", bookId: "HOS", book: "Oséias", chapter: 9, verse: 6, text: "Porque, eis que eles se foram por causa da destruição, mas o Egito os recolherá, Mênfis os sepultará; o desejável da sua prata as urtigas o possuirão por herança, espinhos crescerão nas suas tendas." },
  { id: "HOS 9:7", bookId: "HOS", book: "Oséias", chapter: 9, verse: 7, text: "Chegarão os dias da punição, chegarão os dias da retribuição; Israel o saberá; o profeta é um insensato, o homem de espírito é um louco; por causa da abundância da tua iniqüidade também haverá grande ódio." },
  { id: "HOS 9:8", bookId: "HOS", book: "Oséias", chapter: 9, verse: 8, text: "Efraim era o vigia com o meu Deus, mas o profeta é como um laço de caçador de aves em todos os seus caminhos, e ódio na casa do seu Deus." },
  { id: "HOS 9:9", bookId: "HOS", book: "Oséias", chapter: 9, verse: 9, text: "Muito profundamente se corromperam, como nos dias de Gibeá; ele lembrar-se-á das suas injustiças, visitará os pecados deles." },
  { id: "HOS 9:10", bookId: "HOS", book: "Oséias", chapter: 9, verse: 10, text: "Achei a Israel como uvas no deserto, vi a vossos pais como a fruta temporã da figueira no seu princípio; mas eles foram para Baal-Peor, e se consagraram a essa vergonha, e se tornaram abomináveis como aquilo que amaram." },
  { id: "HOS 9:11", bookId: "HOS", book: "Oséias", chapter: 9, verse: 11, text: "Quanto a Efraim, a sua glória como ave voará, não haverá nascimento, não haverá gestação nem concepção." },
  { id: "HOS 9:12", bookId: "HOS", book: "Oséias", chapter: 9, verse: 12, text: "Ainda que venham a criar seus filhos, contudo os privarei deles para que não fique nenhum homem. Ai deles, quando deles eu me apartar!" },
  { id: "HOS 9:13", bookId: "HOS", book: "Oséias", chapter: 9, verse: 13, text: "Efraim, assim como vi a Tiro, está plantado num lugar aprazível; mas Efraim levará os seus filhos ao matador." },
  { id: "HOS 9:14", bookId: "HOS", book: "Oséias", chapter: 9, verse: 14, text: "Dá-lhes, ó Senhor; mas que lhes darás? Dá-lhes uma madre que aborte e seios secos." },
  { id: "HOS 9:15", bookId: "HOS", book: "Oséias", chapter: 9, verse: 15, text: "Toda a sua malícia se acha em Gilgal, porque ali os odiei; por causa da maldade das suas obras lançá-los-ei para fora de minha casa. Não os amarei mais; todos os seus príncipes são rebeldes." },
  { id: "HOS 9:16", bookId: "HOS", book: "Oséias", chapter: 9, verse: 16, text: "Efraim foi ferido, secou-se a sua raiz; não darão fruto; sim, ainda que gerem, matarei os frutos desejáveis do seu ventre." },
  { id: "HOS 9:17", bookId: "HOS", book: "Oséias", chapter: 9, verse: 17, text: "O meu Deus os rejeitará, porque não o ouviram, e errantes andarão entre as nações." },
  { id: "HOS 10:1", bookId: "HOS", book: "Oséias", chapter: 10, verse: 1, text: "Israel é uma vide estéril que dá fruto para si mesmo; conforme a abundância do seu fruto, multiplicou também os altares; conforme a bondade da sua terra, assim, fizeram boas as estátuas." },
  { id: "HOS 10:2", bookId: "HOS", book: "Oséias", chapter: 10, verse: 2, text: "O seu coração está dividido, por isso serão culpados; o Senhor demolirá os seus altares, e destruirá as suas estátuas." },
  { id: "HOS 10:3", bookId: "HOS", book: "Oséias", chapter: 10, verse: 3, text: "Certamente agora dirão: Não temos rei, porque não tememos ao Senhor; e o rei, que faria por nós?" },
  { id: "HOS 10:4", bookId: "HOS", book: "Oséias", chapter: 10, verse: 4, text: "Falaram palavras, jurando falsamente, fazendo uma aliança; por isso florescerá o juízo como erva peçonhenta nos sulcos dos campos." },
  { id: "HOS 10:5", bookId: "HOS", book: "Oséias", chapter: 10, verse: 5, text: "Os moradores de Samaria serão atemorizados pelo bezerro de Bete-«ven; porque o seu povo se lamentará por causa dele, como também os seus sacerdotes idólatras que nele se regozijavam, por causa da sua glória, que se apartou dela." },
  { id: "HOS 10:6", bookId: "HOS", book: "Oséias", chapter: 10, verse: 6, text: "Também será levada para a Assíria como um presente ao rei Jarebe; Efraim ficará confuso, e Israel se envergonhará por causa do seu próprio conselho." },
  { id: "HOS 10:7", bookId: "HOS", book: "Oséias", chapter: 10, verse: 7, text: "O rei de Samaria será desfeito como a espuma sobre a face da água." },
  { id: "HOS 10:8", bookId: "HOS", book: "Oséias", chapter: 10, verse: 8, text: "E os altos de Áven, pecado de Israel, serão destruídos; espinhos e cardos crescerão sobre os seus altares; e dirão aos montes: Cobri-nos! E aos outeiros: Caí sobre nós!" },
  { id: "HOS 10:9", bookId: "HOS", book: "Oséias", chapter: 10, verse: 9, text: "Desde os dias de Gibeá pecaste, ó Israel; ali permaneceram; a peleja em Gibeá, contra os filhos da perversidade, não os alcançará." },
  { id: "HOS 10:10", bookId: "HOS", book: "Oséias", chapter: 10, verse: 10, text: "Eu os castigarei na medida do meu desejo; e congregar-se-ão contra eles os povos, quando eu os atar pela sua dupla transgressão." },
  { id: "HOS 10:11", bookId: "HOS", book: "Oséias", chapter: 10, verse: 11, text: "Porque Efraim é uma bezerra domada, que gosta de trilhar; e eu poupava a formosura do seu pescoço; mas farei cavalgar Efraim. Judá lavrará, Jacó lhe desfará os torrões." },
  { id: "HOS 10:12", bookId: "HOS", book: "Oséias", chapter: 10, verse: 12, text: "Semeai para vós em justiça, ceifai segundo a misericórdia; lavrai o campo de lavoura; porque é tempo de buscar ao Senhor, até que venha e chova a justiça sobre vós." },
  { id: "HOS 10:13", bookId: "HOS", book: "Oséias", chapter: 10, verse: 13, text: "Lavrastes a impiedade, segastes a iniqüidade, e comestes o fruto da mentira; porque confiaste no teu caminho, na multidão dos teus poderosos." },
  { id: "HOS 10:14", bookId: "HOS", book: "Oséias", chapter: 10, verse: 14, text: "Portanto, entre o teu povo se levantará um grande tumulto, e todas as tuas fortalezas serão destruídas, como Salmã destruiu a Bete-Arbel no dia da guerra; a mãe ali foi despedaçada com os filhos." },
  { id: "HOS 10:15", bookId: "HOS", book: "Oséias", chapter: 10, verse: 15, text: "Assim vos fará Betel por causa da vossa grande malícia; de madrugada o rei de Israel será totalmente destruído." },
  { id: "HOS 11:1", bookId: "HOS", book: "Oséias", chapter: 11, verse: 1, text: "Quando Israel era menino, eu o amei; e do Egito chamei a meu filho." },
  { id: "HOS 11:2", bookId: "HOS", book: "Oséias", chapter: 11, verse: 2, text: "Mas, como os chamavam, assim se iam da sua face; sacrificavam a baalins, e queimavam incenso às imagens de escultura." },
  { id: "HOS 11:3", bookId: "HOS", book: "Oséias", chapter: 11, verse: 3, text: "Todavia, eu ensinei a andar a Efraim; tomando-os pelos seus braços, mas não entenderam que eu os curava." },
  { id: "HOS 11:4", bookId: "HOS", book: "Oséias", chapter: 11, verse: 4, text: "Atraí-os com cordas humanas, com laços de amor, e fui para eles como os que tiram o jugo de sobre as suas queixadas, e lhes dei mantimento." },
  { id: "HOS 11:5", bookId: "HOS", book: "Oséias", chapter: 11, verse: 5, text: "Não voltará para a terra do Egito, mas a Assíria será seu rei; porque recusam converter-se." },
  { id: "HOS 11:6", bookId: "HOS", book: "Oséias", chapter: 11, verse: 6, text: "E cairá a espada sobre as suas cidades, e consumirá os seus ramos, e os devorará, por causa dos seus próprios conselhos." },
  { id: "HOS 11:7", bookId: "HOS", book: "Oséias", chapter: 11, verse: 7, text: "Porque o meu povo é inclinado a desviar-se de mim; ainda que chamam ao Altíssimo, nenhum deles o exalta." },
  { id: "HOS 11:8", bookId: "HOS", book: "Oséias", chapter: 11, verse: 8, text: "Como te deixaria, ó Efraim? Como te entregaria, ó Israel? Como te faria como Admá? Te poria como Zeboim? Está comovido em mim o meu coração, as minhas compaixões à uma se acendem." },
  { id: "HOS 11:9", bookId: "HOS", book: "Oséias", chapter: 11, verse: 9, text: "Não executarei o furor da minha ira; não voltarei para destruir a Efraim, porque eu sou Deus e não homem, o Santo no meio de ti; eu não entrarei na cidade." },
  { id: "HOS 11:10", bookId: "HOS", book: "Oséias", chapter: 11, verse: 10, text: "Andarão após o Senhor; ele rugirá como leão; rugindo, pois, ele, os filhos do ocidente tremerão." },
  { id: "HOS 11:11", bookId: "HOS", book: "Oséias", chapter: 11, verse: 11, text: "Tremendo virão como um passarinho, os do Egito, e como uma pomba os da terra da Assíria, e os farei habitar em suas casas, diz o Senhor." },
  { id: "HOS 11:12", bookId: "HOS", book: "Oséias", chapter: 11, verse: 12, text: "Efraim me cercou com mentira, e a casa de Israel com engano; mas Judá ainda domina com Deus, e com os santos está fiel." },
  { id: "HOS 12:1", bookId: "HOS", book: "Oséias", chapter: 12, verse: 1, text: "Efraim se apascenta de vento, e segue o vento leste; todo o dia multiplica a mentira e a destruição; e fazem aliança com a Assíria, e o azeite se leva ao Egito." },
  { id: "HOS 12:2", bookId: "HOS", book: "Oséias", chapter: 12, verse: 2, text: "O Senhor também com Judá tem contenda, e castigará Jacó segundo os seus caminhos; segundo as suas obras o recompensará." },
  { id: "HOS 12:3", bookId: "HOS", book: "Oséias", chapter: 12, verse: 3, text: "No ventre pegou do calcanhar de seu irmão, e na sua força lutou com Deus." },
  { id: "HOS 12:4", bookId: "HOS", book: "Oséias", chapter: 12, verse: 4, text: "Lutou com o anjo, e prevaleceu; chorou, e lhe suplicou; em Betel o achou, e ali falou conosco," },
  { id: "HOS 12:5", bookId: "HOS", book: "Oséias", chapter: 12, verse: 5, text: "Sim, o Senhor, o Deus dos Exércitos; o Senhor é o seu memorial." },
  { id: "HOS 12:6", bookId: "HOS", book: "Oséias", chapter: 12, verse: 6, text: "Tu, pois, converte-te a teu Deus; guarda a benevolência e o juízo, e em teu Deus espera sempre." },
  { id: "HOS 12:7", bookId: "HOS", book: "Oséias", chapter: 12, verse: 7, text: "É um mercador; tem nas mãos uma balança enganosa; ama a opressão." },
  { id: "HOS 12:8", bookId: "HOS", book: "Oséias", chapter: 12, verse: 8, text: "E diz Efraim: Contudo me tenho enriquecido, e tenho adquirido para mim grandes bens; em todo o meu trabalho não acharão em mim iniqüidade alguma que seja pecado." },
  { id: "HOS 12:9", bookId: "HOS", book: "Oséias", chapter: 12, verse: 9, text: "Mas eu sou o Senhor teu Deus desde a terra do Egito; eu ainda te farei habitar em tendas, como nos dias da festa solene." },
  { id: "HOS 12:10", bookId: "HOS", book: "Oséias", chapter: 12, verse: 10, text: "Falei aos profetas, e multipliquei a visão; e pelo ministério dos profetas propus símiles." },
  { id: "HOS 12:11", bookId: "HOS", book: "Oséias", chapter: 12, verse: 11, text: "Não é Gileade iniqüidade? Pura vaidade são eles; em Gilgal sacrificam bois; os seus altares são como montões de pedras nos sulcos dos campos." },
  { id: "HOS 12:12", bookId: "HOS", book: "Oséias", chapter: 12, verse: 12, text: "Jacó fugiu para o campo da Síria, e Israel serviu por uma mulher, e por uma mulher guardou o gado." },
  { id: "HOS 12:13", bookId: "HOS", book: "Oséias", chapter: 12, verse: 13, text: "Mas o Senhor por meio de um profeta fez subir a Israel do Egito, e por um profeta foi ele guardado." },
  { id: "HOS 12:14", bookId: "HOS", book: "Oséias", chapter: 12, verse: 14, text: "Efraim mui amargosamente provocou a sua ira; portanto deixará ficar sobre ele o seu sangue, e o seu Senhor o recompensará pelo seu opróbrio." },
  { id: "HOS 13:1", bookId: "HOS", book: "Oséias", chapter: 13, verse: 1, text: "Quando Efraim falava, tremia-se; foi exaltado em Israel; mas ele se fez culpado em Baal, e morreu." },
  { id: "HOS 13:2", bookId: "HOS", book: "Oséias", chapter: 13, verse: 2, text: "E agora multiplicaram pecados, e da sua prata fizeram uma imagem de fundição, ídolos segundo o seu entendimento, todos obra de artífices, dos quais dizem: Os homens que sacrificam beijem os bezerros." },
  { id: "HOS 13:3", bookId: "HOS", book: "Oséias", chapter: 13, verse: 3, text: "Por isso serão como a nuvem da manhã, e como o orvalho da madrugada, que cedo passa; como folhelho que a tempestade lança da eira, e como a fumaça da chaminé." },
  { id: "HOS 13:4", bookId: "HOS", book: "Oséias", chapter: 13, verse: 4, text: "Todavia, eu sou o Senhor teu Deus desde a terra do Egito; portanto não reconhecerás outro deus além de mim, porque não há Salvador senão eu." },
  { id: "HOS 13:5", bookId: "HOS", book: "Oséias", chapter: 13, verse: 5, text: "Eu te conheci no deserto, na terra muito seca." },
  { id: "HOS 13:6", bookId: "HOS", book: "Oséias", chapter: 13, verse: 6, text: "Depois eles se fartaram em proporção do seu pasto; estando fartos, ensoberbeceu-se o seu coração, por isso se esqueceram de mim." },
  { id: "HOS 13:7", bookId: "HOS", book: "Oséias", chapter: 13, verse: 7, text: "Serei, pois, para eles como leão; como leopardo espiarei no caminho." },
  { id: "HOS 13:8", bookId: "HOS", book: "Oséias", chapter: 13, verse: 8, text: "Como ursa roubada dos seus filhos, os encontrarei, e lhes romperei as teias do seu coração, e como leão ali os devorarei; as feras do campo os despedaçarão." },
  { id: "HOS 13:9", bookId: "HOS", book: "Oséias", chapter: 13, verse: 9, text: "Para a tua perda, ó Israel, te rebelaste contra mim, a saber, contra o teu ajudador." },
  { id: "HOS 13:10", bookId: "HOS", book: "Oséias", chapter: 13, verse: 10, text: "Onde está agora o teu rei, para que te guarde em todas as tuas cidades, e os teus juízes, dos quais disseste: Dá-me rei e príncipes?" },
  { id: "HOS 13:11", bookId: "HOS", book: "Oséias", chapter: 13, verse: 11, text: "Dei-te um rei na minha ira, e tirei-o no meu furor." },
  { id: "HOS 13:12", bookId: "HOS", book: "Oséias", chapter: 13, verse: 12, text: "A iniqüidade de Efraim está atada, o seu pecado está armazenado." },
  { id: "HOS 13:13", bookId: "HOS", book: "Oséias", chapter: 13, verse: 13, text: "Dores de mulher de parto lhe sobrevirão; ele é um filho insensato; porque é tempo e não está no lugar em que deve vir à luz." },
  { id: "HOS 13:14", bookId: "HOS", book: "Oséias", chapter: 13, verse: 14, text: "Eu os remirei da mão do inferno, e os resgatarei da morte. Onde estão, ó morte, as tuas pragas? Onde está, ó inferno, a tua perdição? O arrependimento está escondido de meus olhos." },
  { id: "HOS 13:15", bookId: "HOS", book: "Oséias", chapter: 13, verse: 15, text: "Ainda que ele dê fruto entre os irmãos, virá o vento leste, vento do Senhor, subindo do deserto, e secar-se-á a sua nascente, e secar-se-á a sua fonte; ele saqueará o tesouro de todos os vasos desejáveis." },
  { id: "HOS 13:16", bookId: "HOS", book: "Oséias", chapter: 13, verse: 16, text: "Samaria virá a ser deserta, porque se rebelou contra o seu Deus; cairão à espada, seus filhos serão despedaçados, e as suas grávidas serão fendidas pelo meio." },
  { id: "HOS 14:1", bookId: "HOS", book: "Oséias", chapter: 14, verse: 1, text: "Converte-te, ó Israel, ao SENHOR teu Deus; porque pelos teus pecados tens caído." },
  { id: "HOS 14:2", bookId: "HOS", book: "Oséias", chapter: 14, verse: 2, text: "Tomai convosco palavras, e convertei-vos ao Senhor; dizei-lhe: Tira toda a iniqüidade, e aceita o que é bom; e ofereceremos como novilhos os sacrifícios dos nossos lábios." },
  { id: "HOS 14:3", bookId: "HOS", book: "Oséias", chapter: 14, verse: 3, text: "Não nos salvará a Assíria, não iremos montados em cavalos, e à obra das nossas mãos já não diremos mais: Tu és o nosso deus; porque por ti o órfão alcança misericórdia." },
  { id: "HOS 14:4", bookId: "HOS", book: "Oséias", chapter: 14, verse: 4, text: "Eu sararei a sua infidelidade, eu voluntariamente os amarei; porque a minha ira se apartou deles." },
  { id: "HOS 14:5", bookId: "HOS", book: "Oséias", chapter: 14, verse: 5, text: "Eu serei para Israel como o orvalho. Ele florescerá como o lírio e lançará as suas raízes como o Líbano." },
  { id: "HOS 14:6", bookId: "HOS", book: "Oséias", chapter: 14, verse: 6, text: "Estender-se-ão os seus galhos, e a sua glória será como a da oliveira, e sua fragrância como a do Líbano." },
  { id: "HOS 14:7", bookId: "HOS", book: "Oséias", chapter: 14, verse: 7, text: "Voltarão os que habitam debaixo da sua sombra; serão vivificados como o trigo, e florescerão como a vide; a sua memória será como o vinho do Líbano." },
  { id: "HOS 14:8", bookId: "HOS", book: "Oséias", chapter: 14, verse: 8, text: "Efraim dirá: Que mais tenho eu com os ídolos? Eu o tenho ouvido, e cuidarei dele; eu sou como a faia verde; de mim é achado o teu fruto." },
  { id: "HOS 14:9", bookId: "HOS", book: "Oséias", chapter: 14, verse: 9, text: "Quem é sábio, para que entenda estas coisas? Quem é prudente, para que as saiba? Porque os caminhos do Senhor são retos, e os justos andarão neles, mas os transgressores neles cairão." },
  // MIQUÉIAS
  { id: "MIC 1:1", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 1, text: "Palavra do SENHOR, que veio a Miquéias, morastita, nos dias de Jotão, Acaz e Ezequias, reis de Judá, a qual ele viu sobre Samaria e Jerusalém." },
  { id: "MIC 1:2", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 2, text: "Ouvi, todos os povos, presta atenção, ó terra, e tudo o que nela há; e seja o Senhor DEUS testemunha contra vós, o Senhor, desde o seu santo templo." },
  { id: "MIC 1:3", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 3, text: "Porque eis que o Senhor está para sair do seu lugar, e descerá, e andará sobre as alturas da terra." },
  { id: "MIC 1:4", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 4, text: "E os montes debaixo dele se derreterão, e os vales se fenderão, como a cera diante do fogo, como as águas que se precipitam num abismo." },
  { id: "MIC 1:5", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 5, text: "Tudo isto por causa da transgressão de Jacó, e dos pecados da casa de Israel. Qual é a transgressão de Jacó? Não é Samaria? E quais os altos de Judá? Não é Jerusalém?" },
  { id: "MIC 1:6", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 6, text: "Por isso farei de Samaria um montão de pedras do campo, uma terra de plantar vinhas, e farei rolar as suas pedras no vale, e descobrirei os seus fundamentos." },
  { id: "MIC 1:7", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 7, text: "E todas as suas imagens de escultura serão despedaçadas, e todas as suas ofertas serão queimadas pelo fogo, e de todos os seus ídolos eu farei uma assolação; porque pela paga de prostituta os ajuntou, e para a paga de prostituta voltarão." },
  { id: "MIC 1:8", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 8, text: "Por isso lamentarei, e gemerei, andarei despojado e nu; farei lamentação como de chacais, e pranto como de avestruzes." },
  { id: "MIC 1:9", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 9, text: "Porque a sua chaga é incurável, porque chegou até Judá; estendeu-se até à porta do meu povo, até Jerusalém." },
  { id: "MIC 1:10", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 10, text: "Não o anuncieis em Gate, nem choreis muito; revolve-te no pó, na casa de Afra." },
  { id: "MIC 1:11", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 11, text: "Passa, ó moradora de Safir, em vergonhosa nudez; a moradora de Zaanã não saiu; o pranto de Bete-Ezel tirará de vós a sua posição." },
  { id: "MIC 1:12", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 12, text: "Porque a moradora de Marote sofre pelo bem; porque desceu do Senhor o mal até à porta de Jerusalém." },
  { id: "MIC 1:13", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 13, text: "Ata os animais ligeiros ao carro, ó moradora de Laquis; esta foi o princípio do pecado para a filha de Sião, porque em ti se acharam as transgressões de Israel." },
  { id: "MIC 1:14", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 14, text: "Por isso darás presentes a Moresete-Gate; as casas de Aczibe se tornarão em engano para os reis de Israel." },
  { id: "MIC 1:15", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 15, text: "Ainda trarei a ti, ó moradora de Maressa, aquele que te possuirá; chegará até Adulão a glória de Israel." },
  { id: "MIC 1:16", bookId: "MIC", book: "Miquéias", chapter: 1, verse: 16, text: "Faze-te calva, e tosquia-te, por causa dos filhos das tuas delícias; alarga a tua calva como a águia, porque de ti foram levados cativos." },
  { id: "MIC 2:1", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 1, text: "Ai daqueles que nas suas camas intentam a iniqüidade, e maquinam o mal; à luz da alva o praticam, porque está no poder da sua mão!" },
  { id: "MIC 2:2", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 2, text: "E cobiçam campos, e roubam-nos, cobiçam casas, e arrebatam-nas; assim fazem violência a um homem e à sua casa, a uma pessoa e à sua herança." },
  { id: "MIC 2:3", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 3, text: "Portanto, assim diz o Senhor: Eis que projeto um mal contra esta família, do qual não tirareis os vossos pescoços, e não andareis tão altivos, porque o tempo será mau." },
  { id: "MIC 2:4", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 4, text: "Naquele dia se levantará sobre vós um provérbio, e se lamentará pranto lastimoso, dizendo: Nós estamos inteiramente desolados; a porção do meu povo ele a troca; como me despoja! Tira os nossos campos e os reparte!" },
  { id: "MIC 2:5", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 5, text: "Portanto, não terás tu na congregação do Senhor quem lance o cordel pela sorte." },
  { id: "MIC 2:6", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 6, text: "Não profetizeis aos que profetizam; eles não profetizarão para eles, pois não se apartará a sua vergonha." },
  { id: "MIC 2:7", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 7, text: "Ó vós que sois chamados casa de Jacó, porventura encurtou-se o Espírito do Senhor? São estas as suas obras? E não é assim que fazem bem as minhas palavras ao que anda retamente?" },
  { id: "MIC 2:8", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 8, text: "Mas ontem, se levantou o meu povo como inimigo; de sobre a vestidura tirastes a capa daqueles que passavam seguros, como homens que voltavam da guerra." },
  { id: "MIC 2:9", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 9, text: "Lançastes fora as mulheres do meu povo, da casa das suas delícias; das suas crianças tirastes para sempre a minha glória." },
  { id: "MIC 2:10", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 10, text: "Levantai-vos, e ide-vos, porque este não é lugar de descanso; por causa da imundícia que traz destruição, sim, destruição enorme." },
  { id: "MIC 2:11", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 11, text: "Se houver alguém que, andando com espírito de falsidade, mentir, dizendo: Eu te profetizarei sobre o vinho e a bebida forte; será esse tal o profeta deste povo." },
  { id: "MIC 2:12", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 12, text: "Certamente te ajuntarei todo, ó Jacó; certamente congregarei o restante de Israel; pô-los-ei todos juntos, como ovelhas de Bozra; como o rebanho no meio do seu pasto, farão estrondo por causa da multidão dos homens." },
  { id: "MIC 2:13", bookId: "MIC", book: "Miquéias", chapter: 2, verse: 13, text: "Subirá diante deles o que abrirá o caminho; eles romperão, e entrarão pela porta, e sairão por ela; e o rei irá adiante deles, e o Senhor à testa deles." },
  { id: "MIC 3:1", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 1, text: "E disse eu: Ouvi, peço-vos, ó chefes de Jacó, e vós, príncipes da casa de Israel; não é a vós que pertence saber o juízo?" },
  { id: "MIC 3:2", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 2, text: "A vós que odiais o bem, e amais o mal, que arrancais a pele de cima deles, e a carne de cima dos seus ossos;" },
  { id: "MIC 3:3", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 3, text: "E que comeis a carne do meu povo, e lhes arrancais a pele, e lhes esmiuçais os ossos, e os repartis como para a panela e como carne dentro do caldeirão." },
  { id: "MIC 3:4", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 4, text: "Então clamarão ao Senhor, mas não os ouvirá; antes esconderá deles a sua face naquele tempo, visto que eles fizeram mal nas suas obras." },
  { id: "MIC 3:5", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 5, text: "Assim diz o Senhor acerca dos profetas que fazem errar o meu povo, que mordem com os seus dentes, e clamam paz; mas contra aquele que nada lhes dá na boca preparam guerra." },
  { id: "MIC 3:6", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 6, text: "Portanto, se vos fará noite sem visão, e tereis trevas sem adivinhação, e haverá o sol sobre os profetas, e o dia sobre eles se enegrecerá." },
  { id: "MIC 3:7", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 7, text: "E os videntes se envergonharão, e os adivinhadores se confundirão; sim, todos eles cobrirão os seus lábios, porque não haverá resposta de Deus." },
  { id: "MIC 3:8", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 8, text: "Mas eu estou cheio do poder do Espírito do Senhor, e de juízo e de força, para anunciar a Jacó a sua transgressão e a Israel o seu pecado." },
  { id: "MIC 3:9", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 9, text: "Ouvi agora isto, vós, chefes da casa de Jacó, e príncipes da casa de Israel, que abominais o juízo e perverteis tudo o que é direito," },
  { id: "MIC 3:10", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 10, text: "Edificando a Sião com sangue, e a Jerusalém com iniqüidade." },
  { id: "MIC 3:11", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 11, text: "Os seus chefes dão as sentenças por suborno, e os seus sacerdotes ensinam por interesse, e os seus profetas adivinham por dinheiro; e ainda se encostam ao Senhor, dizendo: Não está o Senhor no meio de nós? Nenhum mal nos sobrevirá." },
  { id: "MIC 3:12", bookId: "MIC", book: "Miquéias", chapter: 3, verse: 12, text: "Portanto, por causa de vós, Sião será lavrada como um campo, e Jerusalém se tornará em montões de pedras, e o monte desta casa como os altos de um bosque." },
  { id: "MIC 4:1", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 1, text: "Mas nos últimos dias acontecerá que o monte da casa do SENHOR será estabelecido no cume dos montes, e se elevará sobre os outeiros, e a ele afluirão os povos." },
  { id: "MIC 4:2", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 2, text: "E irão muitas nações, e dirão: Vinde, e subamos ao monte do Senhor, e à casa do Deus de Jacó, para que nos ensine os seus caminhos, e andemos pelas suas veredas; porque de Sião sairá a lei, e de Jerusalém a palavra do Senhor." },
  { id: "MIC 4:3", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 3, text: "E julgará entre muitos povos, e castigará nações poderosas e longínquas, e converterão as suas espadas em pás, e as suas lanças em foices; uma nação não levantará a espada contra outra nação, nem aprenderão mais a guerra." },
  { id: "MIC 4:4", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 4, text: "Mas assentar-se-á cada um debaixo da sua videira, e debaixo da sua figueira, e não haverá quem os espante, porque a boca do Senhor dos Exércitos o disse." },
  { id: "MIC 4:5", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 5, text: "Porque todos os povos andam, cada um em nome do seu deus; mas nós andaremos em nome do Senhor nosso Deus, para todo o sempre." },
  { id: "MIC 4:6", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 6, text: "Naquele dia, diz o Senhor, congregarei a que coxeava, e recolherei a que tinha sido expulsa, e a que eu tinha maltratado." },
  { id: "MIC 4:7", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 7, text: "E da que coxeava farei um remanescente, e da que tinha sido arrojada para longe, uma nação poderosa; e o Senhor reinará sobre eles no monte Sião, desde agora e para sempre." },
  { id: "MIC 4:8", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 8, text: "E a ti, ó torre do rebanho, fortaleza da filha de Sião, a ti virá; sim, a ti virá o primeiro domínio, o reino da filha de Jerusalém." },
  { id: "MIC 4:9", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 9, text: "E agora, por que fazes tão grande pranto? Não há em ti rei? Pereceu o teu conselheiro? Apoderou-se de ti a dor, como da que está de parto?" },
  { id: "MIC 4:10", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 10, text: "Sofre dores, e trabalha, para dar à luz, ó filha de Sião, como a que está de parto, porque agora sairás da cidade, e morarás no campo, e virás até babilônia; ali, porém, serás livrada; ali te remirá o SENHOR da mão de teus inimigos." },
  { id: "MIC 4:11", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 11, text: "Agora se congregaram muitas nações contra ti, que dizem: Seja profanada, e vejam os nossos olhos o seu desejo sobre Sião." },
  { id: "MIC 4:12", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 12, text: "Mas não sabem os pensamentos do Senhor, nem entendem o seu conselho; porque as ajuntou como gavelas numa eira." },
  { id: "MIC 4:13", bookId: "MIC", book: "Miquéias", chapter: 4, verse: 13, text: "Levanta-te e trilha, ó filha de Sião; porque eu farei de ferro o teu chifre, e de bronze as tuas unhas; e esmiuçarás a muitos povos, e o seu ganho será consagrado ao Senhor, e os seus bens ao Senhor de toda a terra." },
  { id: "MIC 5:1", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 1, text: "Agora ajunta-te em tropas, ó filha de tropas; pôr-se-á cerco contra nós; ferirão com a vara na face ao juiz de Israel." },
  { id: "MIC 5:2", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 2, text: "E tu, Belém Efrata, posto que pequena entre os milhares de Judá, de ti me sairá o que governará em Israel, e cujas saídas são desde os tempos antigos, desde os dias da eternidade." },
  { id: "MIC 5:3", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 3, text: "Portanto os entregará até ao tempo em que a que está de parto tiver dado à luz; então o restante de seus irmãos voltará aos filhos de Israel." },
  { id: "MIC 5:4", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 4, text: "E ele permanecerá, e apascentará ao povo na força do Senhor, na excelência do nome do Senhor seu Deus; e eles permanecerão, porque agora será engrandecido até aos fins da terra." },
  { id: "MIC 5:5", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 5, text: "E este será a nossa paz; quando a Assíria vier à nossa terra, e quando pisar em nossos palácios, levantaremos contra ela sete pastores e oito príncipes dentre os homens." },
  { id: "MIC 5:6", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 6, text: "Esses consumirão a terra da Assíria à espada, e a terra de Ninrode nas suas entradas. Assim nos livrará da Assíria, quando vier à nossa terra, e quando calcar os nossos termos." },
  { id: "MIC 5:7", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 7, text: "E o remanescente de Jacó estará no meio de muitos povos, como orvalho da parte do Senhor, como chuvisco sobre a erva, que não espera pelo homem, nem aguarda a filhos de homens." },
  { id: "MIC 5:8", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 8, text: "E o restante de Jacó estará entre os gentios, no meio de muitos povos, como um leão entre os animais do bosque, como um leãozinho entre os rebanhos de ovelhas, o qual, quando passar, pisará e despedaçará, sem que haja quem as livre." },
  { id: "MIC 5:9", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 9, text: "A tua mão se exaltará sobre os teus adversários; e todos os teus inimigos serão exterminados." },
  { id: "MIC 5:10", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 10, text: "E sucederá naquele dia, diz o Senhor, que eu exterminarei do meio de ti os teus cavalos, e destruirei os teus carros." },
  { id: "MIC 5:11", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 11, text: "E destruirei as cidades da tua terra, e derrubarei todas as tuas fortalezas;" },
  { id: "MIC 5:12", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 12, text: "E exterminarei as feitiçarias da tua mão; e não terás adivinhadores;" },
  { id: "MIC 5:13", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 13, text: "E destruirei do meio de ti as tuas imagens de escultura e as tuas estátuas; e tu não te inclinarás mais diante da obra das tuas mãos." },
  { id: "MIC 5:14", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 14, text: "E arrancarei os teus bosques do meio de ti; e destruirei as tuas cidades." },
  { id: "MIC 5:15", bookId: "MIC", book: "Miquéias", chapter: 5, verse: 15, text: "E com ira e com furor farei vingança sobre os gentios que não ouvem." },
  { id: "MIC 6:1", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 1, text: "Ouvi agora o que diz o SENHOR: Levanta-te, contende com os montes, e ouçam os outeiros a tua voz." },
  { id: "MIC 6:2", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 2, text: "Ouvi, montes, a demanda do Senhor, e vós, fortes fundamentos da terra; porque o Senhor tem uma demanda com o seu povo, e com Israel entrará em juízo." },
  { id: "MIC 6:3", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 3, text: "Ó povo meu; que te tenho feito? E com que te enfadei? Testifica contra mim." },
  { id: "MIC 6:4", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 4, text: "Pois te fiz subir da terra do Egito, e da casa da servidão te remi; e enviei adiante de ti a Moisés, Arão e Miriã." },
  { id: "MIC 6:5", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 5, text: "Povo meu, lembra-te agora do que consultou Balaque, rei de Moabe, e o que lhe respondeu Balaão, filho de Beor, e do que aconteceu desde Sitim até Gilgal, para que conheças as justiças do Senhor." },
  { id: "MIC 6:6", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 6, text: "Com que me apresentarei ao Senhor, e me inclinarei diante do Deus altíssimo? Apresentar-me-ei diante dele com holocaustos, com bezerros de um ano?" },
  { id: "MIC 6:7", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 7, text: "Agradar-se-á o Senhor de milhares de carneiros, ou de dez mil ribeiros de azeite? Darei o meu primogênito pela minha transgressão, o fruto do meu ventre pelo pecado da minha alma?" },
  { id: "MIC 6:8", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 8, text: "Ele te declarou, ó homem, o que é bom; e que é o que o Senhor pede de ti, senão que pratiques a justiça, e ames a benignidade, e andes humildemente com o teu Deus?" },
  { id: "MIC 6:9", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 9, text: "A voz do Senhor clama à cidade e o que é sábio verá o teu nome. Ouvi a vara, e quem a ordenou." },
  { id: "MIC 6:10", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 10, text: "Ainda há na casa do ímpio tesouros da impiedade, e medida escassa, que é detestável?" },
  { id: "MIC 6:11", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 11, text: "Seria eu limpo com balanças falsas, e com uma bolsa de pesos enganosos?" },
  { id: "MIC 6:12", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 12, text: "Porque os seus ricos estão cheios de violência, e os seus habitantes falam mentiras e a sua língua é enganosa na sua boca." },
  { id: "MIC 6:13", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 13, text: "Assim eu também te enfraquecerei, ferindo-te e assolando-te por causa dos teus pecados." },
  { id: "MIC 6:14", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 14, text: "Tu comerás, mas não te fartarás, e a tua humilhação estará no meio de ti; removerás os teus bens mas não livrarás; e aquilo que livrares, eu o entregarei à espada." },
  { id: "MIC 6:15", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 15, text: "Tu semearás, mas não segarás; pisarás a azeitona, mas não te ungirás com azeite; e pisarás o mosto, mas não beberás vinho." },
  { id: "MIC 6:16", bookId: "MIC", book: "Miquéias", chapter: 6, verse: 16, text: "Porque se observam os estatutos de Onri, e toda a obra da casa de Acabe, e andais nos conselhos deles; para que eu te faça uma desolação, e dos seus habitantes um assobio; assim trareis sobre vós o opróbrio do meu povo." },
  { id: "MIC 7:1", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 1, text: "Ai de mim! porque estou feito como as colheitas de frutas do verão, como os rabiscos da vindima; não há cacho de uvas para comer, nem figos temporãos que a minha alma deseja." },
  { id: "MIC 7:2", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 2, text: "Já pereceu da terra o homem piedoso, e não há entre os homens um que seja justo; todos armam ciladas para sangue; cada um caça a seu irmão com a rede," },
  { id: "MIC 7:3", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 3, text: "As suas mãos fazem diligentemente o mal; assim demanda o príncipe, e o juiz julga pela recompensa, e o grande fala da corrupção da sua alma, e assim todos eles tecem o mal." },
  { id: "MIC 7:4", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 4, text: "O melhor deles é como um espinho; o mais reto é pior do que a sebe de espinhos; veio o dia dos teus vigias, veio o dia da tua punição; agora será a sua confusão." },
  { id: "MIC 7:5", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 5, text: "Não creiais no amigo, nem confieis no vosso guia; daquela que repousa no teu seio, guarda as portas da tua boca." },
  { id: "MIC 7:6", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 6, text: "Porque o filho despreza ao pai, a filha se levanta contra sua mãe, a nora contra sua sogra, os inimigos do homem são os da sua própria casa." },
  { id: "MIC 7:7", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 7, text: "Eu, porém, olharei para o Senhor; esperarei no Deus da minha salvação; o meu Deus me ouvirá." },
  { id: "MIC 7:8", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 8, text: "Ó inimiga minha, não te alegres a meu respeito; ainda que eu tenha caído, levantar-me-ei; se morar nas trevas, o Senhor será a minha luz." },
  { id: "MIC 7:9", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 9, text: "Sofrerei a ira do Senhor, porque pequei contra ele, até que julgue a minha causa, e execute o meu direito; ele me tirará para a luz, e eu verei a sua justiça." },
  { id: "MIC 7:10", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 10, text: "E a minha inimiga verá isso, e cobri-la-á a vergonha, que me diz: Onde está o Senhor teu Deus? Os meus olhos a contemplarão; agora será ela pisada como a lama das ruas." },
  { id: "MIC 7:11", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 11, text: "No dia em que reedificar os teus muros, nesse dia estará longe e dilatado o estatuto." },
  { id: "MIC 7:12", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 12, text: "Naquele dia virá a ti, desde a Assíria e das cidades fortificadas, e das cidades fortificadas até ao rio, e do mar até ao mar, e da montanha até à montanha." },
  { id: "MIC 7:13", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 13, text: "Mas esta terra será posta em desolação, por causa dos seus moradores, por causa do fruto das suas obras." },
  { id: "MIC 7:14", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 14, text: "Apascenta o teu povo com a tua vara, o rebanho da tua herança, que habita a sós, no bosque, no meio do Carmelo; apascentem-se em Basã e Gileade, como nos dias do passado." },
  { id: "MIC 7:15", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 15, text: "Eu lhes mostrarei maravilhas, como nos dias da tua saída da terra do Egito." },
  { id: "MIC 7:16", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 16, text: "As nações o verão, e envergonhar-se-ão, por causa de todo o seu poder; porão a mão sobre a boca, e os seus ouvidos ficarão surdos." },
  { id: "MIC 7:17", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 17, text: "Lamberão o pó como serpente, como vermes da terra, tremendo, sairão dos seus esconderijos; com pavor virão ao Senhor nosso Deus, e terão medo de ti." },
  { id: "MIC 7:18", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 18, text: "Quem é Deus semelhante a ti, que perdoa a iniqüidade, e que passa por cima da rebelião do restante da sua herança? Ele não retém a sua ira para sempre, porque tem prazer na sua benignidade." },
  { id: "MIC 7:19", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 19, text: "Tornará a apiedar-se de nós; sujeitará as nossas iniqüidades, e tu lançarás todos os seus pecados nas profundezas do mar." },
  { id: "MIC 7:20", bookId: "MIC", book: "Miquéias", chapter: 7, verse: 20, text: "Darás a Jacó a fidelidade, e a Abraão a benignidade, que juraste a nossos pais desde os dias antigos." },
  // ZACARIAS
  { id: "ZEC 1:1", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 1, text: "No oitavo mês do segundo ano de Dario veio a palavra do SENHOR ao profeta Zacarias, filho de Baraquias, filho de Ido, dizendo:" },
  { id: "ZEC 1:2", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 2, text: "O Senhor se irou fortemente contra vossos pais." },
  { id: "ZEC 1:3", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 3, text: "Portanto dize-lhes: Assim diz o Senhor dos Exércitos: Tornai-vos para mim, diz o Senhor dos Exércitos, e eu me tornarei para vós, diz o Senhor dos Exércitos." },
  { id: "ZEC 1:4", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 4, text: "E não sejais como vossos pais, aos quais clamavam os primeiros profetas, dizendo: Assim diz o Senhor dos Exércitos: Convertei-vos agora dos vossos maus caminhos e das vossas más obras; mas não ouviram, nem me escutaram, diz o Senhor." },
  { id: "ZEC 1:5", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 5, text: "Vossos pais, onde estão? E os profetas, viverão eles para sempre?" },
  { id: "ZEC 1:6", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 6, text: "Contudo as minhas palavras e os meus estatutos, que eu ordenei aos profetas, meus servos, não alcançaram a vossos pais? E eles voltaram, e disseram: Assim como o Senhor dos Exércitos fez tenção de nos tratar, segundo os nossos caminhos, e segundo as nossas obras, assim ele nos tratou." },
  { id: "ZEC 1:7", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 7, text: "Aos vinte e quatro dias do mês undécimo (que é o mês de Sebate), no segundo ano de Dario, veio a palavra do Senhor ao profeta Zacarias, filho de Baraquias, filho de Ido, dizendo:" },
  { id: "ZEC 1:8", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 8, text: "Olhei de noite, e vi um homem montado num cavalo vermelho; e ele estava parado entre as murtas que estavam na baixada; e atrás dele estavam cavalos vermelhos, malhados e brancos." },
  { id: "ZEC 1:9", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 9, text: "E eu disse: Senhor meu, quem são estes? E disse-me o anjo que falava comigo: Eu te mostrarei quem são estes." },
  { id: "ZEC 1:10", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 10, text: "Então respondeu o homem que estava entre as murtas, e disse: Estes são os que o Senhor tem enviado para percorrerem a terra." },
  { id: "ZEC 1:11", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 11, text: "E eles responderam ao anjo do Senhor, que estava entre as murtas, e disseram: Nós já percorremos a terra, e eis que toda a terra está tranqüila e quieta." },
  { id: "ZEC 1:12", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 12, text: "Então o anjo do Senhor respondeu, e disse: Ó Senhor dos Exércitos, até quando não terás compaixão de Jerusalém, e das cidades de Judá, contra as quais estiveste irado estes setenta anos?" },
  { id: "ZEC 1:13", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 13, text: "E respondeu o Senhor ao anjo, que falava comigo, com palavras boas, palavras consoladoras." },
  { id: "ZEC 1:14", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 14, text: "E o anjo que falava comigo disse-me: Clama, dizendo: Assim diz o Senhor dos Exércitos: Com grande zelo estou zelando por Jerusalém e por Sião." },
  { id: "ZEC 1:15", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 15, text: "E com grande indignação estou irado contra os gentios em descanso; porque eu estava pouco indignado, mas eles agravaram o mal." },
  { id: "ZEC 1:16", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 16, text: "Portanto, assim diz o Senhor: Voltei-me para Jerusalém com misericórdia; nela será edificada a minha casa, diz o Senhor dos Exércitos, e o cordel será estendido sobre Jerusalém:" },
  { id: "ZEC 1:17", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 17, text: "Clama outra vez, dizendo: Assim diz o Senhor dos Exércitos: As minhas cidades ainda aumentarão e prosperarão; porque o Senhor ainda consolará a Sião e ainda escolherá a Jerusalém." },
  { id: "ZEC 1:18", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 18, text: "E levantei os meus olhos, e vi, e eis quatro chifres." },
  { id: "ZEC 1:19", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 19, text: "E eu disse ao anjo que falava comigo: Que são estes? E ele me disse: Estes são os chifres que dispersaram a Judá, a Israel e a Jerusalém." },
  { id: "ZEC 1:20", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 20, text: "E o Senhor me mostrou quatro carpinteiros." },
  { id: "ZEC 1:21", bookId: "ZEC", book: "Zacarias", chapter: 1, verse: 21, text: "Então eu disse: Que vêm estes fazer? E ele falou, dizendo: Estes são os chifres que dispersaram a Judá, de maneira que ninguém pôde levantar a sua cabeça; estes, pois, vieram para os amedrontarem, para derrubarem os chifres dos gentios que levantaram o seu poder contra a terra de Judá, para a espalharem." },
  { id: "ZEC 2:1", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 1, text: "Tornei a levantar os meus olhos, e vi, e eis um homem que tinha na mão um cordel de medir." },
  { id: "ZEC 2:2", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 2, text: "E eu disse: Para onde vais tu? E ele me disse: Vou medir Jerusalém, para ver qual é a sua largura e qual o seu comprimento." },
  { id: "ZEC 2:3", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 3, text: "E eis que saiu o anjo que falava comigo, e outro anjo lhe saiu ao encontro." },
  { id: "ZEC 2:4", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 4, text: "E disse-lhe: Corre, fala a este jovem, dizendo: Jerusalém será habitada como as aldeias sem muros, por causa da multidão dos homens e dos animais que haverá nela." },
  { id: "ZEC 2:5", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 5, text: "Pois eu, diz o Senhor, serei para ela um muro de fogo em redor, e para glória estarei no meio dela." },
  { id: "ZEC 2:6", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 6, text: "Ah, ah! Fugi agora da terra do norte, diz o Senhor, porque vos espalhei pelos quatro ventos do céu, diz o Senhor." },
  { id: "ZEC 2:7", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 7, text: "Ah! Sião! Escapa, tu, que habitas com a filha de babilônia." },
  { id: "ZEC 2:8", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 8, text: "Porque assim diz o Senhor dos Exércitos: Depois da glória ele me enviou às nações que vos despojaram; porque aquele que tocar em vós toca na menina do seu olho." },
  { id: "ZEC 2:9", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 9, text: "Porque eis aí levantarei a minha mão sobre eles, e eles virão a ser a presa daqueles que os serviram; assim sabereis vós que o Senhor dos Exércitos me enviou." },
  { id: "ZEC 2:10", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 10, text: "Exulta, e alegra-te ó filha de Sião, porque eis que venho, e habitarei no meio de ti, diz o Senhor." },
  { id: "ZEC 2:11", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 11, text: "E naquele dia muitas nações se ajuntarão ao Senhor, e serão o meu povo, e habitarei no meio de ti e saberás que o Senhor dos Exércitos me enviou a ti." },
  { id: "ZEC 2:12", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 12, text: "Então o Senhor herdará a Judá como sua porção na terra santa, e ainda escolherá a Jerusalém." },
  { id: "ZEC 2:13", bookId: "ZEC", book: "Zacarias", chapter: 2, verse: 13, text: "Cala-te, toda a carne, diante do Senhor, porque ele se levantou da sua santa morada." },
  { id: "ZEC 3:1", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 1, text: "E ele mostrou-me o sumo sacerdote Josué, o qual estava diante do anjo do SENHOR, e Satanás estava à sua mão direita, para se lhe opor." },
  { id: "ZEC 3:2", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 2, text: "Mas o Senhor disse a Satanás: O Senhor te repreenda, ó Satanás, sim, o Senhor, que escolheu Jerusalém, te repreenda; não é este um tição tirado do fogo?" },
  { id: "ZEC 3:3", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 3, text: "Josué, vestido de vestes sujas, estava diante do anjo." },
  { id: "ZEC 3:4", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 4, text: "Então respondeu, aos que estavam diante dele, dizendo: Tirai-lhe estas vestes sujas. E a Josué disse: Eis que tenho feito com que passe de ti a tua iniqüidade, e te vestirei de vestes finas." },
  { id: "ZEC 3:5", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 5, text: "E disse eu: Ponham-lhe uma mitra limpa sobre a sua cabeça. E puseram uma mitra limpa sobre a sua cabeça, e vestiram-no das roupas; e o anjo do Senhor estava em pé." },
  { id: "ZEC 3:6", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 6, text: "E o anjo do Senhor protestou a Josué, dizendo:" },
  { id: "ZEC 3:7", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 7, text: "Assim diz o Senhor dos Exércitos: Se andares nos meus caminhos, e se observares a minha ordenança, também tu julgarás a minha casa, e também guardarás os meus átrios, e te darei livre acesso entre os que estão aqui." },
  { id: "ZEC 3:8", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 8, text: "Ouve, pois, Josué, sumo sacerdote, tu e os teus companheiros que se assentam diante de ti, porque são homens portentosos; eis que eu farei vir o meu servo, o RENOVO." },
  { id: "ZEC 3:9", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 9, text: "Porque eis aqui a pedra que pus diante de Josué; sobre esta pedra única estão sete olhos; eis que eu esculpirei a sua escultura, diz o Senhor dos Exércitos, e tirarei a iniqüidade desta terra num só dia." },
  { id: "ZEC 3:10", bookId: "ZEC", book: "Zacarias", chapter: 3, verse: 10, text: "Naquele dia, diz o Senhor dos Exércitos, cada um de vós convidará o seu próximo para debaixo da videira e para debaixo da figueira." },
  { id: "ZEC 4:1", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 1, text: "E o anjo que falava comigo voltou, e despertou-me, como a um homem que é despertado do seu sono," },
  { id: "ZEC 4:2", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 2, text: "E disse-me: Que vês? E eu disse: Olho, e eis que vejo um castiçal todo de ouro, e um vaso de azeite no seu topo, com as suas sete lâmpadas; e sete canudos, um para cada uma das lâmpadas que estão no seu topo." },
  { id: "ZEC 4:3", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 3, text: "E, por cima dele, duas oliveiras, uma à direita do vaso de azeite, e outra à sua esquerda." },
  { id: "ZEC 4:4", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 4, text: "E respondi, dizendo ao anjo que falava comigo: Senhor meu, que é isto?" },
  { id: "ZEC 4:5", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 5, text: "Então respondeu o anjo que falava comigo, dizendo-me: Não sabes tu o que é isto? E eu disse: Não, senhor meu." },
  { id: "ZEC 4:6", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 6, text: "E respondeu-me, dizendo: Esta é a palavra do Senhor a Zorobabel, dizendo: Não por força nem por violência, mas sim pelo meu Espírito, diz o Senhor dos Exércitos." },
  { id: "ZEC 4:7", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 7, text: "Quem és tu, ó grande monte? Diante de Zorobabel tornar-te-ás uma campina; porque ele trará a pedra angular com aclamações: Graça, graça a ela." },
  { id: "ZEC 4:8", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 8, text: "E a palavra do Senhor veio novamente a mim, dizendo:" },
  { id: "ZEC 4:9", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 9, text: "As mãos de Zorobabel têm lançado os alicerces desta casa; também as suas mãos a acabarão, para que saibais que o Senhor dos Exércitos me enviou a vós." },
  { id: "ZEC 4:10", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 10, text: "Porque, quem despreza o dia das coisas pequenas? Pois esses se alegrarão, vendo o prumo na mão de Zorobabel; esses são os sete olhos do Senhor, que percorrem por toda a terra." },
  { id: "ZEC 4:11", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 11, text: "Respondi mais, dizendo-lhe: Que são as duas oliveiras à direita e à esquerda do castiçal?" },
  { id: "ZEC 4:12", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 12, text: "E, respondendo-lhe outra vez, disse: Que são aqueles dois ramos de oliveira, que estão junto aos dois tubos de ouro, e que vertem de si azeite dourado?" },
  { id: "ZEC 4:13", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 13, text: "E ele me falou, dizendo: Não sabes tu o que é isto? E eu disse: Não, senhor meu." },
  { id: "ZEC 4:14", bookId: "ZEC", book: "Zacarias", chapter: 4, verse: 14, text: "Então ele disse: Estes são os dois ungidos, que estão diante do Senhor de toda a terra." },
  { id: "ZEC 5:1", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 1, text: "E outra vez levantei os meus olhos, e vi, e eis um rolo volante." },
  { id: "ZEC 5:2", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 2, text: "E disse-me o anjo: Que vês? E eu disse: Vejo um rolo volante, que tem vinte côvados de comprido e dez côvados de largo." },
  { id: "ZEC 5:3", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 3, text: "Então disse-me: Esta é a maldição que sairá pela face de toda a terra; porque qualquer que furtar será desarraigado, conforme está estabelecido de um lado do rolo; como também qualquer que jurar falsamente, será desarraigado, conforme está estabelecido do outro lado do rolo." },
  { id: "ZEC 5:4", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 4, text: "Eu a farei sair, disse o Senhor dos Exércitos, e ela entrará na casa do ladrão, e na casa do que jurar falsamente pelo meu nome; e permanecerá no meio da sua casa, e a consumirá juntamente com a sua madeira e com as suas pedras." },
  { id: "ZEC 5:5", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 5, text: "E saiu o anjo, que falava comigo, e disse-me: Levanta agora os teus olhos, e vê que é isto que sai." },
  { id: "ZEC 5:6", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 6, text: "E eu disse: Que é isto? E ele disse: Isto é um efa que sai. Disse ainda: Este é o aspecto deles em toda a terra." },
  { id: "ZEC 5:7", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 7, text: "E eis que foi levantado um talento de chumbo, e uma mulher estava assentada no meio do efa." },
  { id: "ZEC 5:8", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 8, text: "E ele disse: Esta é a impiedade. E a lançou dentro do efa; e lançou sobre a boca deste o peso de chumbo." },
  { id: "ZEC 5:9", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 9, text: "E levantei os meus olhos, e vi, e eis que saíram duas mulheres; e traziam vento nas suas asas, pois tinham asas como as da cegonha; e levantaram o efa entre a terra e o céu." },
  { id: "ZEC 5:10", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 10, text: "Então eu disse ao anjo que falava comigo: Para onde levam elas o efa?" },
  { id: "ZEC 5:11", bookId: "ZEC", book: "Zacarias", chapter: 5, verse: 11, text: "E ele me disse: Para lhe edificarem uma casa na terra de Sinar; e, estando ela acabada, ele será posto ali na sua base." },
  { id: "ZEC 6:1", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 1, text: "E outra vez levantei os meus olhos, e vi, e eis que quatro carros saiam dentre dois montes, e estes montes eram montes de bronze." },
  { id: "ZEC 6:2", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 2, text: "No primeiro carro eram cavalos vermelhos, e no segundo carro, cavalos pretos," },
  { id: "ZEC 6:3", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 3, text: "E no terceiro carro, cavalos brancos, e no quarto carro, cavalos malhados, todos eram fortes." },
  { id: "ZEC 6:4", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 4, text: "E respondi, dizendo ao anjo que falava comigo: Que é isto, senhor meu?" },
  { id: "ZEC 6:5", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 5, text: "E o anjo respondeu, dizendo-me: Estes são os quatro espíritos dos céus, saindo donde estavam perante o Senhor de toda a terra." },
  { id: "ZEC 6:6", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 6, text: "O carro em que estão os cavalos pretos, sai para a terra do norte, e os brancos saem atrás deles, e os malhados saem para a terra do sul." },
  { id: "ZEC 6:7", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 7, text: "E os cavalos fortes saíam, e procuravam ir por diante, para percorrerem a terra. E ele disse: Ide, percorrei a terra. E percorreram a terra." },
  { id: "ZEC 6:8", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 8, text: "E chamou-me, e falou-me, dizendo: Eis que aqueles que saíram para a terra do norte fizeram repousar o meu Espírito na terra do norte." },
  { id: "ZEC 6:9", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 9, text: "E a palavra do Senhor veio a mim, dizendo:" },
  { id: "ZEC 6:10", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 10, text: "Toma dos que foram levados cativos, a saber, de Heldai, de Tobias e de Jedaías, os quais vieram de babilônia, e vem tu no mesmo dia, e entra na casa de Josias, filho de Sofonias." },
  { id: "ZEC 6:11", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 11, text: "Toma, digo, prata e ouro, e faze coroas, e põe-nas na cabeça do sumo sacerdote Josué, filho de Jozadaque." },
  { id: "ZEC 6:12", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 12, text: "E fala-lhe, dizendo: Assim diz o SENHOR dos Exércitos: Eis aqui o homem cujo nome é RENOVO; ele brotará do seu lugar, e edificará o templo do SENHOR." },
  { id: "ZEC 6:13", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 13, text: "Ele mesmo edificará o templo do Senhor, e ele levará a glória; assentar-se-á no seu trono e dominará, e será sacerdote no seu trono, e conselho de paz haverá entre ambos os ofícios." },
  { id: "ZEC 6:14", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 14, text: "E estas coroas serão para Helém, e para Tobias, e para Jedaías, e para Hem, filho de Sofonias, como um memorial no templo do Senhor." },
  { id: "ZEC 6:15", bookId: "ZEC", book: "Zacarias", chapter: 6, verse: 15, text: "E aqueles que estão longe virão, e edificarão no templo do Senhor, e vós sabereis que o Senhor dos Exércitos me tem enviado a vós; e isto sucederá assim, se diligentemente ouvirdes a voz do Senhor vosso Deus." },
  { id: "ZEC 7:1", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 1, text: "Aconteceu, no quarto ano do rei Dario, que a palavra do SENHOR veio a Zacarias, no quarto dia do nono mês, que é Quisleu." },
  { id: "ZEC 7:2", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 2, text: "Quando o povo enviou Sarezer e Régen-Meleque, e os seus homens, à casa de Deus, para suplicarem o favor do Senhor," },
  { id: "ZEC 7:3", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 3, text: "E para dizerem aos sacerdotes, que estavam na casa do Senhor dos Exércitos, e aos profetas: Chorarei eu no quinto mês, fazendo abstinência, como tenho feito por tantos anos?" },
  { id: "ZEC 7:4", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 4, text: "Então a palavra do Senhor dos Exércitos veio a mim, dizendo:" },
  { id: "ZEC 7:5", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 5, text: "Fala a todo o povo desta terra, e aos sacerdotes, dizendo: Quando jejuastes, e pranteastes, no quinto e no sétimo mês, durante estes setenta anos, porventura, foi mesmo para mim que jejuastes?" },
  { id: "ZEC 7:6", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 6, text: "Ou quando comestes, e quando bebestes, não foi para vós mesmos que comestes e bebestes?" },
  { id: "ZEC 7:7", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 7, text: "Não foram estas as palavras que o Senhor pregou pelo ministério dos primeiros profetas, quando Jerusalém estava habitada e em paz, com as suas cidades ao redor dela, e o sul e a campina eram habitados?" },
  { id: "ZEC 7:8", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 8, text: "E a palavra do Senhor veio a Zacarias, dizendo:" },
  { id: "ZEC 7:9", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 9, text: "Assim falou o Senhor dos Exércitos, dizendo: Executai juízo verdadeiro, mostrai piedade e misericórdia cada um para com seu irmão." },
  { id: "ZEC 7:10", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 10, text: "E não oprimais a viúva, nem o órfão, nem o estrangeiro, nem o pobre, nem intente cada um, em seu coração, o mal contra o seu irmão." },
  { id: "ZEC 7:11", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 11, text: "Eles, porém, não quiseram escutar, e deram-me o ombro rebelde, e ensurdeceram os seus ouvidos, para que não ouvissem." },
  { id: "ZEC 7:12", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 12, text: "Sim, fizeram os seus corações como pedra de diamante, para que não ouvissem a lei, nem as palavras que o Senhor dos Exércitos enviara pelo seu Espírito por intermédio dos primeiros profetas; daí veio a grande ira do Senhor dos Exércitos." },
  { id: "ZEC 7:13", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 13, text: "E aconteceu que, assim como ele clamou e eles não ouviram, também eles clamaram, e eu não ouvi, diz o Senhor dos Exércitos." },
  { id: "ZEC 7:14", bookId: "ZEC", book: "Zacarias", chapter: 7, verse: 14, text: "Assim os espalhei com um turbilhão por entre todas as nações, que eles não conheceram, e a terra foi assolada atrás deles, de sorte que ninguém passava por ela, nem se voltava; porque fizeram da terra desejada uma desolação." },
  { id: "ZEC 8:1", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 1, text: "Depois veio a mim a palavra do SENHOR dos Exércitos, dizendo:" },
  { id: "ZEC 8:2", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 2, text: "Assim diz o Senhor dos Exércitos: Zelei por Sião com grande zelo, e com grande indignação zelei por ela." },
  { id: "ZEC 8:3", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 3, text: "Assim diz o Senhor: Voltarei para Sião, e habitarei no meio de Jerusalém; e Jerusalém chamar-se-á a cidade da verdade, e o monte do Senhor dos Exércitos, o monte santo." },
  { id: "ZEC 8:4", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 4, text: "Assim diz o Senhor dos Exércitos: Ainda nas praças de Jerusalém habitarão velhos e velhas; levando cada um, na mão, o seu bordão, por causa da sua muita idade." },
  { id: "ZEC 8:5", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 5, text: "E as ruas da cidade se encherão de meninos e meninas, que nelas brincarão." },
  { id: "ZEC 8:6", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 6, text: "Assim diz o Senhor dos Exércitos: Se isto for maravilhoso aos olhos do restante deste povo naqueles dias, será também maravilhoso aos meus olhos? diz o Senhor dos Exércitos." },
  { id: "ZEC 8:7", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 7, text: "Assim diz o Senhor dos Exércitos: Eis que salvarei o meu povo da terra do oriente e da terra do ocidente;" },
  { id: "ZEC 8:8", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 8, text: "E trá-los-ei, e habitarão no meio de Jerusalém; e eles serão o meu povo, e eu lhes serei o seu Deus em verdade e em justiça." },
  { id: "ZEC 8:9", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 9, text: "Assim diz o Senhor dos Exércitos: Esforcem-se as vossas mãos, ó vós que nestes dias ouvistes estas palavras da boca dos profetas, que estiveram no dia em que foi posto o fundamento da casa do Senhor dos Exércitos, para que o templo fosse edificado." },
  { id: "ZEC 8:10", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 10, text: "Porque antes destes dias não tem havido salário para os homens, nem lhes davam ganhos os animais; nem havia paz para o que entrava nem para o que saía, por causa do inimigo, porque eu incitei a todos os homens, cada um contra o seu próximo." },
  { id: "ZEC 8:11", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 11, text: "Mas agora não serei para com o restante deste povo como nos primeiros dias, diz o Senhor dos Exércitos." },
  { id: "ZEC 8:12", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 12, text: "Porque haverá semente de prosperidade; a vide dará o seu fruto, e a terra dará a sua novidade, e os céus darão o seu orvalho; e farei que o restante deste povo herde tudo isto." },
  { id: "ZEC 8:13", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 13, text: "E há de suceder, ó casa de Judá, e casa de Israel, que, assim como fostes uma maldição entre os gentios, assim vos salvarei, e sereis uma bênção; não temais, esforcem-se as vossas mãos." },
  { id: "ZEC 8:14", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 14, text: "Porque assim diz o Senhor dos Exércitos: Como pensei fazer-vos mal, quando vossos pais me provocaram à ira, diz o Senhor dos Exércitos, e não me arrependi," },
  { id: "ZEC 8:15", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 15, text: "Assim tornei a pensar nestes dias fazer o bem a Jerusalém e à casa de Judá; não temais." },
  { id: "ZEC 8:16", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 16, text: "Estas são as coisas que deveis fazer: Falai a verdade cada um com o seu próximo; executai juízo de verdade e de paz nas vossas portas." },
  { id: "ZEC 8:17", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 17, text: "E nenhum de vós pense mal no seu coração contra o seu próximo, nem ameis o juramento falso; porque todas estas são coisas que eu odeio diz o Senhor." },
  { id: "ZEC 8:18", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 18, text: "E a palavra do Senhor dos Exércitos veio a mim, dizendo:" },
  { id: "ZEC 8:19", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 19, text: "Assim diz o Senhor dos Exércitos: O jejum do quarto, e o jejum do quinto, e o jejum do sétimo, e o jejum do décimo mês será para a casa de Judá gozo, alegria, e festividades solenes; amai, pois, a verdade e a paz." },
  { id: "ZEC 8:20", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 20, text: "Assim diz o Senhor dos Exércitos: Ainda sucederá que virão os povos e os habitantes de muitas cidades." },
  { id: "ZEC 8:21", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 21, text: "E os habitantes de uma cidade irão à outra, dizendo: Vamos depressa suplicar o favor do Senhor, e buscar o Senhor dos Exércitos; eu também irei." },
  { id: "ZEC 8:22", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 22, text: "Assim virão muitos povos e poderosas nações, a buscar em Jerusalém ao Senhor dos Exércitos, e a suplicar o favor do Senhor." },
  { id: "ZEC 8:23", bookId: "ZEC", book: "Zacarias", chapter: 8, verse: 23, text: "Assim diz o Senhor dos Exércitos: Naquele dia sucederá que pegarão dez homens, de todas as línguas das nações, pegarão, sim, na orla das vestes de um judeu, dizendo: Iremos convosco, porque temos ouvido que Deus está convosco." },
  { id: "ZEC 9:1", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 1, text: "O peso da palavra do SENHOR contra a terra de Hadraque, e Damasco, o seu repouso; porque o olhar do homem, e de todas as tribos de Israel, se volta para o SENHOR." },
  { id: "ZEC 9:2", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 2, text: "E também Hamate que confina com ela, e Tiro e Sidom, ainda que sejam mais sábias." },
  { id: "ZEC 9:3", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 3, text: "E Tiro edificou para si fortalezas, e amontoou prata como o pó, e ouro fino como a lama das ruas." },
  { id: "ZEC 9:4", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 4, text: "Eis que o Senhor a despojará e ferirá no mar a sua força, e ela será consumida pelo fogo." },
  { id: "ZEC 9:5", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 5, text: "Ascalom o verá e temerá; também Gaza, e terá grande dor; igualmente Ecrom; porque a sua esperança será confundida; e o rei de Gaza perecerá, e Ascalom não será habitada." },
  { id: "ZEC 9:6", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 6, text: "E um bastardo habitará em Asdode, e exterminarei a soberba dos filisteus." },
  { id: "ZEC 9:7", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 7, text: "E da sua boca tirarei o seu sangue, e dentre os seus dentes as suas abominações; e ele também ficará como um remanescente para o nosso Deus; e será como governador em Judá, e Ecrom como um jebuseu." },
  { id: "ZEC 9:8", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 8, text: "E acampar-me-ei ao redor da minha casa, contra o exército, para que ninguém passe, nem volte; para que não passe mais sobre eles o opressor; porque agora vi com os meus olhos." },
  { id: "ZEC 9:9", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 9, text: "Alegra-te muito, ó filha de Sião; exulta, ó filha de Jerusalém; eis que o teu rei virá a ti, justo e Salvador, pobre, e montado sobre um jumento, e sobre um jumentinho, filho de jumenta." },
  { id: "ZEC 9:10", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 10, text: "E de Efraim destruirei os carros, e de Jerusalém os cavalos; e o arco de guerra será destruído, e ele anunciará paz aos gentios; e o seu domínio se estenderá de mar a mar, e desde o rio até às extremidades da terra." },
  { id: "ZEC 9:11", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 11, text: "Ainda quanto a ti, por causa do sangue da tua aliança, libertei os teus presos da cova em que não havia água." },
  { id: "ZEC 9:12", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 12, text: "Voltai à fortaleza, ó presos de esperança; também hoje vos anuncio que vos restaurarei em dobro." },
  { id: "ZEC 9:13", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 13, text: "Porque curvei Judá para mim, enchi com Efraim o arco; suscitarei a teus filhos, ó Sião, contra os teus filhos, ó Grécia! E pôr-te-ei, ó Sião, como a espada de um poderoso." },
  { id: "ZEC 9:14", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 14, text: "E o SENHOR será visto sobre eles, e as suas flechas sairão como o relâmpago; e o Senhor DEUS fará soar a trombeta, e irá com os redemoinhos do sul." },
  { id: "ZEC 9:15", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 15, text: "O Senhor dos Exércitos os amparará; eles devorarão, depois que os tiverem sujeitado, as pedras da funda; também beberão e farão barulho como excitados pelo vinho; e encher-se-ão como bacias de sacrifício, como os cantos do altar." },
  { id: "ZEC 9:16", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 16, text: "E o Senhor seu Deus naquele dia os salvará, como ao rebanho do seu povo: porque como pedras de uma coroa eles resplandecerão na sua terra." },
  { id: "ZEC 9:17", bookId: "ZEC", book: "Zacarias", chapter: 9, verse: 17, text: "Porque, quão grande é a sua bondade! E quão grande é a sua formosura! O trigo fará florescer os jovens e o mosto as virgens." },
  { id: "ZEC 10:1", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 1, text: "Pedi ao SENHOR chuva no tempo da chuva serôdia, sim, ao SENHOR que faz relâmpagos; e lhes dará chuvas abundantes, e a cada um erva no campo." },
  { id: "ZEC 10:2", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 2, text: "Porque os ídolos têm falado vaidade, e os adivinhos têm visto mentira, e contam sonhos falsos; com vaidade consolam, por isso seguem o seu caminho como ovelhas; estão aflitos, porque não há pastor." },
  { id: "ZEC 10:3", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 3, text: "Contra os pastores se acendeu a minha ira, e castigarei os bodes; mas o Senhor dos Exércitos visitará o seu rebanho, a casa de Judá, e os fará como o seu majestoso cavalo na peleja." },
  { id: "ZEC 10:4", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 4, text: "Dele sairá a pedra de esquina, dele a estaca, dele o arco de guerra, dele juntamente sairá todo o opressor." },
  { id: "ZEC 10:5", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 5, text: "E serão como poderosos que na batalha esmagam ao inimigo no lodo das ruas; porque o Senhor estará com eles; e confundirão os que andam montados em cavalos." },
  { id: "ZEC 10:6", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 6, text: "E fortalecerei a casa de Judá, e salvarei a casa de José, e fá-los- ei voltar, porque me compadeci deles; e serão como se eu não os tivera rejeitado, porque eu sou o Senhor seu Deus, e os ouvirei." },
  { id: "ZEC 10:7", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 7, text: "E os de Efraim serão como um poderoso, e o seu coração se alegrará como pelo vinho; e seus filhos o verão, e se alegrarão; o seu coração se regozijará no Senhor." },
  { id: "ZEC 10:8", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 8, text: "Eu lhes assobiarei, e os ajuntarei, porque eu os tenho remido; e multiplicar-se-ão como antes se tinham multiplicado." },
  { id: "ZEC 10:9", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 9, text: "Ainda que os espalhei por entre os povos, eles se lembrarão de mim em lugares remotos; e viverão com seus filhos, e voltarão." },
  { id: "ZEC 10:10", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 10, text: "Porque eu os farei voltar da terra do Egito, e os congregarei da Assíria; e trá-los-ei à terra de Gileade e do Líbano, e não se achará lugar bastante para eles." },
  { id: "ZEC 10:11", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 11, text: "E ele passará pelo mar com angústia, e ferirá as ondas no mar, e todas as profundezas do Nilo se secarão; então será derrubada a soberba da Assíria, e o cetro do Egito se retirará." },
  { id: "ZEC 10:12", bookId: "ZEC", book: "Zacarias", chapter: 10, verse: 12, text: "E eu os fortalecerei no Senhor, e andarão no seu nome, diz o Senhor." },
  { id: "ZEC 11:1", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 1, text: "Abre, ó Líbano, as tuas portas para que o fogo consuma os teus cedros." },
  { id: "ZEC 11:2", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 2, text: "Geme, ó cipreste, porque o cedro caiu, porque os mais poderosos são destruídos; gemei, ó carvalhos de Basã, porque o bosque forte é derrubado." },
  { id: "ZEC 11:3", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 3, text: "Voz de uivo dos pastores! porque a sua glória é destruída; voz de bramido dos filhos de leões, porque foi destruída a soberba do Jordão." },
  { id: "ZEC 11:4", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 4, text: "Assim diz o Senhor meu Deus: Apascenta as ovelhas da matança," },
  { id: "ZEC 11:5", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 5, text: "Cujos possuidores as matam, e não se têm por culpados; e cujos vendedores dizem: Louvado seja o Senhor, porque tenho enriquecido; e os seus pastores não têm piedade delas." },
  { id: "ZEC 11:6", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 6, text: "Certamente não terei mais piedade dos moradores desta terra, diz o Senhor; mas, eis que entregarei os homens cada um na mão do seu próximo e na mão do seu rei; eles ferirão a terra, e eu não os livrarei da sua mão." },
  { id: "ZEC 11:7", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 7, text: "Eu, pois, apascentei as ovelhas da matança, as pobres ovelhas do rebanho. Tomei para mim duas varas: a uma chamei Graça, e à outra chamei União; e apascentei as ovelhas." },
  { id: "ZEC 11:8", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 8, text: "E destruí os três pastores num mês; porque a minha alma se impacientou deles, e também a alma deles se enfastiou de mim." },
  { id: "ZEC 11:9", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 9, text: "E eu disse: Não vos apascentarei mais; o que morrer, morra; e o que for destruído, seja destruído; e as que restarem comam cada uma a carne da outra." },
  { id: "ZEC 11:10", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 10, text: "E tomei a minha vara Graça, e a quebrei, para desfazer a minha aliança, que tinha estabelecido com todos estes povos." },
  { id: "ZEC 11:11", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 11, text: "E foi desfeita naquele dia; e assim conheceram os pobres do rebanho, que me respeitavam, que isto era palavra do Senhor." },
  { id: "ZEC 11:12", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 12, text: "Porque eu lhes disse: Se parece bem aos vossos olhos, dai-me o meu salário e, se não, deixai-o. E pesaram o meu salário, trinta moedas de prata." },
  { id: "ZEC 11:13", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 13, text: "O Senhor, pois, disse-me: Arroja isso ao oleiro, esse belo preço em que fui avaliado por eles. E tomei as trinta moedas de prata, e as arrojei ao oleiro, na casa do Senhor." },
  { id: "ZEC 11:14", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 14, text: "Então quebrei a minha segunda vara União, para romper a irmandade entre Judá e Israel." },
  { id: "ZEC 11:15", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 15, text: "E o Senhor disse-me: Toma ainda para ti o instrumento de um pastor insensato." },
  { id: "ZEC 11:16", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 16, text: "Porque, eis que suscitarei um pastor na terra, que não cuidará das que estão perecendo, não buscará a pequena, e não curará a ferida, nem apascentará a sã; mas comerá a carne da gorda, e lhe despedaçará as unhas." },
  { id: "ZEC 11:17", bookId: "ZEC", book: "Zacarias", chapter: 11, verse: 17, text: "Ai do pastor inútil, que abandona o rebanho! A espada cairá sobre o seu braço e sobre o seu olho direito; e o seu braço completamente se secará, e o seu olho direito completamente se escurecerá." },
  { id: "ZEC 12:1", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 1, text: "Peso da palavra do SENHOR sobre Israel: Fala o SENHOR, o que estende o céu, e que funda a terra, e que forma o espírito do homem dentro dele." },
  { id: "ZEC 12:2", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 2, text: "Eis que eu farei de Jerusalém um copo de tremor para todos os povos em redor, e também para Judá, durante o cerco contra Jerusalém." },
  { id: "ZEC 12:3", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 3, text: "E acontecerá naquele dia que farei de Jerusalém uma pedra pesada para todos os povos; todos os que a carregarem certamente serão despedaçados; e ajuntar-se-á contra ela todo o povo da terra." },
  { id: "ZEC 12:4", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 4, text: "Naquele dia, diz o Senhor, ferirei de espanto a todos os cavalos, e de loucura os que montam neles; mas sobre a casa de Judá abrirei os meus olhos, e ferirei de cegueira a todos os cavalos dos povos." },
  { id: "ZEC 12:5", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 5, text: "Então os governadores de Judá dirão no seu coração: Os habitantes de Jerusalém são a minha força no Senhor dos Exércitos, seu Deus." },
  { id: "ZEC 12:6", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 6, text: "Naquele dia porei os governadores de Judá como um braseiro ardente no meio da lenha, e como um facho de fogo entre gavelas; e à direita e à esquerda consumirão a todos os povos em redor, e Jerusalém será habitada outra vez no seu lugar, em Jerusalém;" },
  { id: "ZEC 12:7", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 7, text: "E o Senhor salvará primeiramente as tendas de Judá, para que a glória da casa de Davi e a glória dos habitantes de Jerusalém não seja exaltada sobre Judá." },
  { id: "ZEC 12:8", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 8, text: "Naquele dia o Senhor protegerá os habitantes de Jerusalém; e o mais fraco dentre eles naquele dia será como Davi, e a casa de Davi será como Deus, como o anjo do Senhor diante deles." },
  { id: "ZEC 12:9", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 9, text: "E acontecerá naquele dia, que procurarei destruir todas as nações que vierem contra Jerusalém;" },
  { id: "ZEC 12:10", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 10, text: "Mas sobre a casa de Davi, e sobre os habitantes de Jerusalém, derramarei o Espírito de graça e de súplicas; e olharão para mim, a quem traspassaram; e prantearão sobre ele, como quem pranteia pelo filho unigênito; e chorarão amargamente por ele, como se chora amargamente pelo primogênito." },
  { id: "ZEC 12:11", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 11, text: "Naquele dia será grande o pranto em Jerusalém, como o pranto de Hadade-Rimom no vale de Megido." },
  { id: "ZEC 12:12", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 12, text: "E a terra pranteará, cada família à parte: a família da casa de Davi à parte, e suas mulheres à parte; e a família da casa de Natã à parte, e suas mulheres à parte;" },
  { id: "ZEC 12:13", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 13, text: "A família da casa de Levi à parte, e suas mulheres à parte; a família de Simei à parte, e suas mulheres à parte." },
  { id: "ZEC 12:14", bookId: "ZEC", book: "Zacarias", chapter: 12, verse: 14, text: "Todas as mais famílias remanescentes, cada família à parte, e suas mulheres à parte." },
  { id: "ZEC 13:1", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 1, text: "Naquele dia haverá uma fonte aberta para a casa de Davi, e para os habitantes de Jerusalém, para purificação do pecado e da imundícia." },
  { id: "ZEC 13:2", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 2, text: "E acontecerá naquele dia, diz o Senhor dos Exércitos, que tirarei da terra os nomes dos ídolos, e deles não haverá mais memória; e também farei sair da terra os profetas e o espírito da impureza." },
  { id: "ZEC 13:3", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 3, text: "E acontecerá que, quando alguém ainda profetizar, seu pai e sua mãe, que o geraram, lhe dirão: Não viverás, porque falaste mentira em nome do Senhor; e seu pai e sua mãe, que o geraram, o traspassarão quando profetizar." },
  { id: "ZEC 13:4", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 4, text: "E acontecerá naquele dia que os profetas se envergonharão, cada um da sua visão, quando profetizarem; nem mais se vestirão de manto de pelos, para mentirem." },
  { id: "ZEC 13:5", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 5, text: "Mas dirão: Não sou profeta, sou lavrador da terra; porque certo homem ensinou-me a guardar o gado desde a minha mocidade." },
  { id: "ZEC 13:6", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 6, text: "E se alguém lhe disser: Que feridas são estas nas tuas mãos? Dirá ele: São feridas com que fui ferido em casa dos meus amigos." },
  { id: "ZEC 13:7", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 7, text: "Ó espada, desperta-te contra o meu pastor, e contra o homem que é o meu companheiro, diz o Senhor dos Exércitos. Fere ao pastor, e espalhar-se-ão as ovelhas; mas volverei a minha mão sobre os pequenos." },
  { id: "ZEC 13:8", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 8, text: "E acontecerá em toda a terra, diz o Senhor, que as duas partes dela serão extirpadas, e expirarão; mas a terceira parte restará nela." },
  { id: "ZEC 13:9", bookId: "ZEC", book: "Zacarias", chapter: 13, verse: 9, text: "E farei passar esta terceira parte pelo fogo, e a purificarei, como se purifica a prata, e a provarei, como se prova o ouro. Ela invocará o meu nome, e eu a ouvirei; direi: É meu povo; e ela dirá: O Senhor é o meu Deus." },
  { id: "ZEC 14:1", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 1, text: "Eis que vem o dia do SENHOR, em que teus despojos se repartirão no meio de ti." },
  { id: "ZEC 14:2", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 2, text: "Porque eu ajuntarei todas as nações para a peleja contra Jerusalém; e a cidade será tomada, e as casas serão saqueadas, e as mulheres forçadas; e metade da cidade sairá para o cativeiro, mas o restante do povo não será extirpado da cidade." },
  { id: "ZEC 14:3", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 3, text: "E o Senhor sairá, e pelejará contra estas nações, como pele- jou, sim, no dia da batalha." },
  { id: "ZEC 14:4", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 4, text: "E naquele dia estarão os seus pés sobre o monte das Oliveiras, que está defronte de Jerusalém para o oriente; e o monte das Oliveiras será fendido pelo meio, para o oriente e para o ocidente, e haverá um vale muito grande; e metade do monte se apartará para o norte, e a outra metade dele para o sul." },
  { id: "ZEC 14:5", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 5, text: "E fugireis pelo vale dos meus montes, pois o vale dos montes chegará até Azel; e fugireis assim como fugistes de diante do terremoto nos dias de Uzias, rei de Judá. Então virá o Senhor meu Deus, e todos os santos contigo." },
  { id: "ZEC 14:6", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 6, text: "E acontecerá naquele dia, que não haverá preciosa luz, nem espessa escuridão." },
  { id: "ZEC 14:7", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 7, text: "Mas será um dia conhecido do Senhor; nem dia nem noite será; mas acontecerá que ao cair da tarde haverá luz." },
  { id: "ZEC 14:8", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 8, text: "Naquele dia também acontecerá que sairão de Jerusalém águas vivas, metade delas para o mar oriental, e metade delas para o mar ocidental; no verão e no inverno sucederá isto." },
  { id: "ZEC 14:9", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 9, text: "E o Senhor será rei sobre toda a terra; naquele dia um será o Senhor, e um será o seu nome." },
  { id: "ZEC 14:10", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 10, text: "Toda a terra em redor se tornará em planície, desde Geba até Rimom, ao sul de Jerusalém, e ela será exaltada, e habitada no seu lugar, desde a porta de Benjamim até ao lugar da primeira porta, até à porta da esquina, e desde a torre de Hananeel até aos lagares do rei." },
  { id: "ZEC 14:11", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 11, text: "E habitarão nela, e não haverá mais destruição, porque Jerusalém habitará segura." },
  { id: "ZEC 14:12", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 12, text: "E esta será a praga com que o Senhor ferirá a todos os povos que guerrearam contra Jerusalém: a sua carne apodrecerá, estando eles em pé, e lhes apodrecerão os olhos nas suas órbitas, e a língua lhes apodrecerá na sua boca." },
  { id: "ZEC 14:13", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 13, text: "Naquele dia também acontecerá que haverá da parte do Senhor uma grande perturbação entre eles; porque cada um pegará na mão do seu próximo, e cada um levantará a mão contra o seu próximo." },
  { id: "ZEC 14:14", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 14, text: "E também Judá pelejará em Jerusalém, e as riquezas de todos os gentios serão ajuntadas ao redor, ouro e prata e roupas em grande abundância." },
  { id: "ZEC 14:15", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 15, text: "Assim será também a praga dos cavalos, dos mulos, dos camelos e dos jumentos e de todos os animais que estiverem naqueles arraiais, como foi esta praga." },
  { id: "ZEC 14:16", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 16, text: "E acontecerá que, todos os que restarem de todas as nações que vieram contra Jerusalém, subirão de ano em ano para adorar o Rei, o Senhor dos Exércitos, e para celebrarem a festa dos tabernáculos." },
  { id: "ZEC 14:17", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 17, text: "E acontecerá que, se alguma das famílias da terra não subir a Jerusalém, para adorar o Rei, o Senhor dos Exércitos, não virá sobre ela a chuva." },
  { id: "ZEC 14:18", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 18, text: "E, se a família dos egípcios não subir, nem vier, não virá sobre ela a chuva; virá sobre eles a praga com que o Senhor ferirá os gentios que não subirem a celebrar a festa dos tabernáculos." },
  { id: "ZEC 14:19", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 19, text: "Este será o castigo do pecado dos egípcios e o castigo do pecado de todas as nações que não subirem a celebrar a festa dos tabernáculos." },
  { id: "ZEC 14:20", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 20, text: "Naquele dia será gravado sobre as campainhas dos cavalos: SANTIDADE AO SENHOR; e as panelas na casa do SENHOR serão como as bacias diante do altar." },
  { id: "ZEC 14:21", bookId: "ZEC", book: "Zacarias", chapter: 14, verse: 21, text: "E todas as panelas em Jerusalém e Judá serão consagradas ao Senhor dos Exércitos, e todos os que sacrificarem virão, e delas tomarão, e nelas cozerão. E naquele dia não haverá mais cananeu na casa do Senhor dos Exércitos." },
  // MALAQUIAS
  { id: "MAL 1:1", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 1, text: "Peso da palavra do SENHOR contra Israel, por intermédio de Malaquias." },
  { id: "MAL 1:2", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 2, text: "Eu vos tenho amado, diz o Senhor. Mas vós dizeis: Em que nos tens amado? Não era Esaú irmão de Jacó? disse o Senhor; todavia amei a Jacó," },
  { id: "MAL 1:3", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 3, text: "E odiei a Esaú; e fiz dos seus montes uma desolação, e dei a sua herança aos chacais do deserto." },
  { id: "MAL 1:4", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 4, text: "Ainda que Edom diga: Empobrecidos estamos, porém tornaremos a edificar os lugares desolados; assim diz o Senhor dos Exércitos: Eles edificarão, e eu destruirei; e lhes chamarão: Termo de impiedade, e povo contra quem o Senhor está irado para sempre." },
  { id: "MAL 1:5", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 5, text: "E os vossos olhos o verão, e direis: O Senhor seja engrandecido além dos termos de Israel." },
  { id: "MAL 1:6", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 6, text: "O filho honra o pai, e o servo o seu senhor; se eu sou pai, onde está a minha honra? E, se eu sou senhor, onde está o meu temor? diz o SENHOR dos Exércitos a vós, ó sacerdotes, que desprezais o meu nome. E vós dizeis: Em que nós temos desprezado o teu nome?" },
  { id: "MAL 1:7", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 7, text: "Ofereceis sobre o meu altar pão imundo, e dizeis: Em que te havemos profanado? Nisto que dizeis: A mesa do Senhor é desprezível." },
  { id: "MAL 1:8", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 8, text: "Porque, quando ofereceis animal cego para o sacrifício, isso não é mau? E quando ofereceis o coxo ou enfermo, isso não é mau? Ora apresenta-o ao teu governador; porventura terá ele agrado em ti? ou aceitará ele a tua pessoa? diz o Senhor dos Exércitos." },
  { id: "MAL 1:9", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 9, text: "Agora, pois, eu suplico, pedi a Deus, que ele seja misericordioso conosco; isto veio das vossas mãos; aceitará ele a vossa pessoa? diz o Senhor dos Exércitos." },
  { id: "MAL 1:10", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 10, text: "Quem há também entre vós que feche as portas por nada, e não acenda debalde o fogo do meu altar? Eu não tenho prazer em vós, diz o Senhor dos Exércitos, nem aceitarei oferta da vossa mão." },
  { id: "MAL 1:11", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 11, text: "Mas desde o nascente do sol até ao poente é grande entre os gentios o meu nome; e em todo o lugar se oferecerá ao meu nome incenso, e uma oferta pura; porque o meu nome é grande entre os gentios, diz o Senhor dos Exércitos." },
  { id: "MAL 1:12", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 12, text: "Mas vós o profanais, quando dizeis: A mesa do Senhor é impura, e o seu produto, isto é, a sua comida é desprezível." },
  { id: "MAL 1:13", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 13, text: "E dizeis ainda: Eis aqui, que canseira! E o lançastes ao desprezo, diz o Senhor dos Exércitos; vós ofereceis o que foi roubado, e o coxo e o enfermo; assim trazeis a oferta. Aceitaria eu isso de vossa mão? diz o Senhor." },
  { id: "MAL 1:14", bookId: "MAL", book: "Malaquias", chapter: 1, verse: 14, text: "Pois seja maldito o enganador que, tendo macho no seu rebanho, promete e oferece ao Senhor o que tem mácula; porque eu sou grande Rei, diz o Senhor dos Exércitos, o meu nome é temível entre os gentios." },
  { id: "MAL 2:1", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 1, text: "Agora, ó sacerdotes, este mandamento é para vós." },
  { id: "MAL 2:2", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 2, text: "Se não ouvirdes e se não propuserdes, no vosso coração, dar honra ao meu nome, diz o Senhor dos Exércitos, enviarei a maldição contra vós, e amaldiçoarei as vossas bênçãos; e também já as tenho amaldiçoado, porque não aplicais a isso o coração." },
  { id: "MAL 2:3", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 3, text: "Eis que reprovarei a vossa semente, e espalharei esterco sobre os vossos rostos, o esterco das vossas festas solenes; e para junto deste sereis levados." },
  { id: "MAL 2:4", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 4, text: "Então sabereis que eu vos enviei este mandamento, para que a minha aliança fosse com Levi, diz o Senhor dos Exércitos." },
  { id: "MAL 2:5", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 5, text: "Minha aliança com ele foi de vida e de paz, e eu lhas dei para que temesse; então temeu-me, e assombrou-se por causa do meu nome." },
  { id: "MAL 2:6", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 6, text: "A lei da verdade esteve na sua boca, e a iniqüidade não se achou nos seus lábios; andou comigo em paz e em retidão, e da iniqüidade converteu a muitos." },
  { id: "MAL 2:7", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 7, text: "Porque os lábios do sacerdote devem guardar o conhecimento, e da sua boca devem os homens buscar a lei porque ele é o mensageiro do Senhor dos Exércitos." },
  { id: "MAL 2:8", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 8, text: "Mas vós vos desviastes do caminho; a muitos fizestes tropeçar na lei; corrompestes a aliança de Levi, diz o Senhor dos Exércitos." },
  { id: "MAL 2:9", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 9, text: "Por isso também eu vos fiz desprezíveis, e indignos diante de todo o povo, visto que não guardastes os meus caminhos, mas fizestes acepção de pessoas na lei." },
  { id: "MAL 2:10", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 10, text: "Não temos nós todos um mesmo Pai? Não nos criou um mesmo Deus? Por que agimos aleivosamente cada um contra seu irmão, profanando a aliança de nossos pais?" },
  { id: "MAL 2:11", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 11, text: "Judá tem sido desleal, e abominação se cometeu em Israel e em Jerusalém; porque Judá profanou o santuário do Senhor, o qual ele ama, e se casou com a filha de deus estranho." },
  { id: "MAL 2:12", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 12, text: "O Senhor destruirá das tendas de Jacó o homem que fizer isto, o que vela, e o que responde, e o que apresenta uma oferta ao Senhor dos Exércitos." },
  { id: "MAL 2:13", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 13, text: "Ainda fazeis isto outra vez, cobrindo o altar do Senhor de lágrimas, com choro e com gemidos; de sorte que ele não olha mais para a oferta, nem a aceitará com prazer da vossa mão." },
  { id: "MAL 2:14", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 14, text: "E dizeis: Por quê? Porque o Senhor foi testemunha entre ti e a mulher da tua mocidade, com a qual tu foste desleal, sendo ela a tua companheira, e a mulher da tua aliança." },
  { id: "MAL 2:15", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 15, text: "E não fez ele somente um, ainda que lhe sobrava o espírito? E por que somente um? Ele buscava uma descendência para Deus. Portanto guardai-vos em vosso espírito, e ninguém seja infiel para com a mulher da sua mocidade." },
  { id: "MAL 2:16", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 16, text: "Porque o Senhor, o Deus de Israel diz que odeia o repúdio, e aquele que encobre a violência com a sua roupa, diz o Senhor dos Exércitos; portanto guardai-vos em vosso espírito, e não sejais desleais." },
  { id: "MAL 2:17", bookId: "MAL", book: "Malaquias", chapter: 2, verse: 17, text: "Enfadais ao Senhor com vossas palavras; e ainda dizeis: Em que o enfadamos? Nisto que dizeis: Qualquer que faz o mal passa por bom aos olhos do Senhor, e desses é que ele se agrada, ou, onde está o Deus do juízo?" },
  { id: "MAL 3:1", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 1, text: "Eis que eu envio o meu mensageiro, que preparará o caminho diante de mim; e de repente virá ao seu templo o Senhor, a quem vós buscais; e o mensageiro da aliança, a quem vós desejais, eis que ele vem, diz o SENHOR dos Exércitos." },
  { id: "MAL 3:2", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 2, text: "Mas quem suportará o dia da sua vinda? E quem subsistirá, quando ele aparecer? Porque ele será como o fogo do ourives e como o sabão dos lavandeiros." },
  { id: "MAL 3:3", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 3, text: "E assentar-se-á como fundidor e purificador de prata; e purificará os filhos de Levi, e os refinará como ouro e como prata; então ao Senhor trarão oferta em justiça." },
  { id: "MAL 3:4", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 4, text: "E a oferta de Judá e de Jerusalém será agradável ao Senhor, como nos dias antigos, e como nos primeiros anos." },
  { id: "MAL 3:5", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 5, text: "E chegar-me-ei a vós para juízo; e serei uma testemunha veloz contra os feiticeiros, contra os adúlteros, contra os que juram falsamente, contra os que defraudam o diarista em seu salário, e a viúva, e o órfão, e que pervertem o direito do estrangeiro, e não me temem, diz o Senhor dos Exércitos." },
  { id: "MAL 3:6", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 6, text: "Porque eu, o Senhor, não mudo; por isso vós, ó filhos de Jacó, não sois consumidos." },
  { id: "MAL 3:7", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 7, text: "Desde os dias de vossos pais vos desviastes dos meus estatutos, e não os guardastes; tornai-vos para mim, e eu me tornarei para vós, diz o Senhor dos Exércitos; mas vós dizeis: Em que havemos de tornar?" },
  { id: "MAL 3:8", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 8, text: "Roubará o homem a Deus? Todavia vós me roubais, e dizeis: Em que te roubamos? Nos dízimos e nas ofertas." },
  { id: "MAL 3:9", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 9, text: "Com maldição sois amaldiçoados, porque a mim me roubais, sim, toda esta nação." },
  { id: "MAL 3:10", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 10, text: "Trazei todos os dízimos à casa do tesouro, para que haja mantimento na minha casa, e depois fazei prova de mim nisto, diz o Senhor dos Exércitos, se eu não vos abrir as janelas do céu, e não derramar sobre vós uma bênção tal até que não haja lugar suficiente para a recolherdes." },
  { id: "MAL 3:11", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 11, text: "E por causa de vós repreenderei o devorador, e ele não destruirá os frutos da vossa terra; e a vossa vide no campo não será estéril, diz o Senhor dos Exércitos." },
  { id: "MAL 3:12", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 12, text: "E todas as nações vos chamarão bem-aventurados; porque vós sereis uma terra deleitosa, diz o Senhor dos Exércitos." },
  { id: "MAL 3:13", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 13, text: "As vossas palavras foram agressivas para mim, diz o Senhor; mas vós dizeis: Que temos falado contra ti?" },
  { id: "MAL 3:14", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 14, text: "Vós tendes dito: Inútil é servir a Deus; que nos aproveita termos cuidado em guardar os seus preceitos, e em andar de luto diante do Senhor dos Exércitos?" },
  { id: "MAL 3:15", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 15, text: "Ora, pois, nós reputamos por bem-aventurados os soberbos; também os que cometem impiedade são edificados; sim, eles tentam a Deus, e escapam." },
  { id: "MAL 3:16", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 16, text: "Então aqueles que temeram ao Senhor falaram freqüentemente um ao outro; e o Senhor atentou e ouviu; e um memorial foi escrito diante dele, para os que temeram o Senhor, e para os que se lembraram do seu nome." },
  { id: "MAL 3:17", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 17, text: "E eles serão meus, diz o Senhor dos Exércitos; naquele dia serão para mim jóias; poupá-los-ei, como um homem poupa a seu filho, que o serve." },
  { id: "MAL 3:18", bookId: "MAL", book: "Malaquias", chapter: 3, verse: 18, text: "Então voltareis e vereis a diferença entre o justo e o ímpio; entre o que serve a Deus, e o que não o serve." },
  { id: "MAL 4:1", bookId: "MAL", book: "Malaquias", chapter: 4, verse: 1, text: "Porque eis que aquele dia vem ardendo como fornalha; todos os soberbos, e todos os que cometem impiedade, serão como a palha; e o dia que está para vir os abrasará, diz o SENHOR dos Exércitos, de sorte que lhes não deixará nem raiz nem ramo." },
  { id: "MAL 4:2", bookId: "MAL", book: "Malaquias", chapter: 4, verse: 2, text: "Mas para vós, os que temeis o meu nome, nascerá o sol da justiça, e cura trará nas suas asas; e saireis e saltareis como bezerros da estrebaria." },
  { id: "MAL 4:3", bookId: "MAL", book: "Malaquias", chapter: 4, verse: 3, text: "E pisareis os ímpios, porque se farão cinza debaixo das plantas de vossos pés, naquele dia que estou preparando, diz o Senhor dos Exércitos." },
  { id: "MAL 4:4", bookId: "MAL", book: "Malaquias", chapter: 4, verse: 4, text: "Lembrai-vos da lei de Moisés, meu servo, que lhe mandei em Horebe para todo o Israel, a saber, estatutos e juízos." },
  { id: "MAL 4:5", bookId: "MAL", book: "Malaquias", chapter: 4, verse: 5, text: "Eis que eu vos enviarei o profeta Elias, antes que venha o grande e terrível dia do Senhor;" },
  { id: "MAL 4:6", bookId: "MAL", book: "Malaquias", chapter: 4, verse: 6, text: "E ele converterá o coração dos pais aos filhos, e o coração dos filhos a seus pais; para que eu não venha, e fira a terra com maldição." },
];
